function resellerManagerHas(account, permission) {
  if (!permission) return true;
  const actor = account?.resellerActor || {};
  if (actor.role === "owner") return true;
  if (permission === "owner") return false;
  return Array.isArray(actor.permissions) && actor.permissions.includes(permission);
}

function resellerRequirePermission(account, permission) {
  if (!resellerManagerHas(account, permission)) {
    const error = new Error("ШЁШұШ§ЫҢ Ш§ЫҢЩҶ Ш№Щ…Щ„ЫҢШ§ШӘ ШҜШіШӘШұШіЫҢ Ъ©Ш§ЩҒЫҢ ЩҶШҜШ§ШұЫҢШҜ");
    error.code = "RESELLER_PERMISSION_DENIED";
    throw error;
  }
}

