async function changeDirectResellerAgency(env, bot, ownerUserId, agencyId) {
  if (!resellerHasIndependentPanel(bot)) {
    throw new Error("ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ШІЫҢШұЩ…Ш¬Щ…ЩҲШ№ЩҮ ЩҫЩҶЩ„ PasarGuard Щ…ШіШӘЩӮЩ„ ЩҶШҜШ§ШұШҜ");
  }
  const ts = nowIso();
  const statements = [
    env.PASARGUARD_DB.prepare("UPDATE reseller_bots SET agency_id=?,updated_at=? WHERE id=? AND user_id=?")
      .bind(agencyId, ts, bot.id, ownerUserId)
  ];
  if (resellerBotCanCreateDownline(bot)) {
    statements.push(
      env.PASARGUARD_DB.prepare("UPDATE reseller_bots SET agency_id=?,updated_at=? WHERE parent_bot_id=?")
        .bind(agencyId, ts, bot.id)
    );
  }
  const result = await env.PASARGUARD_DB.batch(statements);
  agencyPasarguardTokenCache.delete(String(bot.agency_id || ""));
  agencyPasarguardTokenCache.delete(String(agencyId || ""));
  return result;
}

function downlineControlLogin(bot) {
  return {
    username: cleanText(bot?.control_username, 80),
    local: Boolean(bot?.parent_bot_id && bot?.control_password_hash && bot?.control_password_salt)
  };
}

async function hashResellerControlPassword(password, salt) {
  return passwordHash(String(password || ""), "reseller-control:" + String(salt || ""));
}

async function verifyResellerControlPassword(bot, username, password) {
  const control = downlineControlLogin(bot);
  if (!control.local || !control.username) return false;
  if (String(username || "").trim().toLowerCase() !== control.username.toLowerCase()) return false;
  const hash = await hashResellerControlPassword(password, bot.control_password_salt);
  return timingSafeEqualHex(hash, String(bot.control_password_hash || ""));
}

function resellerUsageAmount(deltaBytes, pricePerGb, previousRemainder = 0) {
  const delta = BigInt(Math.max(0, Math.floor(Number(deltaBytes || 0))));
  const price = BigInt(Math.max(0, Math.floor(Number(pricePerGb || 0))));
  const remainder = BigInt(Math.max(0, Math.floor(Number(previousRemainder || 0))));
  const denominator = BigInt(GIB);
  const numerator = delta * price + remainder;
  return {
    amount: Number(numerator / denominator),
    remainder: Number(numerator % denominator)
  };
}

async function ensureDownlineUser(env, telegramId, username = "", firstName = "") {
  const tid = String(telegramId || "").trim();
  if (!/^\d{5,20}$/.test(tid)) throw new Error("Telegram ID ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ШІЫҢШұЩ…Ш¬Щ…ЩҲШ№ЩҮ Щ…Ш№ШӘШЁШұ ЩҶЫҢШіШӘ");
  const ts = nowIso();
  await env.PASARGUARD_DB.prepare(`
    INSERT INTO users(telegram_id,username,first_name,last_name,role,status,wallet_balance,created_at,updated_at)
    VALUES(?,?,?,NULL,'user','active',0,?,?)
    ON CONFLICT(telegram_id) DO UPDATE SET
      username=CASE WHEN excluded.username<>'' THEN excluded.username ELSE users.username END,
      first_name=CASE WHEN excluded.first_name<>'' THEN excluded.first_name ELSE users.first_name END,
      status='active',updated_at=excluded.updated_at
  `).bind(tid, cleanText(username,64), cleanText(firstName,100), ts, ts).run();
  return await env.PASARGUARD_DB.prepare("SELECT * FROM users WHERE telegram_id=?").bind(tid).first();
}

async function listDownlineBots(env, parentBotId) {
  const rows = await env.PASARGUARD_DB.prepare(`
    SELECT rb.id,rb.user_id,rb.parent_bot_id,rb.purchase_source,rb.license_type,rb.bot_username,rb.bot_name,
      rb.status,rb.license_expires_at,rb.upstream_price_per_gb,rb.upstream_last_usage_bytes,
      rb.upstream_unpaid_toman,rb.upstream_total_charged,rb.upstream_total_profit,rb.created_at,rb.updated_at,
      u.telegram_id,u.username,u.first_name,u.last_name,u.wallet_balance,
      (SELECT COUNT(*) FROM sales_customers c WHERE c.bot_id=rb.id) AS customers_count,
      (SELECT COUNT(*) FROM sales_orders o WHERE o.bot_id=rb.id AND o.status='delivered') AS delivered_orders,
      (SELECT COALESCE(SUM(o.amount_toman),0) FROM sales_orders o WHERE o.bot_id=rb.id AND o.status='delivered') AS total_sales
    FROM reseller_bots rb JOIN users u ON u.id=rb.user_id
    WHERE rb.parent_bot_id=? ORDER BY rb.created_at DESC
  `).bind(parentBotId).all();
  return rows.results || [];
}

async function downlineUsageTotal(env, botId) {
  const row = await env.PASARGUARD_DB.prepare(`
    SELECT COALESCE(SUM(used),0) AS total_usage FROM (
      SELECT remote_username,MAX(COALESCE(remote_used_traffic,0)) AS used
      FROM sales_orders
      WHERE bot_id=? AND status='delivered' AND remote_username IS NOT NULL AND COALESCE(service_provider,'pasarguard')='pasarguard'
      GROUP BY service_provider,LOWER(remote_username)
    )
  `).bind(botId).first();
  return Math.max(0, Number(row?.total_usage || 0));
}

async function syncDownlineRemoteServices(env, childBot, limit = 120) {
  const rows = await env.PASARGUARD_DB.prepare(`
    SELECT MIN(o.id) AS order_id,o.customer_id,o.remote_username
    FROM sales_orders o
    WHERE o.bot_id=? AND o.status='delivered' AND o.remote_username IS NOT NULL AND COALESCE(o.service_provider,'pasarguard')='pasarguard'
    GROUP BY o.customer_id,o.service_provider,LOWER(o.remote_username)
    ORDER BY MAX(o.updated_at) DESC LIMIT ?
  `).bind(childBot.id, Math.max(1, Math.min(500, Number(limit || 120)))).all();
  let synced = 0, failed = 0;
  for (const row of rows.results || []) {
    try {
      await syncSalesService(env, childBot, { id: row.customer_id }, row.order_id);
      synced++;
    } catch (_) { failed++; }
  }
  return { synced, failed };
}

async function collectDownlineUnpaid(env, childBot) {
  const parent = childBot?.parent_bot_id ? await getResellerBotById(env, childBot.parent_bot_id) : null;
  if (!parent) return { collected: 0, unpaid: Number(childBot?.upstream_unpaid_toman || 0) };
  const childUser = await env.PASARGUARD_DB.prepare("SELECT * FROM users WHERE id=?").bind(childBot.user_id).first();
  const due = Math.max(0, Number(childBot.upstream_unpaid_toman || 0));
  const collected = Math.min(Math.max(0, Number(childUser?.wallet_balance || 0)), due);
  const unpaid = Math.max(0, due - collected);
  const ts = nowIso();
  if (collected > 0) {
    await env.PASARGUARD_DB.batch([
      env.PASARGUARD_DB.prepare("UPDATE users SET wallet_balance=wallet_balance-?,updated_at=? WHERE id=?").bind(collected,ts,childBot.user_id),
      env.PASARGUARD_DB.prepare("UPDATE users SET wallet_balance=wallet_balance+?,updated_at=? WHERE id=?").bind(collected,ts,parent.user_id),
      env.PASARGUARD_DB.prepare(`INSERT INTO wallet_ledger(id,user_id,type,amount,balance_after,ref_type,ref_id,description,created_at)
        SELECT ?,id,'downline_usage_settlement',-?,wallet_balance,'reseller_bot',?,'ШӘШіЩҲЫҢЩҮ ШЁШҜЩҮЫҢ Щ…ШөШұЩҒ ШұШЁШ§ШӘ ШІЫҢШұЩ…Ш¬Щ…ЩҲШ№ЩҮ',? FROM users WHERE id=?`)
        .bind(id("led"),collected,childBot.id,ts,childBot.user_id),
      env.PASARGUARD_DB.prepare(`INSERT INTO wallet_ledger(id,user_id,type,amount,balance_after,ref_type,ref_id,description,created_at)
        SELECT ?,id,'downline_usage_income',?,wallet_balance,'reseller_bot',?,'ШҜШұЫҢШ§ЩҒШӘ ЩҮШІЫҢЩҶЩҮ Щ…ШөШұЩҒ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ШІЫҢШұЩ…Ш¬Щ…ЩҲШ№ЩҮ',? FROM users WHERE id=?`)
        .bind(id("led"),collected,childBot.id,ts,parent.user_id)
    ]);
  }
  const nextStatus = unpaid > 0 ? "suspended_balance" : (childBot.status === "suspended_balance" ? "active" : childBot.status);
  await env.PASARGUARD_DB.prepare("UPDATE reseller_bots SET upstream_unpaid_toman=?,status=?,updated_at=? WHERE id=?")
    .bind(unpaid,nextStatus,ts,childBot.id).run();
  return { collected, unpaid, status: nextStatus };
}

async function sharedMarzbanUsageSnapshots(env, bot, limit = 10) {
  const settings = await getSettings(env);
  const cfg = sharedMarzbanConfig(settings, env);
  const rows = await env.PASARGUARD_DB.prepare(`
    SELECT source_type,record_id,customer_id,remote_username,previous_usage,oldest_sync,last_update
    FROM (
      SELECT 'order' AS source_type,MIN(o.id) AS record_id,o.customer_id,o.remote_username,
             MAX(COALESCE(o.remote_used_traffic,0)) AS previous_usage,
             MIN(COALESCE(o.remote_last_synced_at,'')) AS oldest_sync,
             MAX(o.updated_at) AS last_update
      FROM sales_orders o
      WHERE o.bot_id=? AND o.status='delivered' AND o.remote_username IS NOT NULL AND COALESCE(o.service_provider,'pasarguard')='marzban'
      GROUP BY o.customer_id,o.service_provider,LOWER(o.remote_username)
      UNION ALL
      SELECT 'trial' AS source_type,t.id AS record_id,t.customer_id,t.remote_username,
             COALESCE(t.remote_used_traffic,0) AS previous_usage,
             COALESCE(t.remote_last_synced_at,'') AS oldest_sync,
             t.updated_at AS last_update
      FROM sales_trials t
      WHERE t.bot_id=? AND t.status='delivered' AND t.remote_username IS NOT NULL AND COALESCE(t.service_provider,'pasarguard')='marzban'
    )
    ORDER BY oldest_sync ASC,last_update ASC LIMIT ?
  `).bind(bot.id, bot.id, Math.max(1, Math.min(20, Number(limit || cfg.syncBatch)))).all();
  const agency = { id:bot.agency_id, panel_username:bot.panel_username, panel_password_enc:bot.panel_password_enc };
  const snapshots = [];
  let failed = 0;
  for (const row of rows.results || []) {
    try {
      const remote = await servicePanelRequestForProvider(env, agency, "marzban", "GET", "/api/user/" + encodeURIComponent(row.remote_username));
      const snapshot = salesRemoteSnapshot(remote, { remote_username: row.remote_username });
      let subscriptionUrl = snapshot.subscriptionUrl || "";
      if (subscriptionUrl && subscriptionUrl.startsWith("/")) subscriptionUrl = cfg.panelUrl + subscriptionUrl;
      const previous = Math.max(0, Number(row.previous_usage || 0));
      const current = Math.max(0, Number(snapshot.usedTraffic || 0));
      const delta = current >= previous ? current - previous : current;
      snapshots.push({ sourceType:row.source_type, recordId:row.record_id, customerId:row.customer_id,
        username:row.remote_username, previous, current, delta, subscriptionUrl, snapshot });
    } catch (error) {
      failed++;
      try { await audit(env,null,"shared_marzban_service_sync_failed",{botId:bot.id,source:row.source_type,username:row.remote_username,message:String(error?.message||error)}); } catch (_) {}
    }
  }
  return { snapshots, failed, checked:(rows.results || []).length };
}

function sharedMarzbanSnapshotUpdate(env, bot, item, eventKey = "", token = "") {
  const guard = eventKey
    ? " AND EXISTS(SELECT 1 FROM shared_backend_usage_events e WHERE e.event_key=? AND e.processing_token=? AND e.applied=1)"
    : "";
  if (item.sourceType === "trial") {
    const stmt = env.PASARGUARD_DB.prepare(`UPDATE sales_trials SET
      subscription_url=CASE WHEN ?<>'' THEN ? ELSE subscription_url END,
      remote_status=?,remote_data_limit=?,remote_used_traffic=?,remote_expire=?,remote_online_at=?,remote_last_synced_at=?,updated_at=?
      WHERE id=? AND bot_id=? AND customer_id=? AND LOWER(remote_username)=LOWER(?) AND COALESCE(service_provider,'pasarguard')='marzban' AND status='delivered'${guard}`);
    const args = [item.subscriptionUrl,item.subscriptionUrl,item.snapshot.status,item.snapshot.dataLimit,item.current,
      item.snapshot.expire,item.snapshot.onlineAt,item.snapshot.syncedAt,item.snapshot.syncedAt,item.recordId,bot.id,item.customerId,item.username];
    if (eventKey) args.push(eventKey,token);
    return stmt.bind(...args);
  }
  const stmt = env.PASARGUARD_DB.prepare(`UPDATE sales_orders SET
    subscription_url=CASE WHEN ?<>'' THEN ? ELSE subscription_url END,
    remote_status=?,remote_data_limit=?,remote_used_traffic=?,remote_expire=?,remote_online_at=?,remote_last_synced_at=?
    WHERE bot_id=? AND customer_id=? AND LOWER(remote_username)=LOWER(?) AND COALESCE(service_provider,'pasarguard')='marzban' AND status='delivered'${guard}`);
  const args = [item.subscriptionUrl,item.subscriptionUrl,item.snapshot.status,item.snapshot.dataLimit,item.current,
    item.snapshot.expire,item.snapshot.onlineAt,item.snapshot.syncedAt,bot.id,item.customerId,item.username];
  if (eventKey) args.push(eventKey,token);
  return stmt.bind(...args);
}

async function billSharedMarzbanBot(env, bot, options = {}) {
  const settings = await getSettings(env);
  const cfg = sharedMarzbanConfig(settings, env);
  if (!cfg.enabled) return { processed:false, charged:0, collected:0, unpaid:0, upstream_charged:0, upstream_collected:0, upstream_unpaid:0 };
  const account = await ensureSharedBackendAccount(env, bot.id, false);
  const usage = await sharedMarzbanUsageSnapshots(env, bot, options.limit || cfg.syncBatch);
  const ts = nowIso();

  // Existing services become the baseline once. Future deltas are billed exactly once.
  if (!Number(account?.initialized || 0)) {
    const statements = [
      env.PASARGUARD_DB.prepare("UPDATE shared_backend_accounts SET initialized=1,revision=revision+1,last_delta_bytes=0,last_synced_at=?,last_error=NULL,updated_at=? WHERE bot_id=?").bind(ts,ts,bot.id)
    ];
    for (const item of usage.snapshots) statements.push(sharedMarzbanSnapshotUpdate(env,bot,item));
    await env.PASARGUARD_DB.batch(statements);
    return { processed:true, initialized:true, checked:usage.checked, failed:usage.failed, charged:0, collected:0,
      unpaid:Number(account?.unpaid_toman||0), upstream_charged:0, upstream_collected:0,
      upstream_unpaid:Number(account?.upstream_unpaid_toman||0) };
  }

  const deltaBytes = usage.snapshots.reduce((sum,item)=>sum + Math.max(0,Number(item.delta||0)),0);
  const parent = bot.parent_bot_id ? await getResellerBotById(env,bot.parent_bot_id) : null;
  const upstreamPrice = Math.max(0,Number(cfg.pricePerGb || settings.price_per_gb || 0));
  const childPrice = parent
    ? Math.max(upstreamPrice, Number(bot.upstream_price_per_gb || parent.downline_default_price_per_gb || 0))
    : upstreamPrice;
  const childCalc = resellerUsageAmount(deltaBytes,childPrice,Number(account.billing_remainder||0));
  const upstreamCalc = resellerUsageAmount(deltaBytes,upstreamPrice,Number(account.base_billing_remainder||0));
  const profitCalc = resellerUsageAmount(deltaBytes,Math.max(0,childPrice-upstreamPrice),Number(account.margin_billing_remainder||0));

  const childOwner = await env.PASARGUARD_DB.prepare("SELECT id,wallet_balance FROM users WHERE id=?").bind(bot.user_id).first();
  if (!childOwner) throw new Error("ШӯШіШ§ШЁ Щ…Ш§Щ„Ъ© ШұШЁШ§ШӘ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");

  // Direct representative: one wallet owes the central bot.
  if (!parent) {
    const previousUnpaid = Math.max(0,Number(account.unpaid_toman||0));
    const due = previousUnpaid + upstreamCalc.amount;
    const available = Math.max(0,Number(childOwner.wallet_balance||0));
    const collected = Math.min(available,due);
    const unpaid = Math.max(0,due-collected);
    const nextStatus = cfg.suspendOnDebt && unpaid>0 ? "suspended_balance"
      : (bot.status==="suspended_balance" && unpaid===0 && Number(bot.upstream_unpaid_toman||0)>0 ? "active" : bot.status);
    const changed = deltaBytes>0 || collected>0 || unpaid!==previousUnpaid || nextStatus!==bot.status;
    if (!changed) {
      const statements=[env.PASARGUARD_DB.prepare("UPDATE shared_backend_accounts SET last_synced_at=?,last_error=NULL,updated_at=? WHERE bot_id=?").bind(ts,ts,bot.id)];
      for (const item of usage.snapshots) statements.push(sharedMarzbanSnapshotUpdate(env,bot,item));
      await env.PASARGUARD_DB.batch(statements);
      return { processed:true,checked:usage.checked,failed:usage.failed,delta:0,charged:0,collected:0,unpaid,
        upstream_charged:0,upstream_collected:0,upstream_unpaid:unpaid,status:nextStatus };
    }
    const revision=Math.max(0,Number(account.revision||0));
    const eventKey="shared-marzban:"+bot.id+":"+revision;
    const token=id("smu");
    const details=JSON.stringify(usage.snapshots.map(x=>({t:x.sourceType||'order',u:x.username,p:x.previous,c:x.current,d:x.delta})).slice(0,20));
    const stageOne="EXISTS(SELECT 1 FROM shared_backend_usage_events e WHERE e.event_key=? AND e.processing_token=? AND e.applied=1)";
    const own="EXISTS(SELECT 1 FROM shared_backend_usage_events e WHERE e.event_key=? AND e.processing_token=? AND e.applied=2)";
    const statements=[
      env.PASARGUARD_DB.prepare(`INSERT OR IGNORE INTO shared_backend_usage_events(
        event_key,processing_token,applied,bot_id,parent_bot_id,owner_user_id,revision_from,delta_bytes,
        charged_amount,base_cost_amount,parent_profit_amount,collected_amount,parent_profit_collected,
        unpaid_after,price_per_gb,service_count,details_json,parent_income_amount,parent_income_collected,
        upstream_collected_amount,upstream_unpaid_after,parent_net_profit_amount,created_at)
        VALUES(?,?,0,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)`)
        .bind(eventKey,token,bot.id,null,bot.user_id,revision,deltaBytes,upstreamCalc.amount,upstreamCalc.amount,0,
          collected,0,unpaid,upstreamPrice,usage.snapshots.length,details,0,0,collected,unpaid,0,ts),
      env.PASARGUARD_DB.prepare("UPDATE shared_backend_usage_events SET applied=1 WHERE event_key=? AND processing_token=? AND applied=0 AND changes()=1").bind(eventKey,token),
      env.PASARGUARD_DB.prepare(`UPDATE shared_backend_accounts SET revision=revision+1,billing_remainder=?,
        base_billing_remainder=?,margin_billing_remainder=0,unpaid_toman=?,unpaid_base_toman=?,unpaid_margin_toman=0,
        upstream_unpaid_toman=?,total_charged=total_charged+?,total_collected=total_collected+?,
        upstream_total_charged=upstream_total_charged+?,upstream_total_collected=upstream_total_collected+?,
        last_delta_bytes=?,last_synced_at=?,last_error=NULL,updated_at=?
        WHERE bot_id=? AND revision=? AND ${stageOne}`)
        .bind(upstreamCalc.remainder,upstreamCalc.remainder,unpaid,unpaid,unpaid,upstreamCalc.amount,collected,
          upstreamCalc.amount,collected,deltaBytes,ts,ts,bot.id,revision,eventKey,token),
      env.PASARGUARD_DB.prepare("UPDATE shared_backend_usage_events SET applied=2 WHERE event_key=? AND processing_token=? AND applied=1 AND changes()=1").bind(eventKey,token),
      env.PASARGUARD_DB.prepare(`UPDATE reseller_bots SET status=?,upstream_unpaid_toman=?,
        upstream_total_charged=upstream_total_charged+?,updated_at=? WHERE id=? AND ${own}`)
        .bind(nextStatus,unpaid,upstreamCalc.amount,ts,bot.id,eventKey,token)
    ];
    if (collected>0) {
      statements.push(
        env.PASARGUARD_DB.prepare(`INSERT OR IGNORE INTO wallet_ledger(id,user_id,type,amount,balance_after,ref_type,ref_id,description,created_at)
          SELECT ?,id,'shared_marzban_usage',-?,MAX(0,wallet_balance-?),'shared_marzban_event',?,'ЩҮШІЫҢЩҶЩҮ Щ…ШөШұЩҒ Щ…ШұШІШЁШ§ЩҶ Щ…ШҙШӘШұЪ© Щ…ШұЪ©ШІЫҢ',?
          FROM users WHERE id=? AND ${own}`).bind(id("led"),collected,collected,eventKey,ts,bot.user_id,eventKey,token),
        env.PASARGUARD_DB.prepare(`UPDATE users SET wallet_balance=MAX(0,wallet_balance-?),updated_at=? WHERE id=? AND ${own}`)
          .bind(collected,ts,bot.user_id,eventKey,token)
      );
    }
    for (const item of usage.snapshots) statements.push(sharedMarzbanSnapshotUpdate(env,bot,item,eventKey,token));
    const results=await env.PASARGUARD_DB.batch(statements);
    const applied=Number(results?.[3]?.meta?.changes||0)>0;
    return { processed:true,checked:usage.checked,failed:usage.failed,delta:applied?deltaBytes:0,
      charged:applied?upstreamCalc.amount:0,collected:applied?collected:0,unpaid:applied?unpaid:previousUnpaid,
      upstream_charged:applied?upstreamCalc.amount:0,upstream_collected:applied?collected:0,
      upstream_unpaid:applied?unpaid:Number(account.upstream_unpaid_toman||0),parent_income:0,parent_profit:0,
      price_per_gb:upstreamPrice,status:applied?nextStatus:bot.status,duplicate:!applied };
  }

  // Cascading settlement: child pays the master's configured rate; the master independently
  // pays the central rate for the same bytes. Child debt never cancels the master's upstream debt.
  const parentOwner = await env.PASARGUARD_DB.prepare("SELECT id,wallet_balance FROM users WHERE id=?").bind(parent.user_id).first();
  if (!parentOwner) throw new Error("ШӯШіШ§ШЁ Щ…ШіШӘШұ ШЁШ§Щ„Ш§ШҜШіШӘ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  const previousChildUnpaid=Math.max(0,Number(account.unpaid_toman||0));
  const childDue=previousChildUnpaid+childCalc.amount;
  const childAvailable=Math.max(0,Number(childOwner.wallet_balance||0));
  const childCollected=Math.min(childAvailable,childDue);
  const childUnpaid=Math.max(0,childDue-childCollected);

  const previousUpstreamUnpaid=Math.max(0,Number(account.upstream_unpaid_toman||0));
  const upstreamDue=previousUpstreamUnpaid+upstreamCalc.amount;
  const parentBalanceBefore=Math.max(0,Number(parentOwner.wallet_balance||0));
  const parentAvailableAfterIncome=parentBalanceBefore+childCollected;
  const upstreamCollected=Math.min(parentAvailableAfterIncome,upstreamDue);
  const upstreamUnpaid=Math.max(0,upstreamDue-upstreamCollected);
  const parentBalanceAfter=parentAvailableAfterIncome-upstreamCollected;
  const parentNetCash=childCollected-upstreamCollected;
  const accruedProfit=Math.max(0,childCalc.amount-upstreamCalc.amount);

  const childStatus=cfg.suspendOnDebt && childUnpaid>0 ? "suspended_balance"
    : (bot.status==="suspended_balance" && childUnpaid===0 && Number(bot.upstream_unpaid_toman||0)>0 ? "active" : bot.status);
  const otherDebtRow=await env.PASARGUARD_DB.prepare(`SELECT
    COALESCE((SELECT unpaid_toman FROM shared_backend_accounts WHERE bot_id=?),0)+
    COALESCE((SELECT SUM(a.upstream_unpaid_toman) FROM shared_backend_accounts a JOIN reseller_bots rb ON rb.id=a.bot_id WHERE rb.parent_bot_id=? AND rb.id<>?),0) AS other_debt`)
    .bind(parent.id,parent.id,bot.id).first();
  const parentTotalUnpaid=Math.max(0,Number(otherDebtRow?.other_debt||0))+upstreamUnpaid;
  const parentStatus=cfg.suspendOnDebt && parentTotalUnpaid>0 ? "suspended_balance"
    : (parent.status==="suspended_balance" && parentTotalUnpaid===0 && Number(parent.upstream_unpaid_toman||0)>0 ? "active" : parent.status);

  const changed=deltaBytes>0 || childCollected>0 || upstreamCollected>0 || childUnpaid!==previousChildUnpaid ||
    upstreamUnpaid!==previousUpstreamUnpaid || childStatus!==bot.status || parentStatus!==parent.status;
  if (!changed) {
    const statements=[env.PASARGUARD_DB.prepare("UPDATE shared_backend_accounts SET last_synced_at=?,last_error=NULL,updated_at=? WHERE bot_id=?").bind(ts,ts,bot.id)];
    for (const item of usage.snapshots) statements.push(sharedMarzbanSnapshotUpdate(env,bot,item));
    await env.PASARGUARD_DB.batch(statements);
    return { processed:true,checked:usage.checked,failed:usage.failed,delta:0,charged:0,collected:0,unpaid:childUnpaid,
      upstream_charged:0,upstream_collected:0,upstream_unpaid:upstreamUnpaid,parent_income:0,parent_profit:0,
      status:childStatus,parent_status:parentStatus };
  }

  const revision=Math.max(0,Number(account.revision||0));
  const eventKey="shared-marzban:"+bot.id+":"+revision;
  const token=id("smu");
  const details=JSON.stringify(usage.snapshots.map(x=>({t:x.sourceType||'order',u:x.username,p:x.previous,c:x.current,d:x.delta})).slice(0,20));
  const stageOne="EXISTS(SELECT 1 FROM shared_backend_usage_events e WHERE e.event_key=? AND e.processing_token=? AND e.applied=1)";
  const own="EXISTS(SELECT 1 FROM shared_backend_usage_events e WHERE e.event_key=? AND e.processing_token=? AND e.applied=2)";
  const statements=[
    env.PASARGUARD_DB.prepare(`INSERT OR IGNORE INTO shared_backend_usage_events(
      event_key,processing_token,applied,bot_id,parent_bot_id,owner_user_id,revision_from,delta_bytes,
      charged_amount,base_cost_amount,parent_profit_amount,collected_amount,parent_profit_collected,
      unpaid_after,price_per_gb,service_count,details_json,parent_income_amount,parent_income_collected,
      upstream_collected_amount,upstream_unpaid_after,parent_net_profit_amount,created_at)
      VALUES(?,?,0,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)`)
      .bind(eventKey,token,bot.id,parent.id,bot.user_id,revision,deltaBytes,childCalc.amount,upstreamCalc.amount,accruedProfit,
        childCollected,Math.max(0,parentNetCash),childUnpaid,childPrice,usage.snapshots.length,details,
        childCalc.amount,childCollected,upstreamCollected,upstreamUnpaid,accruedProfit,ts),
    env.PASARGUARD_DB.prepare("UPDATE shared_backend_usage_events SET applied=1 WHERE event_key=? AND processing_token=? AND applied=0 AND changes()=1").bind(eventKey,token),
    env.PASARGUARD_DB.prepare(`UPDATE shared_backend_accounts SET revision=revision+1,billing_remainder=?,
      base_billing_remainder=?,margin_billing_remainder=?,unpaid_toman=?,unpaid_base_toman=?,unpaid_margin_toman=0,
      upstream_unpaid_toman=?,total_charged=total_charged+?,total_collected=total_collected+?,
      total_parent_profit=total_parent_profit+?,upstream_total_charged=upstream_total_charged+?,
      upstream_total_collected=upstream_total_collected+?,parent_income_total=parent_income_total+?,
      parent_income_collected=parent_income_collected+?,parent_net_profit_total=parent_net_profit_total+?,
      last_delta_bytes=?,last_synced_at=?,last_error=NULL,updated_at=?
      WHERE bot_id=? AND revision=? AND ${stageOne}`)
      .bind(childCalc.remainder,upstreamCalc.remainder,profitCalc.remainder,childUnpaid,upstreamUnpaid,upstreamUnpaid,
        childCalc.amount,childCollected,accruedProfit,upstreamCalc.amount,upstreamCollected,childCalc.amount,
        childCollected,accruedProfit,deltaBytes,ts,ts,bot.id,revision,eventKey,token),
    env.PASARGUARD_DB.prepare("UPDATE shared_backend_usage_events SET applied=2 WHERE event_key=? AND processing_token=? AND applied=1 AND changes()=1").bind(eventKey,token),
    env.PASARGUARD_DB.prepare(`UPDATE reseller_bots SET status=?,upstream_price_per_gb=?,upstream_unpaid_toman=?,
      upstream_total_charged=upstream_total_charged+?,updated_at=? WHERE id=? AND ${own}`)
      .bind(childStatus,childPrice,childUnpaid,childCalc.amount,ts,bot.id,eventKey,token),
    env.PASARGUARD_DB.prepare(`UPDATE reseller_bots SET status=?,upstream_unpaid_toman=?,
      upstream_total_charged=upstream_total_charged+?,upstream_total_profit=upstream_total_profit+?,updated_at=?
      WHERE id=? AND ${own}`)
      .bind(parentStatus,parentTotalUnpaid,upstreamCalc.amount,accruedProfit,ts,parent.id,eventKey,token)
  ];
  if (childCollected>0) {
    statements.push(
      env.PASARGUARD_DB.prepare(`INSERT OR IGNORE INTO wallet_ledger(id,user_id,type,amount,balance_after,ref_type,ref_id,description,created_at)
        SELECT ?,id,'shared_marzban_usage',-?,?,'shared_marzban_event',?,'ЩҮШІЫҢЩҶЩҮ Щ…ШөШұЩҒ ШҜШұ ШұШЁШ§ШӘ ЩҒШұЩҲШҙ ШЁШ§Щ„Ш§ШҜШіШӘ',?
        FROM users WHERE id=? AND ${own}`).bind(id("led"),childCollected,Math.max(0,childAvailable-childCollected),eventKey,ts,bot.user_id,eventKey,token),
      env.PASARGUARD_DB.prepare(`UPDATE users SET wallet_balance=MAX(0,wallet_balance-?),updated_at=? WHERE id=? AND ${own}`)
        .bind(childCollected,ts,bot.user_id,eventKey,token),
      env.PASARGUARD_DB.prepare(`INSERT OR IGNORE INTO wallet_ledger(id,user_id,type,amount,balance_after,ref_type,ref_id,description,created_at)
        SELECT ?,id,'shared_marzban_downline_income',?,?,'shared_marzban_event',?,'ШҜШұШўЩ…ШҜ Щ…ШөШұЩҒ ШұШЁШ§ШӘ ЩҒШұЩҲШҙ ШіШ§Ш®ШӘЩҮвҖҢШҙШҜЩҮ',?
        FROM users WHERE id=? AND ${own}`).bind(id("led"),childCollected,parentBalanceBefore+childCollected,eventKey,ts,parent.user_id,eventKey,token)
    );
  }
  if (upstreamCollected>0) {
    statements.push(env.PASARGUARD_DB.prepare(`INSERT OR IGNORE INTO wallet_ledger(id,user_id,type,amount,balance_after,ref_type,ref_id,description,created_at)
      SELECT ?,id,'shared_marzban_upstream_cost',-?,?,'shared_marzban_event',?,'ЩҮШІЫҢЩҶЩҮ Щ…ШұЪ©ШІЫҢ Щ…ШөШұЩҒ Щ…ШұШІШЁШ§ЩҶ ШҙШ§Ш®ЩҮ ЩҒШұЩҲШҙ',?
      FROM users WHERE id=? AND ${own}`).bind(id("led"),upstreamCollected,parentBalanceAfter,eventKey,ts,parent.user_id,eventKey,token));
  }
  if (childCollected>0 || upstreamCollected>0) {
    statements.push(env.PASARGUARD_DB.prepare(`UPDATE users SET wallet_balance=wallet_balance+?-?,updated_at=? WHERE id=? AND ${own}`)
      .bind(childCollected,upstreamCollected,ts,parent.user_id,eventKey,token));
  }
  for (const item of usage.snapshots) statements.push(sharedMarzbanSnapshotUpdate(env,bot,item,eventKey,token));
  const results=await env.PASARGUARD_DB.batch(statements);
  const applied=Number(results?.[3]?.meta?.changes||0)>0;
  return { processed:true,checked:usage.checked,failed:usage.failed,delta:applied?deltaBytes:0,
    charged:applied?childCalc.amount:0,collected:applied?childCollected:0,unpaid:applied?childUnpaid:previousChildUnpaid,
    upstream_charged:applied?upstreamCalc.amount:0,upstream_collected:applied?upstreamCollected:0,
    upstream_unpaid:applied?upstreamUnpaid:previousUpstreamUnpaid,parent_income:applied?childCollected:0,
    parent_profit:applied?accruedProfit:0,parent_net_cash:applied?parentNetCash:0,price_per_gb:childPrice,
    upstream_price_per_gb:upstreamPrice,status:applied?childStatus:bot.status,parent_status:applied?parentStatus:parent.status,
    duplicate:!applied };
}

async function syncSharedMarzbanUsage(env, parentBotId = null, limit = 100, options = {}) {
  const settings = await getSettings(env);
  const cfg = sharedMarzbanConfig(settings, env);
  const sql = parentBotId
    ? `SELECT rb.id FROM reseller_bots rb WHERE rb.parent_bot_id=? AND (
         EXISTS(SELECT 1 FROM sales_orders o WHERE o.bot_id=rb.id AND o.status='delivered' AND o.remote_username IS NOT NULL AND COALESCE(o.service_provider,'pasarguard')='marzban') OR
         EXISTS(SELECT 1 FROM sales_trials t WHERE t.bot_id=rb.id AND t.status='delivered' AND t.remote_username IS NOT NULL AND COALESCE(t.service_provider,'pasarguard')='marzban')
       ) ORDER BY rb.updated_at LIMIT ?`
    : `SELECT rb.id FROM reseller_bots rb WHERE
         EXISTS(SELECT 1 FROM sales_orders o WHERE o.bot_id=rb.id AND o.status='delivered' AND o.remote_username IS NOT NULL AND COALESCE(o.service_provider,'pasarguard')='marzban') OR
         EXISTS(SELECT 1 FROM sales_trials t WHERE t.bot_id=rb.id AND t.status='delivered' AND t.remote_username IS NOT NULL AND COALESCE(t.service_provider,'pasarguard')='marzban')
       ORDER BY rb.updated_at LIMIT ?`;
  const query = env.PASARGUARD_DB.prepare(sql);
  const safeLimit = Math.max(1,Math.min(500,Number(limit||100)));
  const rows = parentBotId ? await query.bind(parentBotId,safeLimit).all() : await query.bind(safeLimit).all();
  let processed=0,initialized=0,charged=0,collected=0,unpaid=0,parentProfit=0,upstreamCharged=0,upstreamCollected=0,upstreamUnpaid=0,parentIncome=0,parentNetCash=0,failed=0;
  for (const row of rows.results || []) {
    try {
      const bot = await getResellerBotById(env,row.id);
      if (!bot) continue;
      const result = await billSharedMarzbanBot(env,bot,{limit:Math.max(1,Math.min(cfg.syncBatch,Number(options.serviceLimit||cfg.syncBatch)))});
      processed++;
      if (result.initialized) initialized++;
      charged += Number(result.charged||0);
      collected += Number(result.collected||0);
      unpaid += Number(result.unpaid||0);
      parentProfit += Number(result.parent_profit||0); upstreamCharged += Number(result.upstream_charged||0); upstreamCollected += Number(result.upstream_collected||0); upstreamUnpaid += Number(result.upstream_unpaid||0); parentIncome += Number(result.parent_income||0); parentNetCash += Number(result.parent_net_cash||0);
    } catch (error) {
      failed++;
      try { await env.PASARGUARD_DB.prepare("UPDATE shared_backend_accounts SET last_error=?,updated_at=? WHERE bot_id=?").bind(String(error?.message||error).slice(0,1000),nowIso(),row.id).run(); } catch (_) {}
      try { await audit(env,null,"shared_marzban_usage_sync_failed",{botId:row.id,message:String(error?.message||error)}); } catch (_) {}
    }
  }
  return { provider:"marzban_shared", processed, initialized, charged, collected, unpaid, parent_profit:parentProfit, upstream_charged:upstreamCharged, upstream_collected:upstreamCollected, upstream_unpaid:upstreamUnpaid, parent_income:parentIncome, parent_net_cash:parentNetCash, failed };
}


async function billDownlineResellerBot(env, childBot, options = {}) {
  if (!childBot?.parent_bot_id) return { processed: false, charged: 0, collected: 0, unpaid: 0 };
  const settings = await getSettings(env);
  const parent = await getResellerBotById(env, childBot.parent_bot_id);
  if (!parent) throw new Error("ШұШЁШ§ШӘ Щ…ШіШӘШұ ШЁШ§Щ„Ш§ШҜШіШӘ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  if (options.sync !== false) await syncDownlineRemoteServices(env, childBot, options.limit || 120);

  const currentUsage = await downlineUsageTotal(env, childBot.id);
  const previousUsage = Math.max(0, Number(childBot.upstream_last_usage_bytes || 0));
  let delta = currentUsage - previousUsage;
  if (delta < 0) delta = currentUsage;

  const price = Math.max(centralMinimumDownlinePrice(settings), Number(childBot.upstream_price_per_gb || 0));
  const previousRemainder = Math.max(0, Number(childBot.upstream_billing_remainder || 0));
  const calc = resellerUsageAmount(delta, price, previousRemainder);
  const parentDiscount = await agencyTierDiscount(env,parent.user_id);
  const effectiveCentralPrice = Math.max(0,Math.round(Number(settings.price_per_gb||0)*(100-parentDiscount)/100));
  const centralCalc = resellerUsageAmount(delta,effectiveCentralPrice,0);
  const newlyDue = calc.amount;
  const previousUnpaid = Math.max(0, Number(childBot.upstream_unpaid_toman || 0));
  const dueBeforeCollection = previousUnpaid + newlyDue;
  const childUser = await env.PASARGUARD_DB.prepare("SELECT * FROM users WHERE id=?").bind(childBot.user_id).first();
  if (!childUser) throw new Error("ШӯШіШ§ШЁ Щ…Ш§Щ„Ъ© ШұШЁШ§ШӘ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  const available = Math.max(0, Number(childUser.wallet_balance || 0));
  const collected = Math.min(available, dueBeforeCollection);
  const unpaid = Math.max(0, dueBeforeCollection - collected);
  const ts = nowIso();
  const status = unpaid > 0 ? "suspended_balance" : (childBot.status === "suspended_balance" ? "active" : childBot.status);
  const statusChanged = status !== childBot.status;
  const financialChange = delta > 0 || newlyDue > 0 || collected > 0 || unpaid !== previousUnpaid || statusChanged;

  if (!financialChange) {
    await env.PASARGUARD_DB.prepare("UPDATE reseller_bots SET updated_at=? WHERE id=?").bind(ts, childBot.id).run();
    return { processed: true, usage: currentUsage, delta: 0, charged: 0, collected: 0, unpaid, price_per_gb: price, status, duplicate: false };
  }

  // The event row is the transaction guard. Every financial mutation below is
  // conditional on that INSERT changing one row, preventing concurrent live,
  // manual, or fallback syncs from charging the same usage delta twice.
  const eventKey = [
    "downline", childBot.id, previousUsage, currentUsage, previousRemainder,
    previousUnpaid, available, price, newlyDue, collected
  ].join(":");
  const statements = [
    env.PASARGUARD_DB.prepare(`INSERT OR IGNORE INTO reseller_usage_events(
      event_key,bot_id,parent_bot_id,owner_user_id,usage_from,usage_to,charged_amount,collected_amount,unpaid_after,
      central_cost_amount,master_profit_amount,price_per_gb,created_at) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)`)
      .bind(eventKey,childBot.id,parent.id,childBot.user_id,previousUsage,currentUsage,newlyDue,collected,unpaid,
        centralCalc.amount,Math.max(0,newlyDue-centralCalc.amount),price,ts),
    env.PASARGUARD_DB.prepare(`UPDATE reseller_bots SET upstream_price_per_gb=?,upstream_last_usage_bytes=?,upstream_billing_remainder=?,
      upstream_unpaid_toman=?,upstream_total_charged=upstream_total_charged+?,upstream_total_profit=upstream_total_profit+?,status=?,updated_at=?
      WHERE id=? AND changes()=1`)
      .bind(price,currentUsage,calc.remainder,unpaid,newlyDue,Math.max(0,newlyDue-centralCalc.amount),status,ts,childBot.id)
  ];
  if (collected > 0) {
    statements.push(
      env.PASARGUARD_DB.prepare("UPDATE users SET wallet_balance=wallet_balance-?,updated_at=? WHERE id=? AND changes()=1")
        .bind(collected,ts,childBot.user_id),
      env.PASARGUARD_DB.prepare("UPDATE users SET wallet_balance=wallet_balance+?,updated_at=? WHERE id=? AND changes()=1")
        .bind(collected,ts,parent.user_id),
      env.PASARGUARD_DB.prepare(`INSERT INTO wallet_ledger(id,user_id,type,amount,balance_after,ref_type,ref_id,description,created_at)
        SELECT ?,id,'downline_usage',-?,wallet_balance,'reseller_bot',?,'ЩҮШІЫҢЩҶЩҮ Щ…ШөШұЩҒ ШұШЁШ§ШӘ ШІЫҢШұЩ…Ш¬Щ…ЩҲШ№ЩҮ',? FROM users WHERE id=? AND changes()=1`)
        .bind(id("led"),collected,childBot.id,ts,childBot.user_id),
      env.PASARGUARD_DB.prepare(`INSERT INTO wallet_ledger(id,user_id,type,amount,balance_after,ref_type,ref_id,description,created_at)
        SELECT ?,id,'downline_usage_income',?,wallet_balance,'reseller_bot',?,'ШҜШұШўЩ…ШҜ Щ…ШөШұЩҒ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ШІЫҢШұЩ…Ш¬Щ…ЩҲШ№ЩҮ',? FROM users WHERE id=? AND changes()=1`)
        .bind(id("led"),collected,childBot.id,ts,parent.user_id)
    );
  }
  const results = await env.PASARGUARD_DB.batch(statements);
  const inserted = Number(results?.[0]?.meta?.changes || 0) > 0;
  return {
    processed: true,
    usage: currentUsage,
    delta: inserted ? delta : 0,
    charged: inserted ? newlyDue : 0,
    collected: inserted ? collected : 0,
    unpaid: inserted ? unpaid : previousUnpaid,
    price_per_gb: price,
    status: inserted ? status : childBot.status,
    duplicate: !inserted, upstream_charged: inserted ? centralCalc.amount : 0, upstream_collected: 0, upstream_unpaid: 0, parent_income: inserted ? collected : 0, parent_profit: inserted ? Math.max(0,newlyDue-centralCalc.amount) : 0
  };
}

async function syncDownlineUsage(env, parentBotId = null, limit = 100, options = {}) {
  const backendSettings = await getSettings(env);
  const marzbanResult=sharedMarzbanEnabled(backendSettings,env)
    ? await syncSharedMarzbanUsage(env,parentBotId,limit,options)
    : {processed:0,charged:0,collected:0,unpaid:0,parent_profit:0,failed:0};
  const sql = parentBotId
    ? "SELECT id FROM reseller_bots WHERE parent_bot_id=? ORDER BY updated_at LIMIT ?"
    : "SELECT id FROM reseller_bots WHERE parent_bot_id IS NOT NULL ORDER BY updated_at LIMIT ?";
  const query = env.PASARGUARD_DB.prepare(sql);
  const rows = parentBotId ? await query.bind(parentBotId,limit).all() : await query.bind(limit).all();
  const serviceLimit = clampInt(options.serviceLimit || 120, 5, 120);
  let processed=0,charged=0,collected=0,unpaid=0,upstreamCharged=0,upstreamCollected=0,upstreamUnpaid=0,parentIncome=0,parentProfit=0,failed=0;
  for (const row of rows.results || []) {
    try {
      const bot = await getResellerBotById(env,row.id);
      if (!bot) continue;
      const result = await billDownlineResellerBot(env,bot,{sync:options.sync !== false,limit:serviceLimit});
      processed++;charged+=Number(result.charged||0);collected+=Number(result.collected||0);unpaid+=Number(result.unpaid||0);upstreamCharged+=Number(result.upstream_charged||0);upstreamCollected+=Number(result.upstream_collected||0);upstreamUnpaid+=Number(result.upstream_unpaid||0);parentIncome+=Number(result.parent_income||0);parentProfit+=Number(result.parent_profit||0);
    } catch (error) {
      failed++;
      try { await audit(env,null,"downline_usage_sync_failed",{botId:row.id,message:String(error?.message||error)}); } catch (_) {}
    }
  }
  return {
    processed:processed+Number(marzbanResult.processed||0),
    charged:charged+Number(marzbanResult.charged||0),
    collected:collected+Number(marzbanResult.collected||0),
    unpaid:unpaid+Number(marzbanResult.unpaid||0),
    failed:failed+Number(marzbanResult.failed||0),
    upstream_charged:upstreamCharged+Number(marzbanResult.upstream_charged||0),
    upstream_collected:upstreamCollected+Number(marzbanResult.upstream_collected||0),
    upstream_unpaid:upstreamUnpaid+Number(marzbanResult.upstream_unpaid||0),
    parent_income:parentIncome+Number(marzbanResult.parent_income||0),
    parent_profit:parentProfit+Number(marzbanResult.parent_profit||0),
    pasarguard:{processed,charged,collected,unpaid,upstream_charged:upstreamCharged,upstream_collected:upstreamCollected,upstream_unpaid:upstreamUnpaid,parent_income:parentIncome,parent_profit:parentProfit,failed},
    marzban:marzbanResult
  };
}

async function resellerBotToken(env, bot) {
  const encrypted = String(bot?.bot_token_enc || "");
  const cacheKey = String(bot?.id || "") + ":" + encrypted;
  const cached = resellerTokenCache.get(cacheKey);
  if (cached && Date.now() - cached.at < RESELLER_TOKEN_CACHE_TTL_MS) return cached.token;
  const token = await decryptSecret(encrypted, env);
  if (!token) throw new Error("ШӘЩҲЪ©ЩҶ ШұШЁШ§ШӘ ЩҒШұЩҲШҙ ЩӮШ§ШЁЩ„ ШЁШ§ШІЫҢШ§ШЁЫҢ ЩҶЫҢШіШӘ");
  resellerTokenCache.set(cacheKey, { at: Date.now(), token });
  if (resellerTokenCache.size > 250) resellerTokenCache.delete(resellerTokenCache.keys().next().value);
  return token;
}


function clearResellerBotTokenCache(botId) {
  const prefix = String(botId || "") + ":";
  for (const key of Array.from(resellerTokenCache.keys())) {
    if (String(key).startsWith(prefix)) resellerTokenCache.delete(key);
  }
}

async function replaceResellerBotToken(env, bot, rawToken, options = {}) {
  const token = String(rawToken || "").trim();
  if (!/^\d{6,15}:[A-Za-z0-9_-]{20,}$/.test(token)) throw new Error("ЩҒШұЩ…ШӘ ШӘЩҲЪ©ЩҶ BotFather Щ…Ш№ШӘШЁШұ ЩҶЫҢШіШӘ");
  if (!bot?.id) throw new Error("ШұШЁШ§ШӘ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");

  const info = await telegramApiWithToken(token, "getMe", {});
  const me = info?.result;
  if (!me?.id || !me?.is_bot || !me?.username) throw new Error("ШӘЩҲЪ©ЩҶ ШӘЩҲШіШ· ШӘЩ„ЪҜШұШ§Щ… ШӘШЈЫҢЫҢШҜ ЩҶШҙШҜ");

  const settings = await getSettings(env);
  const centralTelegramId = String(settings.central_bot_telegram_id || String(settings.bot_token || "").split(":")[0] || "");
  if (centralTelegramId && String(me.id) === centralTelegramId) throw new Error("ШӘЩҲЪ©ЩҶ ШұШЁШ§ШӘ Щ…ШұЪ©ШІЫҢ ШұШ§ ЩҶЩ…ЫҢвҖҢШӘЩҲШ§ЩҶ ШЁШұШ§ЫҢ ШұШЁШ§ШӘ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ Ш«ШЁШӘ Ъ©ШұШҜ");

  const duplicate = await env.PASARGUARD_DB.prepare(
    "SELECT id,bot_username FROM reseller_bots WHERE bot_telegram_id=? AND id<>? LIMIT 1"
  ).bind(String(me.id), String(bot.id)).first();
  if (duplicate) throw new Error("Ш§ЫҢЩҶ ШұШЁШ§ШӘ ЩӮШЁЩ„Ш§ЩӢ ШЁШұШ§ЫҢ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ШҜЫҢЪҜШұЫҢ Ш«ШЁШӘ ШҙШҜЩҮ Ш§ШіШӘ");

  let oldToken = "";
  try { oldToken = await resellerBotToken(env, bot); } catch (_) {}
  const oldTelegramId = String(bot.bot_telegram_id || "");
  const encrypted = await encryptSecret(token, env);
  const webhookSecret = randomHex(32);
  const candidate = {
    ...bot,
    bot_token_enc: encrypted,
    bot_telegram_id: String(me.id),
    bot_username: cleanText(me.username, 100),
    bot_name: cleanText(me.first_name || me.username, 120),
    webhook_secret: webhookSecret,
    bot_version: RESELLER_BOT_VERSION,
    miniapp_enabled: 1,
    __cleanup_legacy_keyboard: true
  };

  // The new bot receives a fresh secret before the database switch. Until the DB update,
  // incoming updates from it are rejected and retried instead of being processed with the old token.
  await configureResellerBot(env, candidate, options.origin || resellerBotOrigin(settings));

  const ts = nowIso();
  let result;
  try {
    result = await env.PASARGUARD_DB.prepare(`
      UPDATE reseller_bots SET
        bot_telegram_id=?,bot_username=?,bot_name=?,bot_token_enc=?,webhook_secret=?,
        bot_version=?,miniapp_enabled=1,status=CASE WHEN status='error' THEN 'active' ELSE status END,updated_at=?
      WHERE id=?
    `).bind(
      candidate.bot_telegram_id, candidate.bot_username, candidate.bot_name, encrypted, webhookSecret,
      RESELLER_BOT_VERSION, ts, bot.id
    ).run();
  } catch (error) {
    if (/UNIQUE|bot_telegram_id/i.test(String(error?.message || error))) throw new Error("Ш§ЫҢЩҶ ШұШЁШ§ШӘ ЩҮЩ…вҖҢШІЩ…Ш§ЩҶ ШЁШұШ§ЫҢ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ШҜЫҢЪҜШұЫҢ Ш«ШЁШӘ ШҙШҜЩҮ Ш§ШіШӘ");
    throw error;
  }
  if (!Number(result?.meta?.changes || 0)) throw new Error("Ш°Ш®ЫҢШұЩҮ ШӘЩҲЪ©ЩҶ Ш¬ШҜЫҢШҜ Ш§ЩҶШ¬Ш§Щ… ЩҶШҙШҜ");

  clearResellerBotTokenCache(bot.id);
  resellerTokenCache.set(String(bot.id) + ":" + encrypted, { at: Date.now(), token });

  // A different old bot must not keep posting updates to the same reseller route.
  if (oldToken && oldTelegramId && oldTelegramId !== String(me.id)) {
    try { await telegramApiWithToken(oldToken, "deleteWebhook", { drop_pending_updates: false }); } catch (_) {}
  }

  return {
    bot: { ...candidate, updated_at: ts },
    old_telegram_id: oldTelegramId,
    changed_bot: oldTelegramId !== String(me.id),
    username: candidate.bot_username
  };
}

async function resellerTelegramApi(env, bot, method, body) {
  return telegramUiApi(env, "reseller:" + String(bot.id), await resellerBotToken(env, bot), method, body);
}

async function configureResellerBot(env, bot, origin = "") {
  const routingSettings = await getSettings(env);
  const webhookOrigin = resellerBotOrigin(routingSettings, origin);
  const webhookUrl = webhookOrigin + "/sales-bot/" + encodeURIComponent(bot.id) + "/webhook";
  const miniAppUrl = webhookOrigin + "/sales-app/" + encodeURIComponent(bot.id);
  const token = await resellerBotToken(env, bot);
  await telegramApiWithToken(token, "setWebhook", {
    url: webhookUrl,
    secret_token: bot.webhook_secret,
    allowed_updates: ["message", "callback_query"],
    drop_pending_updates: false
  });

  const ownerChatId = String(bot.owner_telegram_id || "").trim();
  const scopes = [
    { type: "default" },
    { type: "all_private_chats" },
    { type: "all_group_chats" },
    { type: "all_chat_administrators" }
  ];
  if (/^\d{5,20}$/.test(ownerChatId)) scopes.push({ type: "chat", chat_id: Number(ownerChatId) });
  for (const scope of scopes) {
    for (const languageCode of ["", "fa", "en", "ar"]) {
      const payload = languageCode ? { scope, language_code: languageCode } : { scope };
      try { await telegramApiWithToken(token, "deleteMyCommands", payload); } catch (_) {}
    }
  }

  const customerCommands = [
    { command: "start", description: "ЩҶЩ…Ш§ЫҢШҙ Щ…ЩҶЩҲЫҢ Ш§ШөЩ„ЫҢ" },
    { command: "plans", description: "Щ…ШҙШ§ЩҮШҜЩҮ ЩҲ Ш®ШұЫҢШҜ ЩҫЩ„ЩҶвҖҢЩҮШ§" },
    { command: "orders", description: "ШіШұЩҲЫҢШівҖҢЩҮШ§ ЩҲ ШіЩҒШ§ШұШҙвҖҢЩҮШ§ЫҢ Щ…ЩҶ" },
    { command: "renew", description: "ШӘЩ…ШҜЫҢШҜ ЫҢШ§ Ш§ЩҒШІШ§ЫҢШҙ ШӯШ¬Щ…" },
    { command: "wallet", description: "Ъ©ЫҢЩҒ ЩҫЩҲЩ„ ЩҲ ШҙШ§ШұЪҳ ШӯШіШ§ШЁ" },
    { command: "account", description: "ШӯШіШ§ШЁ Ъ©Ш§ШұШЁШұЫҢ" },
    { command: "support", description: "ЩҫШҙШӘЫҢШЁШ§ЩҶЫҢ" }
  ];
  const ownerCommands = [
    { command: "start", description: "ЩҶЩ…Ш§ЫҢШҙ Щ…ЩҶЩҲЫҢ ШұШЁШ§ШӘ" },
    { command: "manage", description: "Щ…ШҜЫҢШұЫҢШӘ Ъ©Ш§Щ…Щ„ ШұШЁШ§ШӘ" },
    ...(resellerBotCanCreateDownline(bot) ? [{ command: "newbot", description: "ШіШ§Ш®ШӘ ШұШЁШ§ШӘ ШІЫҢШұЩ…Ш¬Щ…ЩҲШ№ЩҮ" }] : []),
    { command: "plans", description: "Щ…ШҜЫҢШұЫҢШӘ ЩҫЩ„ЩҶвҖҢЩҮШ§" },
    { command: "orders", description: "Щ…ШҜЫҢШұЫҢШӘ ШіЩҒШ§ШұШҙвҖҢЩҮШ§" },
    { command: "broadcast", description: "Ш§ШұШіШ§Щ„ ЩҮЩ…ЪҜШ§ЩҶЫҢ" },
    { command: "cancel", description: "Щ„ШәЩҲ Ш№Щ…Щ„ЫҢШ§ШӘ Ш¬Ш§ШұЫҢ" }
  ];
  const reportCommands = [
    { command: "setup_reports", description: "ШіШ§Ш®ШӘ Щ…ЩҲШ¶ЩҲШ№вҖҢЩҮШ§ЫҢ ЪҜШұЩҲЩҮ ЪҜШІШ§ШұШҙ Ш§ЫҢЩҶ ШұШЁШ§ШӘ" },
    { command: "reports_status", description: "ЩҶЩ…Ш§ЫҢШҙ ЩҲШ¶Ш№ЫҢШӘ ЪҜШұЩҲЩҮ ЪҜШІШ§ШұШҙ" },
    { command: "test_reports", description: "Ш§ШұШіШ§Щ„ ЪҜШІШ§ШұШҙ ШўШІЩ…Ш§ЫҢШҙЫҢ ЩҒЩҲШұЫҢ" },
    { command: "test_all_topics", description: "ШўШІЩ…Ш§ЫҢШҙ ЩҮЩ…ЩҮ TopicЩҮШ§ЫҢ ЪҜШІШ§ШұШҙ" },
    { command: "flush_reports", description: "ЩҫШұШҜШ§ШІШҙ ШөЩҒ ЪҜШІШ§ШұШҙвҖҢЩҮШ§" },
    { command: "reset_reports", description: "ШЁШ§ШІШіШ§ШІЫҢ Щ…ЩҲШ¶ЩҲШ№вҖҢЩҮШ§ЫҢ ЪҜШІШ§ШұШҙ" },
    { command: "disable_reports", description: "ШӘЩҲЩӮЩҒ Ш§ШұШіШ§Щ„ ЪҜШІШ§ШұШҙ ШЁЩҮ ЪҜШұЩҲЩҮ" }
  ];
  try { await telegramApiWithToken(token, "setMyCommands", { scope: { type: "default" }, commands: customerCommands }); } catch (_) {}
  try { await telegramApiWithToken(token, "setMyCommands", { scope: { type: "all_private_chats" }, commands: customerCommands }); } catch (_) {}
  try { await telegramApiWithToken(token, "setMyCommands", { scope: { type: "all_group_chats" }, commands: reportCommands }); } catch (_) {}
  try { await telegramApiWithToken(token, "setMyCommands", { scope: { type: "all_chat_administrators" }, commands: reportCommands }); } catch (_) {}
  if (/^\d{5,20}$/.test(ownerChatId)) {
    try { await telegramApiWithToken(token, "setMyCommands", { scope: { type: "chat", chat_id: Number(ownerChatId) }, commands: ownerCommands }); } catch (_) {}
  }

  const menuButton = { type: "commands" };
  await telegramApiWithToken(token, "setChatMenuButton", { menu_button: menuButton });
  if (/^\d{5,20}$/.test(ownerChatId)) {
    try { await telegramApiWithToken(token, "setChatMenuButton", { chat_id: Number(ownerChatId), menu_button: menuButton }); } catch (_) {}
  }

  const cleanupLegacyKeyboard = bot.__cleanup_legacy_keyboard === true || String(bot.bot_version || "") !== RESELLER_BOT_VERSION;
  if (cleanupLegacyKeyboard && /^\d{5,20}$/.test(ownerChatId)) {
    try {
      await telegramApiWithToken(token, "sendMessage", {
        chat_id: ownerChatId,
        text: "вң… Щ…ЩҶЩҲ ЩҲ ЩҒШұЩ…Ш§ЩҶвҖҢЩҮШ§ЫҢ Ш§ШұШ§ШҰЩҮвҖҢШҜЩҮЩҶШҜЩҮ ЩӮШЁЩ„ЫҢ ЩҫШ§Ъ© ШҙШҜ. Щ…ЩҶЩҲЫҢ Ш¬ШҜЫҢШҜ ЩҒШ№Ш§Щ„ Ш§ШіШӘШӣ ШЁШұШ§ЫҢ Щ…ШҜЫҢШұЫҢШӘ /manage ШұШ§ Ш§ШұШіШ§Щ„ Ъ©ЩҶЫҢШҜ.",
        reply_markup: { remove_keyboard: true }
      });
    } catch (_) {}
  }
  return webhookUrl;
}

async function ensureResellerBotRuntimeCurrent(env, bot) {
  if (!bot || String(bot.bot_version || "") === RESELLER_BOT_VERSION) return bot;
  const settings = await getSettings(env);
  try {
    await configureResellerBot(env, bot, resellerBotOrigin(settings));
    await env.PASARGUARD_DB.prepare("UPDATE reseller_bots SET bot_version=?,miniapp_enabled=1,status=CASE WHEN status='error' THEN 'active' ELSE status END,updated_at=? WHERE id=?")
      .bind(RESELLER_BOT_VERSION, nowIso(), bot.id).run();
    bot.bot_version = RESELLER_BOT_VERSION;
    bot.miniapp_enabled = 1;
    return bot;
  } catch (error) {
    try { await env.PASARGUARD_DB.prepare("UPDATE reseller_bots SET status='error',updated_at=? WHERE id=?").bind(nowIso(), bot.id).run(); } catch (_) {}
    throw new Error("ЩҮЩ…ЪҜШ§Щ…вҖҢШіШ§ШІЫҢ ШЁШұЩҲШІШұШіШ§ЩҶЫҢ ШұШЁШ§ШӘ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ЩҶШ§Щ…ЩҲЩҒЩӮ ШЁЩҲШҜ: " + String(error?.message || error));
  }
}

function scheduleResellerRuntimeUpdate(env, bot, ctx = null) {
  if (!bot || String(bot.bot_version || "") === RESELLER_BOT_VERSION) return;
  const key = String(bot.id || "");
  if (!key || resellerRuntimeUpdateInFlight.has(key)) return;
  const task = ensureResellerBotRuntimeCurrent(env, { ...bot })
    .then(updated => {
      resellerWebhookBotCache.set(key, { at: Date.now(), bot: updated || bot });
    })
    .catch(error => console.error("background reseller runtime update failed", key, error))
    .finally(() => resellerRuntimeUpdateInFlight.delete(key));
  resellerRuntimeUpdateInFlight.set(key, task);
  if (ctx && typeof ctx.waitUntil === "function") ctx.waitUntil(task);
}

async function listSalesBotAgencies(env, userId) {
  const rows = await env.PASARGUARD_DB.prepare(`
    SELECT id,title,panel_username,status,
           CASE WHEN panel_password_enc IS NULL THEN 0 ELSE 1 END AS has_password
    FROM agencies
    WHERE user_id=? AND COALESCE(is_trial,0)=0
    ORDER BY CASE WHEN status='active' THEN 0 ELSE 1 END,
             CASE WHEN panel_password_enc IS NULL THEN 1 ELSE 0 END,
             created_at DESC
    LIMIT 20
  `).bind(userId).all();
  return rows.results || [];
}

function salesBotAgencyButton(agency, index, prefix) {
  const status = agency.status === "active" ? "рҹҹў " : "рҹҹ  ";
  const passwordHint = Number(agency.has_password || 0) === 1 ? "" : " В· Ш§ШұШіШ§Щ„ ШұЩ…ШІ";
  return {
    text: status + (index + 1) + ". " + agency.title + passwordHint,
    callback_data: prefix + agency.id
  };
}

async function verifyAndStoreAgencyPassword(env, userId, agencyId, rawPassword) {
  const agency = await env.PASARGUARD_DB.prepare(`
    SELECT * FROM agencies
    WHERE id=? AND user_id=? AND COALESCE(is_trial,0)=0
  `).bind(agencyId, userId).first();
  if (!agency) throw new Error("ЩҫЩҶЩ„ Ш§ЩҶШӘШ®Ш§ШЁвҖҢШҙШҜЩҮ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");

  const password = cleanText(rawPassword, 200);
  if (!password) throw new Error("ШұЩ…ШІ ЩҫЩҶЩ„ ШұШ§ Ш§ШұШіШ§Щ„ Ъ©ЩҶЫҢШҜ");
  const settings = await getSettings(env);
  const form = new URLSearchParams();
  form.set("username", String(agency.panel_username));
  form.set("password", password);
  const response = await fetch(pasarguardBaseUrl(settings) + "/api/admin/token", {
    method: "POST",
    headers: { "content-type": "application/x-www-form-urlencoded" },
    body: form.toString()
  });
  const data = await response.json().catch(() => ({}));
  if (!response.ok || !data.access_token) {
    throw new Error("ШұЩ…ШІ ЩҫЩҶЩ„ ШөШӯЫҢШӯ ЩҶЫҢШіШӘШӣ ШұЩ…ШІ ЩҮЩ…Ш§ЩҶ Ш§ШҜЩ…ЫҢЩҶ ШіШ§Ш®ШӘЩҮвҖҢШҙШҜЩҮ ШҜШұ ЩҫШ§ШіШ§ШұЪҜШ§ШұШҜ ШұШ§ ШҜЩҲШЁШ§ШұЩҮ Ш§ШұШіШ§Щ„ Ъ©ЩҶЫҢШҜ");
  }

  const encryptedPassword = await encryptSecret(password, env);
  const result = await env.PASARGUARD_DB.prepare(`
    UPDATE agencies SET panel_password_enc=?,updated_at=?
    WHERE id=? AND user_id=?
  `).bind(encryptedPassword, nowIso(), agency.id, userId).run();
  if (!Number(result?.meta?.changes || 0)) {
    const fresh = await env.PASARGUARD_DB.prepare("SELECT * FROM agencies WHERE id=? AND user_id=?")
      .bind(agency.id, userId).first();
    if (!fresh?.panel_password_enc) throw new Error("Ш°Ш®ЫҢШұЩҮ ШұЩ…ШІ ЩҫЩҶЩ„ Ш§ЩҶШ¬Ш§Щ… ЩҶШҙШҜШӣ ШҜЩҲШЁШ§ШұЩҮ ШӘЩ„Ш§Шҙ Ъ©ЩҶЫҢШҜ");
    return fresh;
  }
  agencyPasarguardTokenCache.set(String(agency.id), { token: String(data.access_token), expiresAt: Date.now() + 10 * 60 * 1000 });
  await audit(env, userId, "agency_password_verified_and_replaced", { agencyId: agency.id, remoteId: agency.remote_manager_id });
  return { ...agency, panel_password_enc: encryptedPassword };
}

async function getAgencyPasarguardToken(env, agency, forceRefresh = false) {
  const settings = await getSettings(env);
  const cacheKey = String(agency.id);
  const cached = agencyPasarguardTokenCache.get(cacheKey);
  if (!forceRefresh && cached?.token && cached.expiresAt > Date.now() + 60000) return cached.token;
  const password = await decryptSecret(agency.panel_password_enc || "", env);
  if (!password) throw new Error("ШұЩ…ШІ ЩҫЩҶЩ„ Ш§ЩҶШӘШ®Ш§ШЁвҖҢШҙШҜЩҮ ШҜШұ ШіШ§Щ…Ш§ЩҶЩҮ Ш°Ш®ЫҢШұЩҮ ЩҶШҙШҜЩҮ Ш§ШіШӘ");
  const form = new URLSearchParams();
  form.set("username", String(agency.panel_username));
  form.set("password", password);
  const response = await fetch(pasarguardBaseUrl(settings) + "/api/admin/token", {
    method: "POST",
    headers: { "content-type": "application/x-www-form-urlencoded" },
    body: form.toString()
  });
  const data = await response.json().catch(() => ({}));
  if (!response.ok || !data.access_token) {
    const detail = data.detail || data.message || data.error || ("HTTP " + response.status);
    const detailText = typeof detail === "string" ? detail : JSON.stringify(detail);
    const invalidCredentials = [400, 401, 403].includes(Number(response.status)) &&
      /incorrect\s*(username|user name).*password|invalid\s*(username|credentials)|username\s*or\s*password|ЩҶШ§Щ… Ъ©Ш§ШұШЁШұЫҢ.*ШұЩ…ШІ|ШұЩ…ШІ.*ЩҶШ§Щ… Ъ©Ш§ШұШЁШұЫҢ/i.test(detailText);
    if (invalidCredentials) {
      agencyPasarguardTokenCache.delete(cacheKey);
      try {
        await env.PASARGUARD_DB.prepare("UPDATE agencies SET panel_password_enc=NULL,updated_at=? WHERE id=?")
          .bind(nowIso(), agency.id).run();
      } catch (_) {}
      const error = new Error("ШұЩ…ШІ ЩҫЩҶЩ„ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ШӘШәЫҢЫҢШұ Ъ©ШұШҜЩҮ ЫҢШ§ Щ…Ш№ШӘШЁШұ ЩҶЫҢШіШӘШӣ ШұЩ…ШІ Ш¬ШҜЫҢШҜ ЩҫЩҶЩ„ ШұШ§ Ш§ШұШіШ§Щ„ Ъ©ЩҶЫҢШҜ");
      error.code = "AGENCY_CREDENTIALS_INVALID";
      error.agencyId = agency.id;
      error.panelUsername = agency.panel_username;
      throw error;
    }
    throw new Error("Ш§ШұШӘШЁШ§Ш· ШЁШ§ ЩҫЩҶЩ„ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ЩҶШ§Щ…ЩҲЩҒЩӮ ШЁЩҲШҜШӣ ЪҶЩҶШҜ Щ„ШӯШёЩҮ ШЁШ№ШҜ ШҜЩҲШЁШ§ШұЩҮ ШӘЩ„Ш§Шҙ Ъ©ЩҶЫҢШҜ");
  }
  const token = String(data.access_token);
  agencyPasarguardTokenCache.set(cacheKey, { token, expiresAt: Date.now() + 10 * 60 * 1000 });
  return token;
}

async function agencyPasarguardRequest(env, agency, method, path, body, retry = true) {
  const settings = await getSettings(env);
  const token = await getAgencyPasarguardToken(env, agency, false);
  const response = await fetch(pasarguardBaseUrl(settings) + path, {
    method,
    headers: {
      authorization: "Bearer " + token,
      ...(body === undefined ? {} : { "content-type": "application/json" })
    },
    body: body === undefined ? undefined : JSON.stringify(body)
  });
  if (response.status === 401 && retry) {
    agencyPasarguardTokenCache.delete(String(agency.id));
    return agencyPasarguardRequest(env, agency, method, path, body, false);
  }
  if (response.status === 204) return {};
  const data = await response.json().catch(() => ({}));
  if (!response.ok) {
    const detail = data.detail || data.message || data.error || ("HTTP " + response.status);
    const error = new Error(typeof detail === "string" ? detail : JSON.stringify(detail));
    error.status = response.status;
    throw error;
  }
  return data;
}
const sharedMarzbanTokenCache = new Map();


function normalizeServiceProvider(value) {
  const raw = String(value || "").trim().toLowerCase();
  return ["marzban","marzban_shared"].includes(raw) ? "marzban" : "pasarguard";
}

function serviceProviderLabel(value) {
  return normalizeServiceProvider(value) === "marzban" ? "Щ…ШұШІШЁШ§ЩҶ" : "PasarGuard";
}

function locationServiceProvider(location, settings = {}, env = {}) {
  const provider = normalizeServiceProvider(location?.backend_provider || location?.service_provider || "pasarguard");
  if (provider === "marzban" && !sharedMarzbanEnabled(settings, env)) {
    throw new Error("Щ…ШұШІШЁШ§ЩҶ Щ…ШҙШӘШұЪ© Щ…ШұЪ©ШІЫҢ ЩҒШ№Ш§Щ„ ЫҢШ§ Ъ©Ш§Щ…Щ„ ШӘЩҶШёЫҢЩ… ЩҶШҙШҜЩҮ Ш§ШіШӘ");
  }
  return provider;
}

function serviceBaseUrlForProvider(settings, env, provider) {
  return normalizeServiceProvider(provider) === "marzban"
    ? sharedMarzbanConfig(settings, env).panelUrl
    : pasarguardBaseUrl(settings);
}

async function servicePanelRequestForProvider(env, agency, provider, method, path, body, retry = true) {
  const selected = normalizeServiceProvider(provider);
  if (selected === "marzban") {
    const settings = await getSettings(env);
    if (!sharedMarzbanEnabled(settings, env)) throw new Error("Щ…ШұШІШЁШ§ЩҶ Щ…ШҙШӘШұЪ© Щ…ШұЪ©ШІЫҢ ЩҒШ№Ш§Щ„ ЩҶЫҢШіШӘ");
    return sharedMarzbanRequest(env, method, path, body, retry);
  }
  if (!agency?.id || !agency?.panel_username) throw new Error("ЩҫЩҶЩ„ PasarGuard Щ…ШӘШөЩ„ ШЁШұШ§ЫҢ Ш§ЫҢЩҶ ШұШЁШ§ШӘ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  return agencyPasarguardRequest(env, agency, method, path, body, retry);
}

function sharedMarzbanEnabled(settings, env = {}) {
  const raw = env.MARZBAN_SHARED_ENABLED !== undefined
    ? env.MARZBAN_SHARED_ENABLED
    : (settings?.marzban_shared_enabled ?? settings?.service_backend);
  return ["true", "marzban_shared"].includes(String(raw || "").toLowerCase());
}

function sharedMarzbanJsonObject(value, label) {
  if (value && typeof value === "object" && !Array.isArray(value)) return value;
  const raw = String(value || "").trim();
  if (!raw) return {};
  try {
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) throw new Error();
    return parsed;
  } catch (_) {
    throw new Error(label + " ШЁШ§ЫҢШҜ JSON Object Щ…Ш№ШӘШЁШұ ШЁШ§ШҙШҜ");
  }
}

function normalizeSharedMarzbanPanelUrl(value) {
  const raw = String(value || "").trim().replace(/\/+$/, "");
  if (!raw) return "";
  return raw.replace(/\/dashboard(?:\/.*)?$/i, "").replace(/\/+$/, "");
}

function sharedMarzbanDashboardUrl(value) {
  const base = normalizeSharedMarzbanPanelUrl(value);
  return base ? base + "/dashboard/" : "";
}

function normalizeSharedMarzbanTemplateUsername(value) {
  return cleanText(String(value || "").trim().replace(/^@/, ""), 200);
}

function sharedMarzbanConfig(settings, env = {}) {
  const panelUrl = normalizeSharedMarzbanPanelUrl(env.MARZBAN_PANEL_URL || settings?.marzban_panel_url || "");
  const username = String(env.MARZBAN_ADMIN_USERNAME || settings?.marzban_admin_username || "").trim();
  const password = String(env.MARZBAN_ADMIN_PASSWORD || settings?.marzban_admin_password || "");
  const enabled = sharedMarzbanEnabled(settings, env);
  if (enabled && !/^https:\/\//i.test(panelUrl)) throw new Error("ШўШҜШұШі ЩҫЩҶЩ„ Щ…ШұШІШЁШ§ЩҶ ШЁШ§ЫҢШҜ ШЁШ§ HTTPS ШҙШұЩҲШ№ ШҙЩҲШҜ");
  if (enabled && (!username || !password)) throw new Error("ЩҶШ§Щ… Ъ©Ш§ШұШЁШұЫҢ ЫҢШ§ ШұЩ…ШІ Ш§ШҜЩ…ЫҢЩҶ Щ…ШҙШӘШұЪ© Щ…ШұШІШЁШ§ЩҶ Ш«ШЁШӘ ЩҶШҙШҜЩҮ Ш§ШіШӘ");
  return {
    enabled,
    panelUrl,
    username,
    password,
    proxies: sharedMarzbanJsonObject(env.MARZBAN_PROXIES_JSON || settings?.marzban_proxies_json || "{}", "ШӘЩҶШёЫҢЩ… Proxies Щ…ШұШІШЁШ§ЩҶ"),
    inbounds: sharedMarzbanJsonObject(env.MARZBAN_INBOUNDS_JSON || settings?.marzban_inbounds_json || "{}", "ШӘЩҶШёЫҢЩ… Inbounds Щ…ШұШІШЁШ§ЩҶ"),
    templateUsername: cleanText(env.MARZBAN_TEMPLATE_USERNAME || settings?.marzban_template_username || "", 200),
    dashboardUrl: sharedMarzbanDashboardUrl(panelUrl),
    pricePerGb: Math.max(0, Number(env.MARZBAN_PRICE_PER_GB || settings?.marzban_price_per_gb || settings?.price_per_gb || 0)),
    suspendOnDebt: String(env.MARZBAN_SUSPEND_ON_DEBT ?? settings?.marzban_suspend_on_debt ?? "true").toLowerCase() !== "false",
    syncBatch: Math.max(1, Math.min(20, Number(env.MARZBAN_SYNC_BATCH || settings?.marzban_sync_batch || 10)))
  };
}

function sharedServiceBaseUrl(settings, env = {}) {
  // Legacy helper is intentionally PasarGuard-only in dual-panel mode.
  return pasarguardBaseUrl(settings);
}

async function getSharedMarzbanToken(env, settings, force = false) {
  const cfg = sharedMarzbanConfig(settings, env);
  const key = cfg.panelUrl + "|" + cfg.username;
  const cached = sharedMarzbanTokenCache.get(key);
  if (!force && cached && cached.expiresAt > Date.now() + 30000) return cached.token;
  const form = new URLSearchParams();
  form.set("username", cfg.username);
  form.set("password", cfg.password);
  const response = await fetch(cfg.panelUrl + "/api/admin/token", {
    method: "POST",
    headers: { "content-type": "application/x-www-form-urlencoded", accept: "application/json" },
    body: form.toString()
  });
  const data = await response.json().catch(() => ({}));
  if (!response.ok || !data?.access_token) {
    const detail = data?.detail || data?.message || data?.error || ("HTTP " + response.status);
    const error = new Error("ЩҲШұЩҲШҜ ШЁЩҮ Щ…ШұШІШЁШ§ЩҶ ЩҶШ§Щ…ЩҲЩҒЩӮ ШЁЩҲШҜ: " + (typeof detail === "string" ? detail : JSON.stringify(detail)));
    error.status = response.status;
    throw error;
  }
  const token = String(data.access_token);
  sharedMarzbanTokenCache.set(key, { token, expiresAt: Date.now() + 50 * 60 * 1000 });
  return token;
}

function normalizeSharedMarzbanExpire(value) {
  if (value === null || value === undefined || value === "" || Number(value) === 0) return 0;
  if (typeof value === "number" || /^\d+$/.test(String(value))) {
    const numeric = Number(value);
    return Math.floor(numeric > 100000000000 ? numeric / 1000 : numeric);
  }
  const timestamp = Date.parse(String(value));
  if (!Number.isFinite(timestamp)) throw new Error("ШӘШ§ШұЫҢШ® Ш§ЩҶЩӮШ¶Ш§ЫҢ ШіШұЩҲЫҢШі Щ…Ш№ШӘШЁШұ ЩҶЫҢШіШӘ");
  return Math.floor(timestamp / 1000);
}

function normalizeSharedMarzbanPayload(method, path, body, cfg) {
  if (body === undefined) return undefined;
  const payload = { ...(body || {}) };
  delete payload.group_ids;
  if (payload.expire !== undefined) payload.expire = normalizeSharedMarzbanExpire(payload.expire);
  if (String(method).toUpperCase() === "POST" && String(path) === "/api/user") {
    if (!payload.proxies) payload.proxies = cfg.proxies;
    if (!payload.inbounds) payload.inbounds = cfg.inbounds;
    if (!payload.data_limit_reset_strategy) payload.data_limit_reset_strategy = "no_reset";
  }
  return payload;
}

async function sharedMarzbanRequest(env, method, path, body, retry = true) {
  const settings = await getSettings(env);
  const cfg = sharedMarzbanConfig(settings, env);
  const token = await getSharedMarzbanToken(env, settings, false);
  const payload = normalizeSharedMarzbanPayload(method, path, body, cfg);
  const response = await fetch(cfg.panelUrl + path, {
    method,
    headers: {
      authorization: "Bearer " + token,
      accept: "application/json",
      ...(payload === undefined ? {} : { "content-type": "application/json" })
    },
    body: payload === undefined ? undefined : JSON.stringify(payload)
  });
  if (response.status === 401 && retry) {
    sharedMarzbanTokenCache.delete(cfg.panelUrl + "|" + cfg.username);
    return sharedMarzbanRequest(env, method, path, body, false);
  }
  if (response.status === 204) return {};
  const data = await response.json().catch(() => ({}));
  if (!response.ok) {
    const detail = data?.detail || data?.message || data?.error || ("HTTP " + response.status);
    const error = new Error(typeof detail === "string" ? detail : JSON.stringify(detail));
    error.status = response.status;
    throw error;
  }
  return data;
}

async function servicePanelRequest(env, agency, method, path, body, retry = true) {
  // Backward-compatible PasarGuard request. Provider-aware paths must use servicePanelRequestForProvider.
  return agencyPasarguardRequest(env, agency, method, path, body, retry);
}

let sharedMarzbanTrialSchemaReady = false;

async function ensureSharedMarzbanTables(env) {
  await env.PASARGUARD_DB.batch([
    env.PASARGUARD_DB.prepare(`CREATE TABLE IF NOT EXISTS shared_backend_accounts (
      bot_id TEXT PRIMARY KEY, provider TEXT NOT NULL DEFAULT 'marzban', initialized INTEGER NOT NULL DEFAULT 0,
      revision INTEGER NOT NULL DEFAULT 0, billing_remainder INTEGER NOT NULL DEFAULT 0,
      base_billing_remainder INTEGER NOT NULL DEFAULT 0, margin_billing_remainder INTEGER NOT NULL DEFAULT 0,
      unpaid_toman INTEGER NOT NULL DEFAULT 0, unpaid_base_toman INTEGER NOT NULL DEFAULT 0,
      unpaid_margin_toman INTEGER NOT NULL DEFAULT 0, total_charged INTEGER NOT NULL DEFAULT 0,
      total_collected INTEGER NOT NULL DEFAULT 0, total_parent_profit INTEGER NOT NULL DEFAULT 0,
      upstream_unpaid_toman INTEGER NOT NULL DEFAULT 0, upstream_total_charged INTEGER NOT NULL DEFAULT 0,
      upstream_total_collected INTEGER NOT NULL DEFAULT 0, parent_income_total INTEGER NOT NULL DEFAULT 0,
      parent_income_collected INTEGER NOT NULL DEFAULT 0, parent_net_profit_total INTEGER NOT NULL DEFAULT 0,
      last_delta_bytes INTEGER NOT NULL DEFAULT 0, last_synced_at TEXT, last_error TEXT,
      created_at TEXT NOT NULL, updated_at TEXT NOT NULL)`),
    env.PASARGUARD_DB.prepare(`CREATE TABLE IF NOT EXISTS shared_backend_usage_events (
      event_key TEXT PRIMARY KEY, processing_token TEXT NOT NULL, applied INTEGER NOT NULL DEFAULT 0,
      bot_id TEXT NOT NULL, parent_bot_id TEXT, owner_user_id INTEGER NOT NULL, revision_from INTEGER NOT NULL,
      delta_bytes INTEGER NOT NULL, charged_amount INTEGER NOT NULL, base_cost_amount INTEGER NOT NULL DEFAULT 0,
      parent_profit_amount INTEGER NOT NULL DEFAULT 0, collected_amount INTEGER NOT NULL DEFAULT 0,
      parent_profit_collected INTEGER NOT NULL DEFAULT 0, unpaid_after INTEGER NOT NULL DEFAULT 0,
      parent_income_amount INTEGER NOT NULL DEFAULT 0, parent_income_collected INTEGER NOT NULL DEFAULT 0,
      upstream_collected_amount INTEGER NOT NULL DEFAULT 0, upstream_unpaid_after INTEGER NOT NULL DEFAULT 0,
      parent_net_profit_amount INTEGER NOT NULL DEFAULT 0,
      price_per_gb INTEGER NOT NULL, service_count INTEGER NOT NULL DEFAULT 0,
      details_json TEXT NOT NULL DEFAULT '[]', created_at TEXT NOT NULL)`),
    env.PASARGUARD_DB.prepare(`CREATE TABLE IF NOT EXISTS shared_service_ownership (
      provider TEXT NOT NULL, panel_scope TEXT NOT NULL, remote_username TEXT NOT NULL,
      bot_id TEXT NOT NULL, customer_id TEXT, root_order_id TEXT, created_at TEXT NOT NULL,
      updated_at TEXT NOT NULL, PRIMARY KEY(provider,panel_scope,remote_username))`),
    env.PASARGUARD_DB.prepare(`CREATE INDEX IF NOT EXISTS idx_shared_backend_accounts_sync ON shared_backend_accounts(last_synced_at,updated_at)`),
    env.PASARGUARD_DB.prepare(`CREATE INDEX IF NOT EXISTS idx_shared_backend_usage_events_bot ON shared_backend_usage_events(bot_id,created_at DESC)`),
    env.PASARGUARD_DB.prepare(`CREATE INDEX IF NOT EXISTS idx_shared_service_ownership_bot ON shared_service_ownership(bot_id,updated_at DESC)`),
    env.PASARGUARD_DB.prepare(`CREATE UNIQUE INDEX IF NOT EXISTS idx_wallet_ledger_shared_marzban_event ON wallet_ledger(type,ref_type,ref_id) WHERE ref_type='shared_marzban_event' AND type IN ('shared_marzban_usage','shared_marzban_margin')`)
  ]);

  const cascadeAccountColumns = [
    ["upstream_unpaid_toman", "INTEGER NOT NULL DEFAULT 0"],
    ["upstream_total_charged", "INTEGER NOT NULL DEFAULT 0"],
    ["upstream_total_collected", "INTEGER NOT NULL DEFAULT 0"],
    ["parent_income_total", "INTEGER NOT NULL DEFAULT 0"],
    ["parent_income_collected", "INTEGER NOT NULL DEFAULT 0"],
    ["parent_net_profit_total", "INTEGER NOT NULL DEFAULT 0"]
  ];
  const cascadeEventColumns = [
    ["parent_income_amount", "INTEGER NOT NULL DEFAULT 0"],
    ["parent_income_collected", "INTEGER NOT NULL DEFAULT 0"],
    ["upstream_collected_amount", "INTEGER NOT NULL DEFAULT 0"],
    ["upstream_unpaid_after", "INTEGER NOT NULL DEFAULT 0"],
    ["parent_net_profit_amount", "INTEGER NOT NULL DEFAULT 0"]
  ];
  for (const [table, columns] of [["shared_backend_accounts", cascadeAccountColumns], ["shared_backend_usage_events", cascadeEventColumns]]) {
    const info = await env.PASARGUARD_DB.prepare("PRAGMA table_info(" + table + ")").all();
    const existing = new Set((info.results || []).map(row => String(row.name || "")));
    for (const [name, definition] of columns) {
      if (existing.has(name)) continue;
      try { await env.PASARGUARD_DB.prepare("ALTER TABLE " + table + " ADD COLUMN " + name + " " + definition).run(); }
      catch (error) { if (!/duplicate column/i.test(String(error?.message || error))) throw error; }
    }
  }
  await env.PASARGUARD_DB.prepare(`CREATE UNIQUE INDEX IF NOT EXISTS idx_wallet_ledger_shared_marzban_cascade
    ON wallet_ledger(user_id,type,ref_type,ref_id)
    WHERE ref_type='shared_marzban_event' AND type IN ('shared_marzban_usage','shared_marzban_downline_income','shared_marzban_upstream_cost')`).run();

  if (!sharedMarzbanTrialSchemaReady) {
    const info = await env.PASARGUARD_DB.prepare("PRAGMA table_info(sales_trials)").all();
    const existing = new Set((info.results || []).map(row => String(row.name || "")));
    const required = [
      ["remote_status", "TEXT"], ["remote_data_limit", "INTEGER"],
      ["remote_used_traffic", "INTEGER NOT NULL DEFAULT 0"], ["remote_expire", "TEXT"],
      ["remote_online_at", "TEXT"], ["remote_last_synced_at", "TEXT"]
    ];
    for (const [name, definition] of required) {
      if (existing.has(name)) continue;
      try { await env.PASARGUARD_DB.prepare(`ALTER TABLE sales_trials ADD COLUMN ${name} ${definition}`).run(); }
      catch (error) { if (!/duplicate column/i.test(String(error?.message || error))) throw error; }
    }
    sharedMarzbanTrialSchemaReady = true;
  }
}

async function ensureSharedBackendAccount(env, botId, activate = false) {
  await ensureSharedMarzbanTables(env);
  const ts = nowIso();
  await env.PASARGUARD_DB.prepare(`INSERT OR IGNORE INTO shared_backend_accounts(bot_id,provider,initialized,created_at,updated_at) VALUES(?,'marzban',?,?,?)`)
    .bind(botId, activate ? 1 : 0, ts, ts).run();
  if (activate) await env.PASARGUARD_DB.prepare("UPDATE shared_backend_accounts SET initialized=1,updated_at=? WHERE bot_id=?").bind(ts,botId).run();
  return env.PASARGUARD_DB.prepare("SELECT * FROM shared_backend_accounts WHERE bot_id=?").bind(botId).first();
}

async function claimSharedServiceOwnership(env, botId, customerId, orderId, username, provider = "marzban") {
  if(normalizeServiceProvider(provider)!=="marzban") return { claimed:false };
  const settings = await getSettings(env);
  if (!sharedMarzbanEnabled(settings, env)) throw new Error("Щ…ШұШІШЁШ§ЩҶ Щ…ШҙШӘШұЪ© Щ…ШұЪ©ШІЫҢ ЩҒШ№Ш§Щ„ ЩҶЫҢШіШӘ");
  await ensureSharedMarzbanTables(env);
  const cfg = sharedMarzbanConfig(settings, env);
  const scope = cfg.panelUrl.toLowerCase();
  const normalized = String(username || "").trim().toLowerCase();
  const ts = nowIso();
  await env.PASARGUARD_DB.prepare(`INSERT OR IGNORE INTO shared_service_ownership(provider,panel_scope,remote_username,bot_id,customer_id,root_order_id,created_at,updated_at) VALUES('marzban',?,?,?,?,?,?,?)`)
    .bind(scope, normalized, botId, customerId || null, orderId || null, ts, ts).run();
  const row = await env.PASARGUARD_DB.prepare(`SELECT bot_id FROM shared_service_ownership WHERE provider='marzban' AND panel_scope=? AND remote_username=?`)
    .bind(scope, normalized).first();
  if (row && String(row.bot_id) !== String(botId)) throw new Error("Ш§ЫҢЩҶ ЩҶШ§Щ… Ъ©Ш§ШұШЁШұЫҢ Щ…ШұШІШЁШ§ЩҶ ЩӮШЁЩ„Ш§ЩӢ ШЁЩҮ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ШҜЫҢЪҜШұЫҢ ШӘШ№Щ„ЩӮ ШҜШ§ШұШҜ");
  await env.PASARGUARD_DB.prepare(`UPDATE shared_service_ownership SET customer_id=COALESCE(?,customer_id),root_order_id=COALESCE(?,root_order_id),updated_at=? WHERE provider='marzban' AND panel_scope=? AND remote_username=? AND bot_id=?`)
    .bind(customerId || null, orderId || null, ts, scope, normalized, botId).run();
  await ensureSharedBackendAccount(env, botId, true);
  return { claimed: true };
}


function salesRemoteExpireValue(value) {
  if (value === null || value === undefined || value === "" || value === 0 || value === "0") return null;
  const normalized = typeof value === "string" ? value.trim() : value;
  if ((typeof normalized === "number" && Number.isFinite(normalized)) || (typeof normalized === "string" && /^\d+$/.test(normalized))) {
    const numeric = Number(normalized);
    const ms = numeric > 1000000000000 ? numeric : numeric * 1000;
    const date = new Date(ms);
    return Number.isFinite(date.getTime()) ? date.toISOString() : null;
  }
  const parsed = Date.parse(String(normalized));
  return Number.isFinite(parsed) ? new Date(parsed).toISOString() : null;
}

function salesRemoteSnapshot(remote = {}, fallback = {}) {
  const nested = remote && typeof remote.data === "object" && remote.data ? remote.data : {};
  const source = { ...remote, ...nested };
  const dataLimit = Math.max(0, Number(source.data_limit ?? source.dataLimit ?? fallback.remote_data_limit ?? 0));
  const usedTraffic = Math.max(0, Number(source.used_traffic ?? source.usedTraffic ?? fallback.remote_used_traffic ?? 0));
  const expire = salesRemoteExpireValue(source.expire ?? fallback.remote_expire);
  const subscriptionUrl = cleanText(source.subscription_url || fallback.subscription_url, 2000);
  return {
    status: cleanText(source.status || fallback.remote_status || "active", 40) || "active",
    dataLimit,
    usedTraffic,
    expire,
    onlineAt: salesRemoteExpireValue(source.online_at || source.onlineAt || fallback.remote_online_at),
    subscriptionUrl,
    syncedAt: nowIso()
  };
}

function salesSubscriptionAllowedHosts(settings) {
  const hosts = new Set();
  const add = (raw) => {
    const value = String(raw || "").trim();
    if (!value) return;
    try {
      const parsed = new URL(value.includes("://") ? value : ("https://" + value));
      if (parsed.hostname) hosts.add(parsed.hostname.toLowerCase());
    } catch (_) {}
  };
  add(settings?.pasarguard_panel_url);
  add(settings?.pasarguard_sub_domain);
  add(settings?.marzban_panel_url);
  return hosts;
}

function salesSubscriptionAllowedPorts(settings) {
  // HTTPS alternate ports supported by Cloudflare and commonly used by PasarGuard deployments.
  const ports = new Set(["", "443", "2053", "2083", "2087", "2096", "8443"]);
  for (const raw of [settings?.pasarguard_panel_url, settings?.pasarguard_sub_domain, settings?.marzban_panel_url]) {
    const value = String(raw || "").trim();
    if (!value) continue;
    try {
      const parsed = new URL(value.includes("://") ? value : ("https://" + value));
      ports.add(parsed.port || "443");
    } catch (_) {}
  }
  return ports;
}

function parseSalesSubscriptionLink(rawLink, settings) {
  let value = cleanText(rawLink, 2000).trim();
  value = value.replace(/^<|>$/g, "").trim();
  if (!value) throw new Error("Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© ШұШ§ Ш§ШұШіШ§Щ„ Ъ©ЩҶЫҢШҜ");
  let url;
  try { url = new URL(value); } catch (_) { throw new Error("ЩҒШұЩ…ШӘ Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© Щ…Ш№ШӘШЁШұ ЩҶЫҢШіШӘ"); }
  if (url.protocol !== "https:") throw new Error("Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© ШЁШ§ЫҢШҜ ШЁШ§ https ШҙШұЩҲШ№ ШҙЩҲШҜ");
  if (url.username || url.password) throw new Error("Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© ШҜШ§ШұШ§ЫҢ Ш§Ш·Щ„Ш§Ш№Ш§ШӘ ЩҲШұЩҲШҜ ЩҶШ§Щ…Ш№ШӘШЁШұ Ш§ШіШӘ");
  const allowedPorts = salesSubscriptionAllowedPorts(settings);
  const effectivePort = url.port || "443";
  if (!allowedPorts.has(effectivePort)) {
    throw new Error("ЩҫЩҲШұШӘ Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© ШЁШ§ ШӘЩҶШёЫҢЩ…Ш§ШӘ ЩҫЩҶЩ„ Ш§ЫҢЩҶ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ Щ…Ш·Ш§ШЁЩӮШӘ ЩҶШҜШ§ШұШҜ");
  }
  const allowedHosts = salesSubscriptionAllowedHosts(settings);
  if (!allowedHosts.size || !allowedHosts.has(url.hostname.toLowerCase())) {
    throw new Error("ШҜШ§Щ…ЩҶЩҮ Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© Щ…ШӘШ№Щ„ЩӮ ШЁЩҮ ЩҫЩҶЩ„ Щ…ШӘШөЩ„ Ш§ЫҢЩҶ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ЩҶЫҢШіШӘ");
  }
  url.hash = "";
  url.search = "";
  let path = url.pathname.replace(/\/+$/, "");
  path = path.replace(/\/(?:info|raw|usage|apps)$/i, "").replace(/\/+$/, "");
  const parts = path.split("/").filter(Boolean);
  if (parts.length < 2) throw new Error("Щ…ШіЫҢШұ Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© Щ…Ш№ШӘШЁШұ ЩҶЫҢШіШӘ");
  let token = "";
  try { token = decodeURIComponent(parts[parts.length - 1]); } catch (_) { token = parts[parts.length - 1]; }
  if (!/^[A-Za-z0-9._~-]{8,1024}$/.test(token)) throw new Error("ШӘЩҲЪ©ЩҶ Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© Щ…Ш№ШӘШЁШұ ЩҶЫҢШіШӘ");
  return {
    token,
    tokenNormalized: token,
    subscriptionUrl: url.origin + path,
    infoUrl: url.origin + path + "/info",
    host: url.hostname.toLowerCase()
  };
}

async function fetchSalesSubscriptionInfo(env, rawLink) {
  const settings = await getSettings(env);
  const parsed = parseSalesSubscriptionLink(rawLink, settings);
  let response;
  try {
    response = await fetchWithTimeout(parsed.infoUrl, {
      method: "GET",
      headers: { accept: "application/json", "user-agent": "BluePanel-Service-Import/" + APP_VERSION },
      redirect: "manual"
    }, 10000);
  } catch (error) {
    if (String(error?.name || "") === "AbortError") throw new Error("Ш§ШіШӘШ№Щ„Ш§Щ… Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© ШІЩ…Ш§ЩҶвҖҢШЁШұ ШҙШҜШӣ ШҜЩҲШЁШ§ШұЩҮ ШӘЩ„Ш§Шҙ Ъ©ЩҶЫҢШҜ");
    throw new Error("Ш§ШӘШөШ§Щ„ ШЁЩҮ Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© Ш§ЩҶШ¬Ш§Щ… ЩҶШҙШҜ");
  }
  if (response.status >= 300 && response.status < 400) throw new Error("Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© ШЁЩҮ ШўШҜШұШі ШҜЫҢЪҜШұЫҢ ЩҮШҜШ§ЫҢШӘ ШҙШҜ ЩҲ ЩӮШ§ШЁЩ„ ЩҫШ°ЫҢШұШҙ ЩҶЫҢШіШӘ");
  const { data } = await readJsonResponseSafe(response, "ЩҫЩҶЩ„ Ш§ШҙШӘШұШ§Ъ©");
  if (!response.ok) {
    if ([401, 403, 404, 410].includes(Number(response.status))) throw new Error("Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© ЩҶШ§Щ…Ш№ШӘШЁШұШҢ Щ…ЩҶЩӮШ¶ЫҢ ЫҢШ§ ШӘШ№ЩҲЫҢШ¶вҖҢШҙШҜЩҮ Ш§ШіШӘ");
    throw new Error(cleanText(data?.detail || data?.message || "Ш§ШіШӘШ№Щ„Ш§Щ… Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© ЩҶШ§Щ…ЩҲЩҒЩӮ ШЁЩҲШҜ", 300));
  }
  const nested = data && typeof data.data === "object" && data.data ? data.data : {};
  const info = { ...data, ...nested };
  const username = cleanText(info.username, 128);
  if (!username) throw new Error("ЩҶШ§Щ… Ъ©Ш§ШұШЁШұЫҢ ШіШұЩҲЫҢШі Ш§ШІ Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© ШҜШұЫҢШ§ЩҒШӘ ЩҶШҙШҜ");
  return { parsed, info, username };
}

async function ensureSalesImportedPlan(env, botId) {
  const existing = await env.PASARGUARD_DB.prepare(
    "SELECT id FROM sales_plans WHERE bot_id=? AND plan_type='imported' LIMIT 1"
  ).bind(botId).first();
  if (existing?.id) return existing.id;
  const planId = "sysimp_" + String(botId).replace(/[^A-Za-z0-9_-]/g, "").slice(0, 72);
  const ts = nowIso();
  await env.PASARGUARD_DB.prepare(`
    INSERT OR IGNORE INTO sales_plans(
      id,bot_id,title,data_limit_bytes,duration_days,price_toman,status,sort_order,category_id,location_id,plan_type,created_at,updated_at
    ) VALUES(?,?,?,0,1,0,'inactive',999999,NULL,NULL,'imported',?,?)
  `).bind(planId, botId, "ШіШұЩҲЫҢШі ЩӮШЁЩ„ЫҢ Ш§ЩҶШӘЩӮШ§Щ„вҖҢЫҢШ§ЩҒШӘЩҮ", ts, ts).run();
  const row = await env.PASARGUARD_DB.prepare(
    "SELECT id FROM sales_plans WHERE bot_id=? AND plan_type='imported' LIMIT 1"
  ).bind(botId).first();
  if (!row?.id) throw new Error("ШіШ§Ш®ШӘ ШұЪ©ЩҲШұШҜ ШіЫҢШіШӘЩ…ЫҢ Ш§ЩҶШӘЩӮШ§Щ„ ШіШұЩҲЫҢШі Ш§ЩҶШ¬Ш§Щ… ЩҶШҙШҜ");
  return row.id;
}

async function importSalesServiceBySubscriptionLink(env, bot, customer, rawLink) {
  if (bot.agency_status !== "active") throw new Error("ЩҫЩҶЩ„ Щ…ШӘШөЩ„ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ЩҒШ№Ш§Щ„ ЩҶЫҢШіШӘ");
  const publicResult = await fetchSalesSubscriptionInfo(env, rawLink);
  const remoteUsername = cleanText(publicResult.username, 128);
  const normalizedUsername = remoteUsername.toLowerCase();
  const agency = { id: bot.agency_id, panel_username: bot.panel_username, panel_password_enc: bot.panel_password_enc };
  let remote;
  try {
    remote = await servicePanelRequest(env, agency, "GET", "/api/user/" + encodeURIComponent(remoteUsername));
  } catch (error) {
    if ([403, 404].includes(Number(error?.status))) throw new Error("Ш§ЫҢЩҶ ШіШұЩҲЫҢШі ШІЫҢШұЩ…Ш¬Щ…ЩҲШ№ЩҮ ЩҫЩҶЩ„ Ш§ЫҢЩҶ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ЩҶЫҢШіШӘ");
    throw error;
  }
  const snapshot = salesRemoteSnapshot(remote, publicResult.info);
  const settings = await getSettings(env);
  const remoteNested = remote && typeof remote.data === "object" && remote.data ? remote.data : {};
  const authenticatedUsername = cleanText(remoteNested.username || remote.username, 128).toLowerCase();
  if (authenticatedUsername && authenticatedUsername !== normalizedUsername) {
    throw new Error("Щ…Ш§Щ„Ъ©ЫҢШӘ Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© ШЁШ§ ШӯШіШ§ШЁ ЩҫЩҶЩ„ Ш§ЫҢЩҶ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ Щ…Ш·Ш§ШЁЩӮШӘ ЩҶШҜШ§ШұШҜ");
  }

  // A successful public /info response already proves that the submitted token is active.
  // PasarGuard may return a different canonical/signed subscription_url for the same user,
  // so raw token equality must not be used as an ownership check.
  let canonicalParsed = publicResult.parsed;
  let apiCanonicalUrl = snapshot.subscriptionUrl;
  if (apiCanonicalUrl && apiCanonicalUrl.startsWith("/")) apiCanonicalUrl = sharedServiceBaseUrl(settings, env) + apiCanonicalUrl;
  if (apiCanonicalUrl) {
    try {
      const apiParsed = parseSalesSubscriptionLink(apiCanonicalUrl, settings);
      if (apiParsed.tokenNormalized === publicResult.parsed.tokenNormalized) canonicalParsed = apiParsed;
    } catch (_) {
      // Keep the submitted URL because its /info endpoint was verified successfully.
    }
  }
  const canonicalUrl = canonicalParsed.subscriptionUrl;
  const panelScope = canonicalParsed.host;

  const priorClaim = await env.PASARGUARD_DB.prepare(
    "SELECT bot_id,customer_id,root_order_id FROM sales_service_claims WHERE panel_scope=? AND remote_username=?"
  ).bind(panelScope, normalizedUsername).first();
  if (priorClaim && (String(priorClaim.bot_id) !== String(bot.id) || String(priorClaim.customer_id) !== String(customer.id))) {
    throw new Error("Ш§ЫҢЩҶ ШіШұЩҲЫҢШі ЩӮШЁЩ„Ш§ЩӢ ШҜШұ ШұШЁШ§ШӘ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ЫҢШ§ ШӯШіШ§ШЁ ШӘЩ„ЪҜШұШ§Щ… ШҜЫҢЪҜШұЫҢ Ш«ШЁШӘ ШҙШҜЩҮ Ш§ШіШӘ");
  }

  const existing = await env.PASARGUARD_DB.prepare(`
    SELECT id,customer_id,remote_username,created_at
    FROM sales_orders
    WHERE bot_id=? AND LOWER(remote_username)=? AND status='delivered'
    ORDER BY CASE WHEN order_type IN ('new','imported') THEN 0 ELSE 1 END,created_at ASC
    LIMIT 1
  `).bind(bot.id, normalizedUsername).first();
  if (existing && String(existing.customer_id) !== String(customer.id)) {
    throw new Error("Ш§ЫҢЩҶ ШіШұЩҲЫҢШі ЩӮШЁЩ„Ш§ЩӢ ШЁЩҮ ШӯШіШ§ШЁ ШӘЩ„ЪҜШұШ§Щ… ШҜЫҢЪҜШұЫҢ ШҜШұ ЩҮЩ…ЫҢЩҶ ШұШЁШ§ШӘ Щ…ШӘШөЩ„ ШҙШҜЩҮ Ш§ШіШӘ");
  }

  const tokenHash = await sha256Hex(publicResult.parsed.token);
  if (existing) {
    await env.PASARGUARD_DB.batch([
      env.PASARGUARD_DB.prepare(`
        UPDATE sales_orders SET subscription_url=?,remote_user_id=COALESCE(NULLIF(?,''),remote_user_id),
          remote_status=?,remote_data_limit=?,remote_used_traffic=?,remote_expire=?,remote_online_at=?,
          remote_last_synced_at=?,service_provider='pasarguard'
        WHERE bot_id=? AND customer_id=? AND LOWER(remote_username)=? AND status='delivered'
      `).bind(canonicalUrl, String(remote?.id || remote?.data?.id || ""), snapshot.status, snapshot.dataLimit,
        snapshot.usedTraffic, snapshot.expire, snapshot.onlineAt, snapshot.syncedAt, bot.id, customer.id, normalizedUsername),
      env.PASARGUARD_DB.prepare(`
        INSERT INTO sales_service_claims(panel_scope,remote_username,bot_id,customer_id,root_order_id,claim_type,subscription_token_hash,claimed_at,updated_at)
        VALUES(?,?,?,?,?,?,?,?,?)
        ON CONFLICT(panel_scope,remote_username) DO UPDATE SET
          subscription_token_hash=excluded.subscription_token_hash,updated_at=excluded.updated_at
        WHERE sales_service_claims.bot_id=excluded.bot_id AND sales_service_claims.customer_id=excluded.customer_id
      `).bind(panelScope, normalizedUsername, bot.id, customer.id, existing.id, "existing", tokenHash, nowIso(), nowIso())
    ]);
    await claimSharedServiceOwnership(env, bot.id, customer.id, existing.id, remoteUsername, "pasarguard");
    await salesEvent(env, bot.id, customer.id, "service_import_refreshed", { serviceId: existing.id, username: remoteUsername });
    return {
      id: existing.id, remote_username: remoteUsername, subscription_url: canonicalUrl, imported: false, alreadyLinked: true,
      remote_status: snapshot.status, remote_data_limit: snapshot.dataLimit, remote_used_traffic: snapshot.usedTraffic,
      remote_expire: snapshot.expire, remote_online_at: snapshot.onlineAt, remote_last_synced_at: snapshot.syncedAt, import_runtime_version: APP_VERSION
    };
  }

  const generatedOrderId = id("ordimp");
  const claimAt = nowIso();
  await env.PASARGUARD_DB.prepare(`
    INSERT OR IGNORE INTO sales_service_claims(
      panel_scope,remote_username,bot_id,customer_id,root_order_id,claim_type,subscription_token_hash,claimed_at,updated_at
    ) VALUES(?,?,?,?,?,?,?,?,?)
  `).bind(panelScope, normalizedUsername, bot.id, customer.id, generatedOrderId, "import", tokenHash, claimAt, claimAt).run();
  const claim = await env.PASARGUARD_DB.prepare(
    "SELECT * FROM sales_service_claims WHERE panel_scope=? AND remote_username=?"
  ).bind(panelScope, normalizedUsername).first();
  if (!claim || String(claim.bot_id) !== String(bot.id) || String(claim.customer_id) !== String(customer.id)) {
    throw new Error("Ш§ЫҢЩҶ ШіШұЩҲЫҢШі ЩҮЩ…вҖҢШІЩ…Ш§ЩҶ ШҜШұ ШұШЁШ§ШӘ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ЫҢШ§ ШӯШіШ§ШЁ ШҜЫҢЪҜШұЫҢ Ш«ШЁШӘ ШҙШҜЩҮ Ш§ШіШӘ");
  }
  const orderId = String(claim.root_order_id || generatedOrderId);
  const claimedOrder = await env.PASARGUARD_DB.prepare(
    "SELECT id FROM sales_orders WHERE id=? AND bot_id=? AND customer_id=?"
  ).bind(orderId, bot.id, customer.id).first();
  if (claimedOrder?.id) {
    await env.PASARGUARD_DB.prepare(`
      UPDATE sales_orders SET subscription_url=?,remote_status=?,remote_data_limit=?,remote_used_traffic=?,
        remote_expire=?,remote_online_at=?,remote_last_synced_at=?,service_provider='pasarguard' WHERE id=?
    `).bind(canonicalUrl, snapshot.status, snapshot.dataLimit, snapshot.usedTraffic, snapshot.expire,
      snapshot.onlineAt, snapshot.syncedAt, orderId).run();
    return {
      id: orderId, remote_username: remoteUsername, subscription_url: canonicalUrl, imported: false, alreadyLinked: true,
      remote_status: snapshot.status, remote_data_limit: snapshot.dataLimit, remote_used_traffic: snapshot.usedTraffic,
      remote_expire: snapshot.expire, remote_online_at: snapshot.onlineAt, remote_last_synced_at: snapshot.syncedAt, import_runtime_version: APP_VERSION
    };
  }

  const planId = await ensureSalesImportedPlan(env, bot.id);
  const remoteId = String(remote?.id || remote?.data?.id || publicResult.info?.id || "");
  try {
    await env.PASARGUARD_DB.prepare(`
      INSERT INTO sales_orders(
        id,bot_id,plan_id,customer_id,amount_toman,original_amount_toman,discount_toman,status,
        remote_user_id,remote_username,subscription_url,remote_status,remote_data_limit,remote_used_traffic,
        remote_expire,remote_online_at,remote_last_synced_at,order_type,payment_method,origin,service_provider,created_at,updated_at
      ) VALUES(?,?,?,?,0,0,0,'delivered',?,?,?,?,?,?,?,?,?,'imported','import','subscription_link','pasarguard',?,?)
    `).bind(orderId, bot.id, planId, customer.id, remoteId, remoteUsername, canonicalUrl, snapshot.status,
      snapshot.dataLimit, snapshot.usedTraffic, snapshot.expire, snapshot.onlineAt, snapshot.syncedAt, claimAt, claimAt).run();
  } catch (error) {
    try {
      await env.PASARGUARD_DB.prepare(
        "DELETE FROM sales_service_claims WHERE panel_scope=? AND remote_username=? AND bot_id=? AND customer_id=? AND root_order_id=?"
      ).bind(panelScope, normalizedUsername, bot.id, customer.id, orderId).run();
    } catch (_) {}
    throw error;
  }
  await claimSharedServiceOwnership(env, bot.id, customer.id, orderId, remoteUsername, "pasarguard");
  await salesEvent(env, bot.id, customer.id, "service_imported", { serviceId: orderId, username: remoteUsername });
  try {
    await queueReportEvent(env, bot.id, "service_imports", "ШіШұЩҲЫҢШі ЩӮШЁЩ„ЫҢ ШЁЩҮ ШұШЁШ§ШӘ Щ…ШӘШөЩ„ ШҙШҜ",
      "Ъ©Ш§ШұШЁШұ <code>" + botEscape(customer.telegram_id) + "</code> ШіШұЩҲЫҢШі <code>" + botEscape(remoteUsername) + "</code> ШұШ§ ШЁШ§ Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© Щ…Ш№ШӘШЁШұ Ш«ШЁШӘ Ъ©ШұШҜ.",
      "service-import:" + bot.id + ":" + normalizedUsername);
  } catch (_) {}
  return {
    id: orderId, remote_username: remoteUsername, subscription_url: canonicalUrl, imported: true, alreadyLinked: false,
    remote_status: snapshot.status, remote_data_limit: snapshot.dataLimit, remote_used_traffic: snapshot.usedTraffic,
    remote_expire: snapshot.expire, remote_online_at: snapshot.onlineAt, remote_last_synced_at: snapshot.syncedAt, import_runtime_version: APP_VERSION
  };
}

function buildSalesServices(orderRows = []) {
  const groups = new Map();
  for (const row of orderRows || []) {
    if (String(row.status || "") !== "delivered" || !row.remote_username) continue;
    if (["deleted", "removed", "remote_missing"].includes(String(row.remote_status || "").toLowerCase())) continue;
    const key = normalizeServiceProvider(row.service_provider)+":"+String(row.remote_username).toLowerCase();
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key).push(row);
  }
  const services = [];
  for (const rows of groups.values()) {
    rows.sort((a, b) => Date.parse(b.updated_at || b.created_at || 0) - Date.parse(a.updated_at || a.created_at || 0));
    const oldest = [...rows].sort((a, b) => Date.parse(a.created_at || 0) - Date.parse(b.created_at || 0))[0];
    const root = rows.find(row => String(row.order_type || "new") === "new" && !row.target_order_id) || oldest;
    const latest = rows[0];
    const snap = rows.find(row => row.remote_last_synced_at) || latest;
    services.push({
      id: root.id,
      latest_order_id: latest.id,
      plan_title: root.plan_title || latest.plan_title || "ШіШұЩҲЫҢШі",
      remote_username: latest.remote_username || root.remote_username,
      service_provider: normalizeServiceProvider(latest.service_provider || root.service_provider),
      service_provider_label: serviceProviderLabel(latest.service_provider || root.service_provider),
      subscription_url: latest.subscription_url || root.subscription_url || "",
      remote_status: snap.remote_status || "active",
      remote_data_limit: Math.max(0, Number(snap.remote_data_limit || 0)),
      remote_used_traffic: Math.max(0, Number(snap.remote_used_traffic || 0)),
      remote_expire: snap.remote_expire || null,
      remote_online_at: snap.remote_online_at || null,
      remote_last_synced_at: snap.remote_last_synced_at || null,
      category_id: root.category_id || latest.category_id || null,
      category_title: root.category_title || latest.category_title || "",
      category_emoji: root.category_emoji || latest.category_emoji || "",
      location_id: root.location_id || latest.location_id || null,
      location_title: root.location_title || latest.location_title || "",
      location_emoji: root.location_emoji || latest.location_emoji || "",
      renewals_count: rows.filter(row => String(row.order_type) === "renewal").length,
      volume_orders_count: rows.filter(row => String(row.order_type) === "volume").length,
      operations_count: rows.length,
      created_at: root.created_at,
      updated_at: latest.updated_at
    });
  }
  return services.sort((a, b) => Date.parse(b.updated_at || 0) - Date.parse(a.updated_at || 0));
}

async function getSalesServiceOrder(env, bot, customer, serviceId) {
  const row = await env.PASARGUARD_DB.prepare(`
    SELECT o.*,p.title AS plan_title,p.category_id,p.location_id,
           c.title AS category_title,c.emoji AS category_emoji,
           l.title AS location_title,l.emoji AS location_emoji
    FROM sales_orders o
    JOIN sales_plans p ON p.id=o.plan_id
    LEFT JOIN sales_categories c ON c.id=p.category_id
    LEFT JOIN sales_locations l ON l.id=p.location_id
    WHERE o.id=? AND o.bot_id=? AND o.customer_id=? AND o.status='delivered' AND o.remote_username IS NOT NULL
      AND COALESCE(o.remote_status,'') NOT IN ('deleted','removed','remote_missing')
  `).bind(serviceId, bot.id, customer.id).first();
  if (!row) throw new Error("ШіШұЩҲЫҢШі Ш§ЩҶШӘШ®Ш§ШЁвҖҢШҙШҜЩҮ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  return row;
}

async function syncSalesService(env, bot, customer, serviceId) {
  const target = await getSalesServiceOrder(env, bot, customer, serviceId);
  const provider=normalizeServiceProvider(target.service_provider);
  if(provider==="pasarguard"&&bot.agency_status!=="active") throw new Error("ЩҫЩҶЩ„ PasarGuard Щ…ШӘШөЩ„ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ЩҒШ№Ш§Щ„ ЩҶЫҢШіШӘ");
  if(provider==="marzban"&&!sharedMarzbanEnabled(await getSettings(env),env)) throw new Error("Щ…ШұШІШЁШ§ЩҶ Щ…ШҙШӘШұЪ© Щ…ШұЪ©ШІЫҢ ЩҒШ№Ш§Щ„ ЩҶЫҢШіШӘ");
  const agency = { id: bot.agency_id, panel_username: bot.panel_username, panel_password_enc: bot.panel_password_enc };
  const remote = await servicePanelRequestForProvider(env, agency, provider, "GET", "/api/user/" + encodeURIComponent(target.remote_username));
  const snapshot = salesRemoteSnapshot(remote, target);
  let subscriptionUrl = snapshot.subscriptionUrl;
  if (subscriptionUrl && subscriptionUrl.startsWith("/")) {
    const settings = await getSettings(env);
    subscriptionUrl = serviceBaseUrlForProvider(settings, env, provider) + subscriptionUrl;
  }
  await env.PASARGUARD_DB.prepare(`
    UPDATE sales_orders SET subscription_url=CASE WHEN ?<>'' THEN ? ELSE subscription_url END,
      remote_status=?,remote_data_limit=?,remote_used_traffic=?,remote_expire=?,remote_online_at=?,remote_last_synced_at=?,updated_at=updated_at
    WHERE bot_id=? AND customer_id=? AND remote_username=? AND service_provider=? AND status='delivered'
  `).bind(subscriptionUrl, subscriptionUrl, snapshot.status, snapshot.dataLimit, snapshot.usedTraffic,
    snapshot.expire, snapshot.onlineAt, snapshot.syncedAt, bot.id, customer.id, target.remote_username, provider).run();
  await salesEvent(env, bot.id, customer.id, "service_synced", { serviceId: target.id, username: target.remote_username });
  return {
    id: target.id,
    remote_username: target.remote_username,
    subscription_url: subscriptionUrl || target.subscription_url || "",
    remote_status: snapshot.status,
    remote_data_limit: snapshot.dataLimit,
    remote_used_traffic: snapshot.usedTraffic,
    remote_expire: snapshot.expire,
    remote_online_at: snapshot.onlineAt,
    remote_last_synced_at: snapshot.syncedAt
  };
}

async function revokeSalesServiceSubscription(env, bot, customer, serviceId) {
  const target = await getSalesServiceOrder(env, bot, customer, serviceId);
  const provider=normalizeServiceProvider(target.service_provider);
  if(provider==="pasarguard"&&bot.agency_status!=="active") throw new Error("ЩҫЩҶЩ„ PasarGuard Щ…ШӘШөЩ„ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ЩҒШ№Ш§Щ„ ЩҶЫҢШіШӘ");
  if(provider==="marzban"&&!sharedMarzbanEnabled(await getSettings(env),env)) throw new Error("Щ…ШұШІШЁШ§ЩҶ Щ…ШҙШӘШұЪ© Щ…ШұЪ©ШІЫҢ ЩҒШ№Ш§Щ„ ЩҶЫҢШіШӘ");
  const agency = { id: bot.agency_id, panel_username: bot.panel_username, panel_password_enc: bot.panel_password_enc };
  let changed = await servicePanelRequestForProvider(env, agency, provider, "POST", "/api/user/" + encodeURIComponent(target.remote_username) + "/revoke_sub");
  if (!changed?.subscription_url && !changed?.data?.subscription_url) {
    changed = await servicePanelRequestForProvider(env, agency, provider, "GET", "/api/user/" + encodeURIComponent(target.remote_username));
  }
  const snapshot = salesRemoteSnapshot(changed, target);
  let subscriptionUrl = snapshot.subscriptionUrl;
  if (!subscriptionUrl) throw new Error("Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© Ш¬ШҜЫҢШҜ Ш§ШІ ЩҫЩҶЩ„ ШҜШұЫҢШ§ЩҒШӘ ЩҶШҙШҜ");
  if (subscriptionUrl.startsWith("/")) {
    const settings = await getSettings(env);
    subscriptionUrl = serviceBaseUrlForProvider(settings, env, provider) + subscriptionUrl;
  }
  await env.PASARGUARD_DB.prepare(`
    UPDATE sales_orders SET subscription_url=?,remote_status=?,remote_data_limit=?,remote_used_traffic=?,
      remote_expire=?,remote_online_at=?,remote_last_synced_at=?
    WHERE bot_id=? AND customer_id=? AND remote_username=? AND service_provider=? AND status='delivered'
  `).bind(subscriptionUrl, snapshot.status, snapshot.dataLimit, snapshot.usedTraffic, snapshot.expire,
    snapshot.onlineAt, snapshot.syncedAt, bot.id, customer.id, target.remote_username, provider).run();
  await salesEvent(env, bot.id, customer.id, "service_subscription_revoked", { serviceId: target.id, username: target.remote_username });
  return { ...snapshot, id: target.id, remote_username: target.remote_username, subscription_url: subscriptionUrl,
    remote_status: snapshot.status, remote_data_limit: snapshot.dataLimit, remote_used_traffic: snapshot.usedTraffic,
    remote_expire: snapshot.expire, remote_online_at: snapshot.onlineAt, remote_last_synced_at: snapshot.syncedAt };
}

async function salesSessionGet(env, botId, telegramId) {
  const row = await env.PASARGUARD_DB.prepare(`
    SELECT state,data,updated_at FROM reseller_bot_sessions WHERE bot_id=? AND telegram_id=?
  `).bind(botId, String(telegramId)).first();
  if (!row) return null;
  if (Date.now() - new Date(row.updated_at).getTime() > 60 * 60 * 1000) {
    await salesSessionClear(env, botId, telegramId);
    return null;
  }
  let data = {};
  try { data = JSON.parse(row.data || "{}"); } catch (_) {}
  return { state: row.state, data };
}

async function salesSessionSet(env, botId, telegramId, state, data = {}) {
  await env.PASARGUARD_DB.prepare(`
    INSERT INTO reseller_bot_sessions(bot_id,telegram_id,state,data,updated_at) VALUES(?,?,?,?,?)
    ON CONFLICT(bot_id,telegram_id) DO UPDATE SET state=excluded.state,data=excluded.data,updated_at=excluded.updated_at
  `).bind(botId, String(telegramId), state, JSON.stringify(data || {}), nowIso()).run();
}

async function salesSessionClear(env, botId, telegramId) {
  await env.PASARGUARD_DB.prepare("DELETE FROM reseller_bot_sessions WHERE bot_id=? AND telegram_id=?")
    .bind(botId, String(telegramId)).run();
}

function salesReferralCode() {
  return crypto.randomUUID().replace(/-/g, "").slice(0, 10).toUpperCase();
}

async function salesBotText(env, botId, key, fallback = "") {
  const row = await env.PASARGUARD_DB.prepare("SELECT text_value FROM reseller_bot_texts WHERE bot_id=? AND text_key=?")
    .bind(botId, key).first();
  return cleanText(row?.text_value, 3500) || fallback;
}

function normalizeSalesPromoCode(value) {
  return String(value || "").trim().toUpperCase().replace(/[^A-Z0-9_-]/g, "").slice(0, 32);
}

function salesPromoExpired(promo) {
  if (!promo?.expires_at) return false;
  const time = Date.parse(String(promo.expires_at));
  return Number.isFinite(time) && time <= Date.now();
}

function salesPromoPublic(promo, discountToman = 0) {
  if (!promo) return null;
  return {
    id: promo.id,
    code: promo.code,
    kind: promo.kind,
    value_type: promo.value_type,
    value: Number(promo.value || 0),
    min_purchase_toman: Number(promo.min_purchase_toman || 0),
    max_uses: Number(promo.max_uses || 0),
    per_user_limit: Number(promo.per_user_limit || 1),
    use_count: Number(promo.use_count || 0),
    expires_at: promo.expires_at || null,
    description: cleanText(promo.description, 300),
    discount_toman: Number(discountToman || 0)
  };
}

async function salesPromoCustomerUsage(env, promoId, customerId) {
  const row = await env.PASARGUARD_DB.prepare(`
    SELECT COUNT(*) AS c FROM sales_promo_redemptions
    WHERE promo_id=? AND customer_id=? AND status IN ('reserved','used')
  `).bind(promoId, customerId).first();
  return Number(row?.c || 0);
}

async function salesPromoFind(env, botId, codeOrId) {
  const raw = cleanText(codeOrId, 80);
  if (!raw) return null;
  const code = normalizeSalesPromoCode(raw);
  return env.PASARGUARD_DB.prepare(`
    SELECT * FROM sales_promo_codes WHERE bot_id=? AND (id=? OR code=?) LIMIT 1
  `).bind(botId, raw, code).first();
}

async function salesActivePromoForCustomer(env, botId, customer) {
  const promoId = cleanText(customer?.active_promo_code_id, 80);
  if (!promoId) return null;
  const promo = await salesPromoFind(env, botId, promoId);
  let valid = !!promo && promo.kind === "discount" && promo.status === "active" && !salesPromoExpired(promo);
  if (valid && Number(promo.max_uses || 0) > 0 && Number(promo.use_count || 0) >= Number(promo.max_uses || 0)) valid = false;
  if (valid) {
    const used = await salesPromoCustomerUsage(env, promo.id, customer.id);
    if (used >= Math.max(1, Number(promo.per_user_limit || 1))) valid = false;
  }
  if (!valid) {
    await env.PASARGUARD_DB.prepare("UPDATE sales_customers SET active_promo_code_id=NULL,updated_at=? WHERE id=? AND bot_id=?")
      .bind(nowIso(), customer.id, botId).run();
    return null;
  }
  return promo;
}

function salesPromoDiscountForAmount(promo, amount) {
  const base = Math.max(0, Number(amount || 0));
  if (!promo || promo.kind !== "discount" || base <= 0) return 0;
  const raw = promo.value_type === "percent"
    ? Math.floor(base * Math.max(0, Math.min(100, Number(promo.value || 0))) / 100)
    : Math.max(0, Number(promo.value || 0));
  // Keep a minimum payable amount to avoid accidental zero-value card orders.
  return Math.max(0, Math.min(Math.max(0, base - 1000), raw));
}

async function salesValidateDiscountPromo(env, bot, customer, codeOrId, purchaseAmount) {
  const promo = await salesPromoFind(env, bot.id, codeOrId);
  if (!promo || promo.kind !== "discount") throw new Error("Ъ©ШҜ ШӘШ®ЩҒЫҢЩҒ Щ…Ш№ШӘШЁШұ ЩҶЫҢШіШӘ");
  if (promo.status !== "active") throw new Error("Ш§ЫҢЩҶ Ъ©ШҜ ШәЫҢШұЩҒШ№Ш§Щ„ Ш§ШіШӘ");
  if (salesPromoExpired(promo)) throw new Error("Щ…ЩҮЩ„ШӘ Ш§ШіШӘЩҒШ§ШҜЩҮ Ш§ШІ Ш§ЫҢЩҶ Ъ©ШҜ ШӘЩ…Ш§Щ… ШҙШҜЩҮ Ш§ШіШӘ");
  if (Number(promo.max_uses || 0) > 0 && Number(promo.use_count || 0) >= Number(promo.max_uses || 0)) throw new Error("ШёШұЩҒЫҢШӘ Ш§ШіШӘЩҒШ§ШҜЩҮ Ш§ШІ Ш§ЫҢЩҶ Ъ©ШҜ ШӘЪ©Щ…ЫҢЩ„ ШҙШҜЩҮ Ш§ШіШӘ");
  const customerUsage = await salesPromoCustomerUsage(env, promo.id, customer.id);
  if (customerUsage >= Math.max(1, Number(promo.per_user_limit || 1))) throw new Error("ШіЩӮЩҒ Ш§ШіШӘЩҒШ§ШҜЩҮ ШҙЩ…Ш§ Ш§ШІ Ш§ЫҢЩҶ Ъ©ШҜ ШӘЪ©Щ…ЫҢЩ„ ШҙШҜЩҮ Ш§ШіШӘ");
  const base = Math.max(0, Number(purchaseAmount || 0));
  if (base < Number(promo.min_purchase_toman || 0)) throw new Error("ШӯШҜШ§ЩӮЩ„ Ш®ШұЫҢШҜ ШЁШұШ§ЫҢ Ш§ЫҢЩҶ Ъ©ШҜ " + botMoney(promo.min_purchase_toman) + " ШӘЩҲЩ…Ш§ЩҶ Ш§ШіШӘ");
  const discount = salesPromoDiscountForAmount(promo, base);
  if (discount <= 0) throw new Error("Ш§ЫҢЩҶ Ъ©ШҜ ШЁШұШ§ЫҢ Щ…ШЁЩ„Шә Ш§ЩҶШӘШ®Ш§ШЁвҖҢШҙШҜЩҮ ШӘШ®ЩҒЫҢЩҒЫҢ Ш§ЫҢШ¬Ш§ШҜ ЩҶЩ…ЫҢвҖҢЪ©ЩҶШҜ");
  return { promo, discount, finalAmount: base - discount };
}

async function salesActivatePromoCode(env, bot, customer, rawCode) {
  const code = normalizeSalesPromoCode(rawCode);
  if (!code) throw new Error("Ъ©ШҜ ШұШ§ ШЁЩҮвҖҢШҜШұШіШӘЫҢ ЩҲШ§ШұШҜ Ъ©ЩҶЫҢШҜ");
  const promo = await salesPromoFind(env, bot.id, code);
  if (!promo || promo.status !== "active") throw new Error("Ъ©ШҜ ЩҲШ§ШұШҜШҙШҜЩҮ Щ…Ш№ШӘШЁШұ ЫҢШ§ ЩҒШ№Ш§Щ„ ЩҶЫҢШіШӘ");
  if (salesPromoExpired(promo)) throw new Error("Щ…ЩҮЩ„ШӘ Ш§ШіШӘЩҒШ§ШҜЩҮ Ш§ШІ Ш§ЫҢЩҶ Ъ©ШҜ ШӘЩ…Ш§Щ… ШҙШҜЩҮ Ш§ШіШӘ");
  if (Number(promo.max_uses || 0) > 0 && Number(promo.use_count || 0) >= Number(promo.max_uses || 0)) throw new Error("ШёШұЩҒЫҢШӘ Ш§ШіШӘЩҒШ§ШҜЩҮ Ш§ШІ Ш§ЫҢЩҶ Ъ©ШҜ ШӘЪ©Щ…ЫҢЩ„ ШҙШҜЩҮ Ш§ШіШӘ");
  const usage = await salesPromoCustomerUsage(env, promo.id, customer.id);
  if (usage >= Math.max(1, Number(promo.per_user_limit || 1))) throw new Error("ЩӮШЁЩ„Ш§ЩӢ Ш§ШІ Ш§ЫҢЩҶ Ъ©ШҜ ШЁЩҮ ШӘШ№ШҜШ§ШҜ Щ…Ш¬Ш§ШІ Ш§ШіШӘЩҒШ§ШҜЩҮ Ъ©ШұШҜЩҮвҖҢШ§ЫҢШҜ");

  if (promo.kind === "gift") {
    const credit = Math.max(1000, Number(promo.value || 0));
    const claimed = await env.PASARGUARD_DB.prepare(`
      UPDATE sales_promo_codes SET use_count=use_count+1,updated_at=?
      WHERE id=? AND bot_id=? AND status='active' AND kind='gift'
        AND (max_uses=0 OR use_count<max_uses)
    `).bind(nowIso(), promo.id, bot.id).run();
    if (!Number(claimed?.meta?.changes || 0)) throw new Error("ШёШұЩҒЫҢШӘ Ш§ШіШӘЩҒШ§ШҜЩҮ Ш§ШІ Ш§ЫҢЩҶ Ъ©ШҜ ШӘЪ©Щ…ЫҢЩ„ ШҙШҜЩҮ Ш§ШіШӘ");
    const redemptionId = id("pred");
    try {
      await env.PASARGUARD_DB.prepare(`
        INSERT INTO sales_promo_redemptions(id,bot_id,promo_id,customer_id,order_id,status,amount_toman,created_at,updated_at)
        VALUES(?,?,?,?,NULL,'used',?,?,?)
      `).bind(redemptionId, bot.id, promo.id, customer.id, credit, nowIso(), nowIso()).run();
      const balance = await adjustSalesCustomerBalance(env, bot.id, customer.id, credit, "gift_code", "promo_code", promo.id, "Ш§Ш№ШӘШЁШ§Шұ ЩҮШҜЫҢЩҮ Ъ©ШҜ " + promo.code);
      await salesEvent(env, bot.id, customer.id, "gift_code_redeemed", { promoId: promo.id, code: promo.code, credit });
      return { kind: "gift", promo: salesPromoPublic(promo), credit, wallet_balance: balance };
    } catch (error) {
      try { await env.PASARGUARD_DB.prepare("DELETE FROM sales_promo_redemptions WHERE id=?").bind(redemptionId).run(); } catch (_) {}
      try { await env.PASARGUARD_DB.prepare("UPDATE sales_promo_codes SET use_count=MAX(0,use_count-1),updated_at=? WHERE id=?").bind(nowIso(), promo.id).run(); } catch (_) {}
      throw error;
    }
  }

  await env.PASARGUARD_DB.prepare("UPDATE sales_customers SET active_promo_code_id=?,updated_at=? WHERE id=? AND bot_id=?")
    .bind(promo.id, nowIso(), customer.id, bot.id).run();
  await salesEvent(env, bot.id, customer.id, "discount_code_activated", { promoId: promo.id, code: promo.code });
  return { kind: "discount", promo: salesPromoPublic(promo) };
}

async function salesReservePromoForOrder(env, bot, customer, promoRef, baseAmount, orderId) {
  if (!promoRef) return null;
  const checked = await salesValidateDiscountPromo(env, bot, customer, promoRef, baseAmount);
  const claimed = await env.PASARGUARD_DB.prepare(`
    UPDATE sales_promo_codes SET use_count=use_count+1,updated_at=?
    WHERE id=? AND bot_id=? AND status='active' AND kind='discount'
      AND (max_uses=0 OR use_count<max_uses)
  `).bind(nowIso(), checked.promo.id, bot.id).run();
  if (!Number(claimed?.meta?.changes || 0)) throw new Error("ШёШұЩҒЫҢШӘ Ш§ШіШӘЩҒШ§ШҜЩҮ Ш§ШІ Ш§ЫҢЩҶ Ъ©ШҜ ШӘЪ©Щ…ЫҢЩ„ ШҙШҜЩҮ Ш§ШіШӘ");
  try {
    await env.PASARGUARD_DB.prepare(`
      INSERT INTO sales_promo_redemptions(id,bot_id,promo_id,customer_id,order_id,status,amount_toman,created_at,updated_at)
      VALUES(?,?,?,?,?,'reserved',?,?,?)
    `).bind(id("pred"), bot.id, checked.promo.id, customer.id, orderId, checked.discount, nowIso(), nowIso()).run();
    await env.PASARGUARD_DB.prepare("UPDATE sales_customers SET active_promo_code_id=NULL,updated_at=? WHERE id=? AND bot_id=?")
      .bind(nowIso(), customer.id, bot.id).run();
    return checked;
  } catch (error) {
    try { await env.PASARGUARD_DB.prepare("UPDATE sales_promo_codes SET use_count=MAX(0,use_count-1),updated_at=? WHERE id=?").bind(nowIso(), checked.promo.id).run(); } catch (_) {}
    throw error;
  }
}

async function salesReleasePromoForOrder(env, orderId) {
  const redemption = await env.PASARGUARD_DB.prepare(`
    SELECT * FROM sales_promo_redemptions WHERE order_id=? AND status='reserved'
  `).bind(orderId).first();
  if (!redemption) return false;
  const changed = await env.PASARGUARD_DB.prepare("UPDATE sales_promo_redemptions SET status='released',updated_at=? WHERE id=? AND status='reserved'")
    .bind(nowIso(), redemption.id).run();
  if (Number(changed?.meta?.changes || 0)) {
    await env.PASARGUARD_DB.prepare("UPDATE sales_promo_codes SET use_count=MAX(0,use_count-1),updated_at=? WHERE id=?")
      .bind(nowIso(), redemption.promo_id).run();
    return true;
  }
  return false;
}

async function salesFinalizePromoForOrder(env, orderId) {
  await env.PASARGUARD_DB.prepare("UPDATE sales_promo_redemptions SET status='used',updated_at=? WHERE order_id=? AND status='reserved'")
    .bind(nowIso(), orderId).run();
}

async function salesEvent(env, botId, customerId, eventType, details = {}) {
  try {
    await env.PASARGUARD_DB.prepare(`
      INSERT INTO sales_bot_events(id,bot_id,customer_id,event_type,details,created_at) VALUES(?,?,?,?,?,?)
    `).bind(id("evt"), botId, customerId || null, eventType, JSON.stringify(details || {}), nowIso()).run();
  } catch (_) {}
}

function salesMiniAppUrl(bot, settingsOrOrigin) {
  let origin = "";
  try {
    if (typeof settingsOrOrigin === "string") origin = new URL(settingsOrOrigin).origin;
    else origin = new URL(String(settingsOrOrigin?.app_url || "")).origin;
  } catch (_) {}
  return origin ? origin + "/sales-app/" + encodeURIComponent(bot.id) : "";
}

function salesQrUrl(value) {
  return "https://api.qrserver.com/v1/create-qr-code/?size=420x420&margin=18&data=" + encodeURIComponent(String(value || ""));
}

function parseStartPayload(text) {
  const match = String(text || "").trim().match(/^\/start(?:@\w+)?(?:\s+([^\s]+))?/i);
  return match?.[1] || "";
}

async function ensureSalesCustomer(env, bot, from, startPayload = "") {
  const telegramId = String(from?.id || "");
  if (!telegramId) throw new Error("ШҙЩҶШ§ШіЩҮ Щ…ШҙШӘШұЫҢ ШҜШұЫҢШ§ЩҒШӘ ЩҶШҙШҜ");
  const ts = nowIso();
  const customerBatch = await env.PASARGUARD_DB.batch([
    env.PASARGUARD_DB.prepare(`
      INSERT INTO sales_customers(id,bot_id,telegram_id,username,first_name,last_name,created_at,updated_at,last_seen_at)
      VALUES(?,?,?,?,?,?,?,?,?)
      ON CONFLICT(bot_id,telegram_id) DO UPDATE SET
        username=excluded.username,first_name=excluded.first_name,last_name=excluded.last_name,
        updated_at=excluded.updated_at,last_seen_at=excluded.last_seen_at
    `).bind(
      id("cus"), bot.id, telegramId, cleanText(from?.username, 64), cleanText(from?.first_name, 100),
      cleanText(from?.last_name, 100), ts, ts, ts
    ),
    env.PASARGUARD_DB.prepare("SELECT * FROM sales_customers WHERE bot_id=? AND telegram_id=?")
      .bind(bot.id, telegramId)
  ]);
  let customer = (customerBatch[1]?.results || [])[0] || null;
  if (!customer) throw new Error("ШӯШіШ§ШЁ Щ…ШҙШӘШұЫҢ ШіШ§Ш®ШӘЩҮ ЩҶШҙШҜ");
  if (!customer.referral_code) {
    for (let attempt = 0; attempt < 5; attempt++) {
      const code = salesReferralCode();
      try {
        await env.PASARGUARD_DB.prepare("UPDATE sales_customers SET referral_code=?,updated_at=? WHERE id=? AND referral_code IS NULL")
          .bind(code, ts, customer.id).run();
        break;
      } catch (_) {}
    }
    customer = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_customers WHERE id=?").bind(customer.id).first();
  }
  const referralCode = String(startPayload || "").replace(/^ref_/i, "").trim().toUpperCase();
  if (referralCode && !customer.referrer_customer_id && referralCode !== String(customer.referral_code || "").toUpperCase()) {
    const referrer = await env.PASARGUARD_DB.prepare("SELECT id FROM sales_customers WHERE bot_id=? AND UPPER(referral_code)=UPPER(?)")
      .bind(bot.id, referralCode).first();
    if (referrer && referrer.id !== customer.id) {
      await env.PASARGUARD_DB.prepare("UPDATE sales_customers SET referrer_customer_id=?,updated_at=? WHERE id=? AND referrer_customer_id IS NULL")
        .bind(referrer.id, ts, customer.id).run();
      customer.referrer_customer_id = referrer.id;
      await salesEvent(env, bot.id, customer.id, "referral_joined", { referrerCustomerId: referrer.id });
    }
  }
  if (String(customer.status || "active") !== "active") throw new Error("ШӯШіШ§ШЁ ШҙЩ…Ш§ ШҜШұ Ш§ЫҢЩҶ ШұШЁШ§ШӘ ШәЫҢШұЩҒШ№Ш§Щ„ ШҙШҜЩҮ Ш§ШіШӘ");
  if (String(customer.created_at || "") === ts) {
    await queueReportEvent(env, bot.id, "customers", "Ъ©Ш§ШұШЁШұ Ш¬ШҜЫҢШҜ ЩҲШ§ШұШҜ ШұШЁШ§ШӘ ШҙШҜ",
      "ЩҶШ§Щ…: <b>" + botEscape(customer.first_name || customer.username || customer.telegram_id) + "</b>\n" +
      "ШӘЩ„ЪҜШұШ§Щ…: <code>" + botEscape(customer.telegram_id) + "</code>" +
      (customer.username ? "\nЩҶШ§Щ… Ъ©Ш§ШұШЁШұЫҢ: @" + botEscape(customer.username) : ""),
      "customer-created:" + customer.id);
  }
  return customer;
}

function salesSupportUrl(bot) {
  const raw = String(bot.support_username || "").trim();
  if (!raw) return "";
  if (/^https:\/\//i.test(raw)) return raw;
  return "https://t.me/" + raw.replace(/^@/, "");
}

function normalizeSalesPhone(value) {
  let raw = String(value || "").trim().replace(/[\s\-()]/g, "");
  if (raw.startsWith("00")) raw = "+" + raw.slice(2);
  const plus = raw.startsWith("+") ? "+" : "";
  const digits = raw.replace(/\D/g, "");
  if (digits.length < 8 || digits.length > 15) return "";
  return plus + digits;
}

function salesPhoneVerified(customer) {
  return Boolean(normalizeSalesPhone(customer?.phone_number) && customer?.phone_verified_at);
}

function salesRequireVerifiedPhone(bot, customer) {
  if (Number(bot?.phone_verification_required || 0) !== 1 || salesPhoneVerified(customer)) return;
  const error = new Error("ШЁШұШ§ЫҢ Ш§ШҜШ§Щ…ЩҮШҢ ШҙЩ…Ш§ШұЩҮ Щ…ЩҲШЁШ§ЫҢЩ„ Ш®ЩҲШҜ ШұШ§ Ш§ШІ Ш·ШұЫҢЩӮ ШҜЪ©Щ…ЩҮ ШӘШЈЫҢЫҢШҜ ШҙЩ…Ш§ШұЩҮ ШҜШұ Щ…ЫҢЩҶЫҢвҖҢШ§Щҫ Ш§ШұШіШ§Щ„ Ъ©ЩҶЫҢШҜ.");
  error.code = "PHONE_REQUIRED";
  throw error;
}

async function sendSalesPhoneVerificationPrompt(env, bot, chatId) {
  return resellerTelegramApi(env, bot, "sendMessage", {
    chat_id: chatId,
    text: "рҹ“ұ <b>ШӘШЈЫҢЫҢШҜ ШҙЩ…Ш§ШұЩҮ Щ…ЩҲШЁШ§ЫҢЩ„</b>\nШЁШұШ§ЫҢ Ш§ШҜШ§Щ…ЩҮ Ш®ШұЫҢШҜ ЩҲ Ш§ШіШӘЩҒШ§ШҜЩҮ Ш§ШІ Ш®ШҜЩ…Ш§ШӘШҢ ШҙЩ…Ш§ШұЩҮ Щ…ШӘШ№Щ„ЩӮ ШЁЩҮ ЩҮЩ…ЫҢЩҶ ШӯШіШ§ШЁ ШӘЩ„ЪҜШұШ§Щ… ШұШ§ Ш§ШұШіШ§Щ„ Ъ©ЩҶЫҢШҜ.",
    parse_mode: "HTML",
    reply_markup: {
      keyboard: [[{ text: "рҹ“ұ Ш§ШұШіШ§Щ„ ЩҲ ШӘШЈЫҢЫҢШҜ ШҙЩ…Ш§ШұЩҮ Щ…ЩҶ", request_contact: true }]],
      resize_keyboard: true,
      one_time_keyboard: true,
      input_field_placeholder: "ШҜЪ©Щ…ЩҮ Ш§ШұШіШ§Щ„ ШҙЩ…Ш§ШұЩҮ ШұШ§ ШЁШІЩҶЫҢШҜ"
    }
  });
}

function salesTicketPublicCode(ticketId) {
  const compact = String(ticketId || "").replace(/[^a-zA-Z0-9]/g, "").toUpperCase();
  return "T-" + compact.slice(-8).padStart(8, "0");
}

function salesTicketCategoryLabel(value) {
  return ({ technical: "ЩҒЩҶЫҢ", sales: "Ш®ШұЫҢШҜ ЩҲ ЩҒШұЩҲШҙ", financial: "Щ…Ш§Щ„ЫҢ", account: "ШӯШіШ§ШЁ Ъ©Ш§ШұШЁШұЫҢ", other: "ШіШ§ЫҢШұ" })[String(value || "")] || "ШіШ§ЫҢШұ";
}

function salesTicketPriorityLabel(value) {
  return ({ low: "Ъ©Щ…", normal: "Ш№Ш§ШҜЫҢ", high: "Щ…ЩҮЩ…", urgent: "ЩҒЩҲШұЫҢ" })[String(value || "")] || "Ш№Ш§ШҜЫҢ";
}

function salesTicketStatusLabel(value) {
  return ({ waiting_owner: "ШҜШұ Ш§ЩҶШӘШёШ§Шұ ЩҫШ§ШіШ® ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ", answered: "ЩҫШ§ШіШ® ШҜШ§ШҜЩҮвҖҢШҙШҜЩҮ", closed: "ШЁШіШӘЩҮвҖҢШҙШҜЩҮ" })[String(value || "")] || String(value || "ЩҶШ§Щ…ШҙШ®Шө");
}

async function salesTicketDetailForCustomer(env, bot, customer, ticketId) {
  const ticket = await env.PASARGUARD_DB.prepare(`
    SELECT * FROM sales_tickets WHERE id=? AND bot_id=? AND customer_id=?
  `).bind(ticketId, bot.id, customer.id).first();
  if (!ticket) throw new Error("ШӘЫҢЪ©ШӘ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  const messages = await env.PASARGUARD_DB.prepare(`
    SELECT id,sender_type,message_text,created_at
    FROM sales_ticket_messages WHERE ticket_id=? AND bot_id=? ORDER BY created_at ASC LIMIT 200
  `).bind(ticket.id, bot.id).all();
  return { ticket, messages: messages.results || [] };
}

async function notifyResellerOwnerTicket(env, bot, ticket, customer, title = "ШӘЫҢЪ©ШӘ Ш¬ШҜЫҢШҜ") {
  if (!bot?.owner_telegram_id) return false;
  const text =
    "рҹҺ« <b>" + botEscape(title) + "</b>\n" +
    "в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n" +
    "ШҙЩ…Ш§ШұЩҮ: <code>" + botEscape(ticket.public_code) + "</code>\n" +
    "Ъ©Ш§ШұШЁШұ: <b>" + botEscape(customer.first_name || customer.username || customer.telegram_id) + "</b>\n" +
    "ШҜШіШӘЩҮ: <b>" + botEscape(salesTicketCategoryLabel(ticket.category)) + "</b>\n" +
    "Ш§ЩҲЩ„ЩҲЫҢШӘ: <b>" + botEscape(salesTicketPriorityLabel(ticket.priority)) + "</b>\n" +
    "Щ…ЩҲШ¶ЩҲШ№: <b>" + botEscape(ticket.subject) + "</b>";
  try {
    await resellerTelegramApi(env, bot, "sendMessage", {
      chat_id: bot.owner_telegram_id,
      text,
      parse_mode: "HTML",
      reply_markup: { inline_keyboard: [[{ text: "рҹ’¬ Щ…ШҙШ§ЩҮШҜЩҮ ЩҲ ЩҫШ§ШіШ®", callback_data: "owner:ticket:" + ticket.id }]] }
    });
    return true;
  } catch (_) {
    return false;
  }
}

async function createSalesTicket(env, bot, customer, input = {}) {
  if (Number(bot.ticketing_enabled ?? 1) !== 1) throw new Error("Щ…ШұЪ©ШІ ШӘЫҢЪ©ШӘ Ш§ЫҢЩҶ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ШәЫҢШұЩҒШ№Ш§Щ„ Ш§ШіШӘ");
  salesRequireVerifiedPhone(bot, customer);
  const category = ["technical", "sales", "financial", "account", "other"].includes(String(input.category)) ? String(input.category) : "other";
  const priority = ["low", "normal", "high", "urgent"].includes(String(input.priority)) ? String(input.priority) : "normal";
  const subject = cleanText(input.subject, 140);
  const message = cleanText(input.message, 3000);
  if (subject.length < 3) throw new Error("Щ…ЩҲШ¶ЩҲШ№ ШӘЫҢЪ©ШӘ ШЁШ§ЫҢШҜ ШӯШҜШ§ЩӮЩ„ Ыі Ъ©Ш§ШұШ§Ъ©ШӘШұ ШЁШ§ШҙШҜ");
  if (message.length < 5) throw new Error("Щ…ШӘЩҶ ШӘЫҢЪ©ШӘ ШЁШ§ЫҢШҜ ШӯШҜШ§ЩӮЩ„ Ыө Ъ©Ш§ШұШ§Ъ©ШӘШұ ШЁШ§ШҙШҜ");
  const ts = nowIso();
  const ticketId = id("tkt");
  const publicCode = salesTicketPublicCode(ticketId);
  const messageId = id("tmsg");
  await env.PASARGUARD_DB.batch([
    env.PASARGUARD_DB.prepare(`
      INSERT INTO sales_tickets(
        id,bot_id,customer_id,public_code,category,priority,subject,status,origin,last_message_at,created_at,updated_at
      ) VALUES(?,?,?,?,?,?,?,'waiting_owner','miniapp',?,?,?)
    `).bind(ticketId, bot.id, customer.id, publicCode, category, priority, subject, ts, ts, ts),
    env.PASARGUARD_DB.prepare(`
      INSERT INTO sales_ticket_messages(id,ticket_id,bot_id,sender_type,sender_id,message_text,created_at)
      VALUES(?,?,?,'customer',?,?,?)
    `).bind(messageId, ticketId, bot.id, customer.id, message, ts)
  ]);
  const ticket = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_tickets WHERE id=?").bind(ticketId).first();
  await salesEvent(env, bot.id, customer.id, "ticket_created", { ticketId, publicCode, category, priority });
  await queueReportEvent(env, bot.id, "support", "ШӘЫҢЪ©ШӘ Ш¬ШҜЫҢШҜ",
    "ШҙЩ…Ш§ШұЩҮ: <code>" + botEscape(publicCode) + "</code>\n" +
    "Щ…ШҙШӘШұЫҢ: <b>" + botEscape(customer.first_name || customer.username || customer.telegram_id) + "</b>\n" +
    "Щ…ЩҲШ¶ЩҲШ№: <b>" + botEscape(subject) + "</b>\n" +
    "Ш§ЩҲЩ„ЩҲЫҢШӘ: <b>" + botEscape(priority) + "</b>",
    "ticket-created:" + ticketId);
  await notifyResellerOwnerTicket(env, bot, ticket, customer, "ШӘЫҢЪ©ШӘ Ш¬ШҜЫҢШҜ");
  return ticket;
}

async function replySalesTicketByCustomer(env, bot, customer, ticketId, rawMessage) {
  if (Number(bot.ticketing_enabled ?? 1) !== 1) throw new Error("Щ…ШұЪ©ШІ ШӘЫҢЪ©ШӘ Ш§ЫҢЩҶ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ШәЫҢШұЩҒШ№Ш§Щ„ Ш§ШіШӘ");
  salesRequireVerifiedPhone(bot, customer);
  const ticket = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_tickets WHERE id=? AND bot_id=? AND customer_id=?")
    .bind(ticketId, bot.id, customer.id).first();
  if (!ticket) throw new Error("ШӘЫҢЪ©ШӘ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  if (ticket.status === "closed") throw new Error("Ш§ЫҢЩҶ ШӘЫҢЪ©ШӘ ШЁШіШӘЩҮ ШҙШҜЩҮ Ш§ШіШӘ");
  const message = cleanText(rawMessage, 3000);
  if (message.length < 2) throw new Error("Щ…ШӘЩҶ ЩҫШ§ШіШ® Ъ©ЩҲШӘШ§ЩҮ Ш§ШіШӘ");
  const ts = nowIso();
  const messageId = id("tmsg");
  await env.PASARGUARD_DB.batch([
    env.PASARGUARD_DB.prepare(`
      INSERT INTO sales_ticket_messages(id,ticket_id,bot_id,sender_type,sender_id,message_text,created_at)
      VALUES(?,?,?,'customer',?,?,?)
    `).bind(messageId, ticket.id, bot.id, customer.id, message, ts),
    env.PASARGUARD_DB.prepare("UPDATE sales_tickets SET status='waiting_owner',last_message_at=?,updated_at=? WHERE id=?")
      .bind(ts, ts, ticket.id)
  ]);
  const fresh = { ...ticket, status: "waiting_owner", last_message_at: ts, updated_at: ts };
  await salesEvent(env, bot.id, customer.id, "ticket_customer_reply", { ticketId: ticket.id, messageId });
  await notifyResellerOwnerTicket(env, bot, fresh, customer, "ЩҫШ§ШіШ® Ш¬ШҜЫҢШҜ Щ…ШҙШӘШұЫҢ");
  return fresh;
}

async function closeSalesTicketByCustomer(env, bot, customer, ticketId) {
  const ticket = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_tickets WHERE id=? AND bot_id=? AND customer_id=?")
    .bind(ticketId, bot.id, customer.id).first();
  if (!ticket) throw new Error("ШӘЫҢЪ©ШӘ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  if (ticket.status === "closed") return ticket;
  const ts = nowIso();
  await env.PASARGUARD_DB.prepare("UPDATE sales_tickets SET status='closed',closed_at=?,updated_at=? WHERE id=?")
    .bind(ts, ts, ticket.id).run();
  await salesEvent(env, bot.id, customer.id, "ticket_closed_by_customer", { ticketId: ticket.id });
  return { ...ticket, status: "closed", closed_at: ts, updated_at: ts };
}

async function replySalesTicketByOwner(env, bot, ownerUserId, ticketId, rawMessage) {
  const ticket = await env.PASARGUARD_DB.prepare(`
    SELECT t.*,c.telegram_id,c.first_name,c.username,c.phone_number,c.phone_verified_at
    FROM sales_tickets t JOIN sales_customers c ON c.id=t.customer_id
    WHERE t.id=? AND t.bot_id=?
  `).bind(ticketId, bot.id).first();
  if (!ticket) throw new Error("ШӘЫҢЪ©ШӘ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  if (ticket.status === "closed") throw new Error("Ш§ШЁШӘШҜШ§ ШӘЫҢЪ©ШӘ ШұШ§ ШЁШ§ШІ Ъ©ЩҶЫҢШҜ");
  const message = cleanText(rawMessage, 3000);
  if (message.length < 2) throw new Error("Щ…ШӘЩҶ ЩҫШ§ШіШ® Ъ©ЩҲШӘШ§ЩҮ Ш§ШіШӘ");
  const ts = nowIso();
  const messageId = id("tmsg");
  await env.PASARGUARD_DB.batch([
    env.PASARGUARD_DB.prepare(`
      INSERT INTO sales_ticket_messages(id,ticket_id,bot_id,sender_type,sender_id,message_text,created_at)
      VALUES(?,?,?,'owner',?,?,?)
    `).bind(messageId, ticket.id, bot.id, String(ownerUserId || ""), message, ts),
    env.PASARGUARD_DB.prepare("UPDATE sales_tickets SET status='answered',last_message_at=?,updated_at=? WHERE id=?")
      .bind(ts, ts, ticket.id)
  ]);
  const customer = {
    id: ticket.customer_id,
    telegram_id: ticket.telegram_id,
    first_name: ticket.first_name,
    username: ticket.username
  };
  await createSalesNotification(
    env, bot, customer, null, "support_reply", "ЩҫШ§ШіШ® Ш¬ШҜЫҢШҜ ЩҫШҙШӘЫҢШЁШ§ЩҶЫҢ",
    "ШЁШұШ§ЫҢ ШӘЫҢЪ©ШӘ " + ticket.public_code + " ЩҫШ§ШіШ® Ш¬ШҜЫҢШҜ Ш«ШЁШӘ ШҙШҜ.",
    "ticket_reply:" + messageId,
    { sendBot: ticket.origin !== "miniapp" }
  );
  await salesEvent(env, bot.id, ticket.customer_id, "ticket_owner_reply", { ticketId: ticket.id, messageId });
  return { ...ticket, status: "answered", last_message_at: ts, updated_at: ts };
}

function resellerFeatureEnabled(bot, key, fallback = true) {
  const value = bot?.[key];
  if (value === undefined || value === null || value === "") return fallback;
  return Number(value) === 1 || value === true || value === "true";
}

async function getSalesServicePreference(env, bot, customer, service) {
  const username = String(service?.remote_username || "").trim();
  if (!username) return null;
  const rootOrderId = String(service?.id || service?.root_order_id || "");
  let row = await env.PASARGUARD_DB.prepare(`
    SELECT * FROM sales_service_preferences WHERE bot_id=? AND customer_id=? AND remote_username=?
  `).bind(bot.id, customer.id, username).first();
  if (!row) {
    const ts = nowIso();
    await env.PASARGUARD_DB.prepare(`
      INSERT INTO sales_service_preferences(bot_id,customer_id,root_order_id,remote_username,auto_renew_enabled,renew_days_before,health_monitor_enabled,created_at,updated_at)
      VALUES(?,?,?,?,0,2,1,?,?)
      ON CONFLICT(bot_id,customer_id,remote_username) DO NOTHING
    `).bind(bot.id, customer.id, rootOrderId, username, ts, ts).run();
    row = await env.PASARGUARD_DB.prepare(`SELECT * FROM sales_service_preferences WHERE bot_id=? AND customer_id=? AND remote_username=?`)
      .bind(bot.id, customer.id, username).first();
  }
  return row;
}

async function toggleSalesServiceAutoRenew(env, bot, customer, serviceId) {
  if (!resellerFeatureEnabled(bot, "auto_renew_enabled", true)) throw new Error("ШӘЩ…ШҜЫҢШҜ Ш®ЩҲШҜЪ©Ш§Шұ ШӘЩҲШіШ· Щ…ШҜЫҢШұ Ш§ЫҢЩҶ ШұШЁШ§ШӘ ШәЫҢШұЩҒШ№Ш§Щ„ Ш§ШіШӘ");
  const service = await getSalesServiceOrder(env, bot, customer, serviceId);
  const pref = await getSalesServicePreference(env, bot, customer, service);
  let renewalPlanId = pref?.renewal_plan_id || null;
  if (!renewalPlanId) {
    const plan = await env.PASARGUARD_DB.prepare(`
      SELECT id FROM sales_plans WHERE bot_id=? AND status='active' AND plan_type='renew'
      ORDER BY sort_order,price_toman,duration_days LIMIT 1
    `).bind(bot.id).first();
    if (!plan) throw new Error("ШЁШұШ§ЫҢ ШӘЩ…ШҜЫҢШҜ Ш®ЩҲШҜЪ©Ш§Шұ ЩҮЩҶЩҲШІ ЩҫЩ„ЩҶ ШӘЩ…ШҜЫҢШҜ ЩҒШ№Ш§Щ„ЫҢ Ш«ШЁШӘ ЩҶШҙШҜЩҮ Ш§ШіШӘ");
    renewalPlanId = plan.id;
  }
  const next = Number(pref?.auto_renew_enabled || 0) === 1 ? 0 : 1;
  await env.PASARGUARD_DB.prepare(`
    UPDATE sales_service_preferences SET auto_renew_enabled=?,renewal_plan_id=?,updated_at=?
    WHERE bot_id=? AND customer_id=? AND remote_username=?
  `).bind(next, renewalPlanId, nowIso(), bot.id, customer.id, service.remote_username).run();
  await salesEvent(env, bot.id, customer.id, "service_auto_renew_toggled", { serviceId, username: service.remote_username, enabled: next === 1, renewalPlanId });
  return next === 1;
}

async function toggleSalesServiceHealthMonitor(env, bot, customer, serviceId) {
  const service = await getSalesServiceOrder(env, bot, customer, serviceId);
  const pref = await getSalesServicePreference(env, bot, customer, service);
  const next = Number(pref?.health_monitor_enabled ?? 1) === 1 ? 0 : 1;
  await env.PASARGUARD_DB.prepare(`UPDATE sales_service_preferences SET health_monitor_enabled=?,updated_at=? WHERE bot_id=? AND customer_id=? AND remote_username=?`)
    .bind(next, nowIso(), bot.id, customer.id, service.remote_username).run();
  return next === 1;
}

function serviceHealthFromSnapshot(service) {
  const status = String(service?.remote_status || "unknown").toLowerCase();
  const expireMs = service?.remote_expire ? Date.parse(service.remote_expire) : NaN;
  const onlineMs = service?.remote_online_at ? Date.parse(service.remote_online_at) : NaN;
  const staleHours = Number.isFinite(onlineMs) ? Math.max(0, (Date.now() - onlineMs) / 3600000) : null;
  let score = 92, label = "ШіШ§Щ„Щ…", icon = "рҹҹў";
  if (["expired","disabled","limited"].includes(status)) { score = 25; label = "ЩҶЫҢШ§ШІЩ…ЩҶШҜ ШЁШұШұШіЫҢ"; icon = "рҹ”ҙ"; }
  else if (Number.isFinite(expireMs) && expireMs < Date.now()) { score = 20; label = "Щ…ЩҶЩӮШ¶ЫҢ"; icon = "рҹ”ҙ"; }
  else if (staleHours != null && staleHours > 72) { score = 62; label = "ШЁШҜЩҲЩҶ Ш§ШӘШөШ§Щ„ Ш§Ш®ЫҢШұ"; icon = "рҹҹЎ"; }
  return { score, label, icon, staleHours };
}

async function salesRecommendedPlan(env, bot, customer) {
  if (!resellerFeatureEnabled(bot, "smart_recommendations_enabled", true)) return null;
  const service = await env.PASARGUARD_DB.prepare(`
    SELECT remote_data_limit,remote_used_traffic,remote_expire FROM sales_orders
    WHERE bot_id=? AND customer_id=? AND status='delivered' AND remote_username IS NOT NULL
    ORDER BY updated_at DESC LIMIT 1
  `).bind(bot.id, customer.id).first();
  const targetBytes = Math.max(1024*1024*1024, Number(service?.remote_used_traffic || 0) * 1.25, Number(service?.remote_data_limit || 0) * .75);
  const plan = await env.PASARGUARD_DB.prepare(`
    SELECT * FROM sales_plans WHERE bot_id=? AND status='active' AND plan_type='sale' AND data_limit_bytes>=?
    ORDER BY data_limit_bytes ASC,duration_days ASC,price_toman ASC LIMIT 1
  `).bind(bot.id, targetBytes).first();
  if (plan) return plan;
  return env.PASARGUARD_DB.prepare(`SELECT * FROM sales_plans WHERE bot_id=? AND status='active' AND plan_type='sale' ORDER BY data_limit_bytes DESC,price_toman ASC LIMIT 1`).bind(bot.id).first();
}

async function salesDynamicUpsell(env, bot, plan) {
  if (!resellerFeatureEnabled(bot, "upsell_enabled", true) || !plan || String(plan.plan_type||"sale") !== "sale") return null;
  if (plan.upsell_plan_id) {
    const fixed = await env.PASARGUARD_DB.prepare(`SELECT * FROM sales_plans WHERE id=? AND bot_id=? AND status='active'`).bind(plan.upsell_plan_id, bot.id).first();
    if (fixed) return fixed;
  }
  return env.PASARGUARD_DB.prepare(`
    SELECT * FROM sales_plans WHERE bot_id=? AND status='active' AND plan_type='sale' AND id<>?
      AND (data_limit_bytes>? OR duration_days>?) AND price_toman>?
    ORDER BY (price_toman-?) ASC,data_limit_bytes ASC LIMIT 1
  `).bind(bot.id, plan.id, Number(plan.data_limit_bytes||0), Number(plan.duration_days||0), Number(plan.price_toman||0), Number(plan.price_toman||0)).first();
}

