async function purchaseGiftPlanFromWallet(env, bot, sender, planId, recipientTelegramId, requestedUsername, giftMessage="") {
  const recipientId=String(recipientTelegramId||"").replace(/\D/g,"");
  if (!/^\d{5,20}$/.test(recipientId)) throw new Error("ШҙЩҶШ§ШіЩҮ ШӘЩ„ЪҜШұШ§Щ… ШҜШұЫҢШ§ЩҒШӘвҖҢЪ©ЩҶЩҶШҜЩҮ Щ…Ш№ШӘШЁШұ ЩҶЫҢШіШӘ");
  if (recipientId===String(sender.telegram_id)) throw new Error("ШЁШұШ§ЫҢ Ш®ЩҲШҜШӘШ§ЩҶ Ш§ШІ Ш®ШұЫҢШҜ Ш№Ш§ШҜЫҢ Ш§ШіШӘЩҒШ§ШҜЩҮ Ъ©ЩҶЫҢШҜ");
  const recipient=await ensureSalesCustomer(env,bot,{id:recipientId,first_name:"ШҜШұЫҢШ§ЩҒШӘвҖҢЪ©ЩҶЩҶШҜЩҮ ЩҮШҜЫҢЩҮ",username:""},"");
  const order=await createSalesOrder(env,bot,recipient,planId,{paymentMethod:"wallet",status:"pending_review",requestedUsername,origin:"bot",giftSenderCustomerId:sender.id,giftMessage});
  await adjustSalesCustomerBalance(env,bot.id,sender.id,-Number(order.amountToman),"gift_purchase","sales_order",order.orderId,"Ш®ШұЫҢШҜ ЩҮШҜЫҢЩҮ "+order.plan.title);
  const giftId=id("gift");
  await env.PASARGUARD_DB.prepare(`INSERT INTO sales_gifts(id,bot_id,sender_customer_id,recipient_customer_id,order_id,plan_id,gift_message,status,created_at) VALUES(?,?,?,?,?,?,?,'processing',?)`)
    .bind(giftId,bot.id,sender.id,recipient.id,order.orderId,planId,cleanText(giftMessage,500),nowIso()).run();
  const owner=await env.PASARGUARD_DB.prepare("SELECT * FROM users WHERE id=?").bind(bot.user_id).first();
  try {
    const delivered=await provisionSalesOrder(env,owner,order.orderId);
    await env.PASARGUARD_DB.prepare(`UPDATE sales_gifts SET status='delivered',delivered_at=? WHERE id=?`).bind(nowIso(),giftId).run();
    await createSalesNotification(env,bot,sender,order.orderId,"gift_sent","ЩҮШҜЫҢЩҮ ШҙЩ…Ш§ ШӘШӯЩҲЫҢЩ„ ШҙШҜ","ШіШұЩҲЫҢШі ЩҮШҜЫҢЩҮ ШЁШұШ§ЫҢ ШҙЩҶШ§ШіЩҮ "+recipientId+" ШЁШ§ Щ…ЩҲЩҒЩӮЫҢШӘ ШіШ§Ш®ШӘЩҮ ШҙШҜ.","gift-sent:"+giftId,{sendBot:true});
    return delivered;
  } catch(error) {
    try{await adjustSalesCustomerBalance(env,bot.id,sender.id,Number(order.amountToman),"refund","sales_order",order.orderId,"ШЁШ§ШІЪҜШҙШӘ ЩҲШ¬ЩҮ ЩҮШҜЫҢЩҮ ЩҶШ§Щ…ЩҲЩҒЩӮ");}catch(_){}
    await env.PASARGUARD_DB.prepare(`UPDATE sales_gifts SET status='failed' WHERE id=?`).bind(giftId).run();
    throw error;
  }
}

async function decodeSubscriptionQrFromTelegramPhoto(env, bot, message) {
  const photos=Array.isArray(message?.photo)?message.photo:[];
  if (!photos.length) return "";
  const fileId=String(photos[photos.length-1]?.file_id||"");
  if (!fileId) return "";
  const token=await decryptSecret(bot.bot_token_enc,env);
  const info=await telegramApiWithToken(token,"getFile",{file_id:fileId});
  const filePath=String(info?.result?.file_path||"");
  if (!filePath) throw new Error("ЩҒШ§ЫҢЩ„ QR Ш§ШІ ШӘЩ„ЪҜШұШ§Щ… ШҜШұЫҢШ§ЩҒШӘ ЩҶШҙШҜ");
  const image=await fetch("https://api.telegram.org/file/bot"+token+"/"+filePath);
  if (!image.ok) throw new Error("ШҜШ§ЩҶЩ„ЩҲШҜ ШӘШөЩҲЫҢШұ QR ЩҶШ§Щ…ЩҲЩҒЩӮ ШЁЩҲШҜ");
  const form=new FormData();
  form.append("file",new Blob([await image.arrayBuffer()],{type:image.headers.get("content-type")||"image/jpeg"}),"qr.jpg");
  const response=await fetch("https://api.qrserver.com/v1/read-qr-code/",{method:"POST",body:form});
  const payload=await response.json().catch(()=>null);
  const value=cleanText(payload?.[0]?.symbol?.[0]?.data,3000);
  if (!value) throw new Error("QR ЩӮШ§ШЁЩ„ Ш®ЩҲШ§ЩҶШҜЩҶ ЩҶЫҢШіШӘШӣ Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© ШұШ§ ШЁЩҮвҖҢШөЩҲШұШӘ Щ…ШӘЩҶ Ш§ШұШіШ§Щ„ Ъ©ЩҶЫҢШҜ");
  return value;
}

async function createGuaranteeClaim(env, bot, customer, serviceId) {
  if (!resellerFeatureEnabled(bot,"guarantee_enabled",true)) throw new Error("Ш¶Щ…Ш§ЩҶШӘ Ш®ШұЫҢШҜ ШҜШұ Ш§ЫҢЩҶ ШұШЁШ§ШӘ ШәЫҢШұЩҒШ№Ш§Щ„ Ш§ШіШӘ");
  const service=await getSalesServiceOrder(env,bot,customer,serviceId);
  const plan=await env.PASARGUARD_DB.prepare(`SELECT guarantee_hours,guarantee_policy FROM sales_plans WHERE id=?`).bind(service.plan_id).first();
  const hours=Math.max(0,Number(plan?.guarantee_hours||0));
  if (!hours) throw new Error("Ш§ЫҢЩҶ ЩҫЩ„ЩҶ Ш¶Щ…Ш§ЩҶШӘ ЩҒШ№Ш§Щ„ ЩҶШҜШ§ШұШҜ");
  const purchased=Date.parse(service.created_at||"");
  if (!Number.isFinite(purchased)||Date.now()-purchased>hours*3600000) throw new Error("Щ…ЩҮЩ„ШӘ Ш§ШіШӘЩҒШ§ШҜЩҮ Ш§ШІ Ш¶Щ…Ш§ЩҶШӘ Ш§ЫҢЩҶ ШіШұЩҲЫҢШі ЩҫШ§ЫҢШ§ЩҶ ЫҢШ§ЩҒШӘЩҮ Ш§ШіШӘ");
  const claimId=id("gcl");
  await env.PASARGUARD_DB.prepare(`INSERT INTO sales_guarantee_claims(id,bot_id,customer_id,order_id,remote_username,reason,status,created_at,updated_at) VALUES(?,?,?,?,?,'connection_problem','pending',?,?) ON CONFLICT(bot_id,order_id,status) DO NOTHING`)
    .bind(claimId,bot.id,customer.id,service.id,service.remote_username,nowIso(),nowIso()).run();
  await queueReportEvent(env,bot.id,"support","ШҜШұШ®ЩҲШ§ШіШӘ Ш¶Щ…Ш§ЩҶШӘ ШіШұЩҲЫҢШі","Ъ©Ш§ШұШЁШұ: <code>"+botEscape(customer.telegram_id)+"</code>\nШіШұЩҲЫҢШі: <code>"+botEscape(service.remote_username)+"</code>\nШіЫҢШ§ШіШӘ: "+botEscape(plan?.guarantee_policy||"ШЁШұШұШіЫҢ Ш§ШӘШөШ§Щ„"),"guarantee:"+service.id);
  return true;
}

async function salesCustomerHomeView(env, bot, customer) {
  const homeBatch = await env.PASARGUARD_DB.batch([
    env.PASARGUARD_DB.prepare(`
      SELECT
        (SELECT COUNT(*) FROM sales_plans WHERE bot_id=? AND status='active') AS active_plans,
        (SELECT COUNT(*) FROM sales_orders WHERE customer_id=?) AS orders_count,
        (SELECT COUNT(DISTINCT remote_username) FROM sales_orders WHERE customer_id=? AND status='delivered' AND remote_username IS NOT NULL AND remote_username<>'') AS delivered_count,
        (SELECT COUNT(*) FROM sales_customers WHERE referrer_customer_id=?) AS referrals_count,
        (SELECT COUNT(*) FROM sales_service_preferences WHERE bot_id=? AND customer_id=? AND auto_renew_enabled=1) AS auto_renew_count
    `).bind(bot.id, customer.id, customer.id, customer.id, bot.id, customer.id),
    env.PASARGUARD_DB.prepare("SELECT text_value FROM reseller_bot_texts WHERE bot_id=? AND text_key='welcome' LIMIT 1").bind(bot.id)
  ]);
  const stats = (homeBatch[0]?.results || [])[0] || {};
  const welcomeRow = (homeBatch[1]?.results || [])[0] || null;
  const supportUrl = salesSupportUrl(bot);
  const rows = [
    [{ text: "рҹӣ’ Ш®ШұЫҢШҜ ШіШұЩҲЫҢШі", callback_data: "sale:locations" }, { text: "вҷ»пёҸ ШӘЩ…ШҜЫҢШҜ ШіШұЩҲЫҢШі", callback_data: "sale:services" }],
    [{ text: "рҹ“Ұ ШіШұЩҲЫҢШівҖҢЩҮШ§ ЩҲ ШіЩҒШ§ШұШҙвҖҢЩҮШ§", callback_data: "sale:orders" }, { text: "рҹ”— Ш§ЩҒШІЩҲШҜЩҶ ШіШұЩҲЫҢШі ЩӮШЁЩ„ЫҢ", callback_data: "sale:import" }],
    [{ text: "рҹ’і ШҙШ§ШұЪҳ ЩҲ Щ…ЩҲШ¬ЩҲШҜЫҢ", callback_data: "sale:wallet" }, { text: "рҹ‘Ө ШӯШіШ§ШЁ Ъ©Ш§ШұШЁШұЫҢ", callback_data: "sale:account" }],
    [{ text: "рҹ‘Ҙ ШІЫҢШұЩ…Ш¬Щ…ЩҲШ№ЩҮвҖҢЪҜЫҢШұЫҢ", callback_data: "sale:referral" }, { text: "рҹҺҒ ШӘШіШӘ ШұШ§ЫҢЪҜШ§ЩҶ", callback_data: "sale:trial" }],
    [{ text: "рҹҺҹ ШӘШ®ЩҒЫҢЩҒ ЩҲ ЩҮШҜЫҢЩҮ", callback_data: "sale:promo" }, { text: "рҹ“ҡ ШўЩ…ЩҲШІШҙ ЩҲ ШұШ§ЩҮЩҶЩ…Ш§", callback_data: "sale:help" }]
  ];
  const growthRow=[];
  if (resellerFeatureEnabled(bot,"smart_recommendations_enabled",true)) growthRow.push({text:"рҹҺҜ ЩҫЫҢШҙЩҶЩҮШ§ШҜ ЩҮЩҲШҙЩ…ЩҶШҜ",callback_data:"sale:recommend"});
  if (resellerFeatureEnabled(bot,"favorite_plan_enabled",true) && customer.favorite_plan_id) growthRow.push({text:"вӯҗ Ш®ШұЫҢШҜ Щ…ШӯШЁЩҲШЁ",callback_data:"sale:favorite"});
  if (growthRow.length) rows.splice(1,0,growthRow);
  if (resellerFeatureEnabled(bot,"gift_service_enabled",true)) rows.splice(2,0,[{text:"рҹҺҒ ЩҮШҜЫҢЩҮвҖҢШҜШ§ШҜЩҶ ШіШұЩҲЫҢШі",callback_data:"sale:gift:start"}]);
  if (Number(bot.ticketing_enabled ?? 1) === 1) rows.push([{ text: "рҹҺ« Щ…ШұЪ©ШІ ЩҫШҙШӘЫҢШЁШ§ЩҶЫҢ", callback_data: "sale:support" }]);
  if (String(customer.telegram_id) === String(bot.owner_telegram_id || "")) {
    if (resellerBotCanCreateDownline(bot)) rows.push([
      { text: "вһ• ШіШ§Ш®ШӘ ШұШЁШ§ШӘ ШІЫҢШұЩ…Ш¬Щ…ЩҲШ№ЩҮ", callback_data: "owner:child:new" },
      { text: "рҹ‘‘ ШІЫҢШұЩ…Ш¬Щ…ЩҲШ№ЩҮвҖҢЩҮШ§ЫҢ Щ…ЩҶ", callback_data: "owner:children" }
    ]);
    rows.push([{ text: "вҡҷпёҸ Щ…ШҜЫҢШұЫҢШӘ ШұШЁШ§ШӘ", callback_data: "owner:home" }]);
  }
  if (supportUrl) rows.push([{ text: "рҹҶҳ Ш§ШұШӘШЁШ§Ш· Щ…ШіШӘЩӮЫҢЩ…", url: supportUrl }]);
  const name = customer.first_name || customer.username || "Ъ©Ш§ШұШЁШұ Ш№ШІЫҢШІ";
  const welcome = cleanText(welcomeRow?.text_value, 3500) || cleanText(bot.welcome_text, 1200) || "Ш§ШІ Щ…ЩҶЩҲЫҢ ШІЫҢШұ ШіШұЩҲЫҢШі ШЁШ®ШұЫҢШҜШҢ ШӘЩ…ШҜЫҢШҜ Ъ©ЩҶЫҢШҜ ЫҢШ§ ШӯШіШ§ШЁ Ш®ЩҲШҜ ШұШ§ Щ…ШҜЫҢШұЫҢШӘ Ъ©ЩҶЫҢШҜ.";
  return {
    text: "рҹ‘Ӣ ШіЩ„Ш§Щ… <b>" + botEscape(name) + "</b>\n" +
      "ШЁЩҮ <b>" + botEscape(bot.brand_name) + "</b> Ш®ЩҲШҙ ШўЩ…ШҜЫҢШҜ.\n\n" + botEscape(welcome) + "\n\n" +
      "рҹ’і Щ…ЩҲШ¬ЩҲШҜЫҢ: <b>" + botMoney(customer.wallet_balance) + " ШӘЩҲЩ…Ш§ЩҶ</b>\n" +
      "рҹӣҚ ЩҫЩ„ЩҶ ЩҒШ№Ш§Щ„: <b>" + botMoney(stats?.active_plans) + "</b>\n" +
      "вң… ШіШұЩҲЫҢШівҖҢЩҮШ§ЫҢ ШӘШӯЩҲЫҢЩ„вҖҢШҙШҜЩҮ: <b>" + botMoney(stats?.delivered_count) + "</b>\n" +
      "рҹ‘Ҙ ШІЫҢШұЩ…Ш¬Щ…ЩҲШ№ЩҮвҖҢЩҮШ§: <b>" + botMoney(stats?.referrals_count) + "</b>\n" +
      (customer.active_promo_code_id ? "рҹҺҹ Ъ©ШҜ ШӘШ®ЩҒЫҢЩҒ ЩҒШ№Ш§Щ„ ШЁШұШ§ЫҢ Ш®ШұЫҢШҜ ШЁШ№ШҜЫҢ\n" : "") +
      "ЩҶШіШ®ЩҮ ШұШЁШ§ШӘ: <code>" + botEscape(RESELLER_BOT_VERSION) + "</code>",
    reply_markup: { inline_keyboard: rows }
  };
}

