async function sendSalesReferralView(env, bot, customer, chatId) {
  const rendered = await salesCustomerReferralView(env, bot, customer);
  if (bot.referral_banner_file_id) {
    const method = String(bot.referral_banner_file_type || "photo") === "document" ? "sendDocument" : "sendPhoto";
    const key = method === "sendDocument" ? "document" : "photo";
    const payload = { chat_id: chatId, caption: rendered.text, parse_mode: "HTML", reply_markup: rendered.reply_markup, protect_content: Number(bot.forward_enabled ?? 1) !== 1 };
    payload[key] = bot.referral_banner_file_id;
    try { return await resellerTelegramApi(env, bot, method, payload); } catch (_) {}
  }
  return resellerTelegramApi(env, bot, "sendMessage", { chat_id: chatId, text: rendered.text, parse_mode: "HTML", reply_markup: rendered.reply_markup, disable_web_page_preview: true, protect_content: Number(bot.forward_enabled ?? 1) !== 1 });
}

async function salesCustomerSendOrEdit(env, bot, target, view, options = {}) {
  let rendered;
  if (view === "group_services") rendered = await salesCustomerGroupView(env, bot, target.customer, "services");
  else if (view === "group_account") rendered = await salesCustomerGroupView(env, bot, target.customer, "account");
  else if (view === "group_rewards") rendered = await salesCustomerGroupView(env, bot, target.customer, "rewards");
  else if (view === "group_support") rendered = await salesCustomerGroupView(env, bot, target.customer, "support");
  else if (view === "plans") rendered = await salesCustomerPlansView(env, bot, target.customer, options);
  else if (view === "categories") rendered = await salesCustomerCategoriesView(env, bot, options);
  else if (view === "locations") {
    const locations = await salesActivePurchaseLocations(env, bot);
    if (locations.length === 1) {
      const locationId = String(locations[0].id);
      const previous = await salesSessionGet(env, bot.id, target.customer.telegram_id);
      await salesSessionSet(env, bot.id, target.customer.telegram_id, "purchase_location", {
        ...(previous?.data || {}), locationId, singleLocation: true
      });
      rendered = await salesCustomerCategoriesView(env, bot, { locationId, singleLocation: true });
    } else {
      rendered = await salesCustomerLocationsView(env, bot);
    }
  }
  else if (view === "orders") rendered = await salesCustomerOrdersView(env, bot, target.customer);
  else if (view === "order_detail") rendered = await salesCustomerOrderDetailView(env, bot, target.customer, options.orderId);
  else if (view === "services") rendered = await salesCustomerServicesView(env, bot, target.customer);
  else if (view === "service_detail") rendered = await salesCustomerServiceDetailView(env, bot, target.customer, options.serviceId);
  else if (view === "wallet") rendered = await salesCustomerWalletView(env, bot, target.customer);
  else if (view === "account") rendered = await salesCustomerAccountView(env, bot, target.customer);
  else if (view === "referral") rendered = await salesCustomerReferralView(env, bot, target.customer);
  else if (view === "promo") rendered = await salesCustomerPromoView(env, bot, target.customer);
  else if (view === "help") rendered = await salesCustomerHelpView(env, bot);
  else if (view === "help_article") rendered = await salesCustomerHelpArticleView(env, bot, options.key);
  else rendered = await salesCustomerHomeView(env, bot, target.customer);
  const payload = {
    chat_id: target.chatId,
    text: rendered.text,
    parse_mode: "HTML",
    disable_web_page_preview: true,
    protect_content: Number(bot.forward_enabled ?? 1) !== 1,
    reply_markup: rendered.reply_markup
  };
  if (target.messageId) {
    try {
      await resellerTelegramApi(env, bot, "editMessageText", { ...payload, message_id: target.messageId });
      return;
    } catch (error) {
      if (String(error.message || "").toLowerCase().includes("message is not modified")) return;
    }
  }
  await resellerTelegramApi(env, bot, "sendMessage", payload);
}

function resellerSecurityConfig(bot) {
  return {
    enabled: Number(bot?.fraud_protection_enabled ?? 1) === 1,
    cooldownSeconds: Math.max(0, Math.min(3600, Number(bot?.order_cooldown_seconds || 30))),
    maxPendingOrders: Math.max(1, Math.min(50, Number(bot?.max_pending_orders || 3))),
    dailyOrderLimit: Math.max(1, Math.min(500, Number(bot?.daily_order_limit || 10))),
    dailyWalletLimit: Math.max(0, Math.min(1000000000000, Number(bot?.daily_wallet_charge_limit_toman || 5000000))),
    duplicateReceiptProtection: Number(bot?.duplicate_receipt_protection ?? 1) === 1,
    autoBlockRiskScore: Math.max(0, Math.min(1000, Number(bot?.auto_block_risk_score || 100)))
  };
}

function salesRiskLevel(score) {
  const value = Number(score || 0);
  if (value >= 100) return "critical";
  if (value >= 60) return "high";
  if (value >= 25) return "medium";
  return "normal";
}

async function recordSalesSecurityEvent(env, bot, customer, eventType, severity = "info", scoreDelta = 0, details = {}) {
  const ts = nowIso();
  const customerId = customer?.id || null;
  await env.PASARGUARD_DB.prepare(`
    INSERT INTO sales_security_events(id,bot_id,customer_id,event_type,severity,score_delta,details,created_at)
    VALUES(?,?,?,?,?,?,?,?)
  `).bind(id("sec"), bot.id, customerId, cleanText(eventType, 120), cleanText(severity, 20),
    Number(scoreDelta || 0), JSON.stringify(details || {}), ts).run();
  if (!customerId || !Number(scoreDelta || 0)) return { score: Number(customer?.risk_score || 0), blocked: false };
  const freshBefore = await env.PASARGUARD_DB.prepare("SELECT risk_score,status FROM sales_customers WHERE id=? AND bot_id=?")
    .bind(customerId, bot.id).first();
  const nextScore = Math.max(0, Number(freshBefore?.risk_score || 0) + Number(scoreDelta || 0));
  const level = salesRiskLevel(nextScore);
  const threshold = resellerSecurityConfig(bot).autoBlockRiskScore;
  const shouldBlock = threshold > 0 && nextScore >= threshold;
  await env.PASARGUARD_DB.prepare(`
    UPDATE sales_customers SET risk_score=?,risk_level=?,last_security_event_at=?,
      status=CASE WHEN ?=1 THEN 'blocked' ELSE status END,updated_at=? WHERE id=? AND bot_id=?
  `).bind(nextScore, level, ts, shouldBlock ? 1 : 0, ts, customerId, bot.id).run();
  if (shouldBlock && String(freshBefore?.status || "") !== "blocked") {
    try {
      await resellerTelegramApi(env, bot, "sendMessage", {
        chat_id: bot.owner_telegram_id,
        text: "рҹҡЁ <b>Щ…ШіШҜЩҲШҜШіШ§ШІЫҢ Ш®ЩҲШҜЪ©Ш§Шұ Ъ©Ш§ШұШЁШұ ЩҫШұШ®Ш·Шұ</b>\nЪ©Ш§ШұШЁШұ: <code>" + botEscape(customer.telegram_id || customerId) +
          "</code>\nШ§Щ…ШӘЫҢШ§ШІ ШұЫҢШіЪ©: <b>" + botMoney(nextScore) + "</b>\nШұШ®ШҜШ§ШҜ: <b>" + botEscape(eventType) + "</b>",
        parse_mode: "HTML"
      });
    } catch (_) {}
  }
  return { score: nextScore, blocked: shouldBlock };
}

function salesSecurityError(message, code = "SECURITY_LIMIT") {
  const error = new Error(message);
  error.code = code;
  return error;
}

async function enforceSalesSecurity(env, bot, customer, action, amountToman = 0) {
  const cfg = resellerSecurityConfig(bot);
  if (String(customer?.status || "active") !== "active") {
    throw salesSecurityError("ШӯШіШ§ШЁ ШҙЩ…Ш§ ШЁШұШ§ЫҢ Ш§ЩҶШ¬Ш§Щ… Ш№Щ…Щ„ЫҢШ§ШӘ Ш¬ШҜЫҢШҜ Щ…ШӯШҜЩҲШҜ ШҙШҜЩҮ Ш§ШіШӘ. ШЁШ§ ЩҫШҙШӘЫҢШЁШ§ЩҶЫҢ ШӘЩ…Ш§Ші ШЁЪҜЫҢШұЫҢШҜ.", "CUSTOMER_BLOCKED");
  }
  if (!cfg.enabled) return cfg;
  const now = Date.now();
  const today = new Date();
  today.setUTCHours(0, 0, 0, 0);
  const dayStart = today.toISOString();
  const actionType = cleanText(action, 50);

  if (cfg.cooldownSeconds > 0) {
    const last = await env.PASARGUARD_DB.prepare(`
      SELECT created_at FROM sales_bot_events WHERE bot_id=? AND customer_id=? AND event_type=? ORDER BY created_at DESC LIMIT 1
    `).bind(bot.id, customer.id, "security_action:" + actionType).first();
    if (last?.created_at) {
      const wait = cfg.cooldownSeconds - Math.floor((now - Date.parse(last.created_at)) / 1000);
      if (wait > 0) {
        await recordSalesSecurityEvent(env, bot, customer, "rapid_action", "warning", 5, { action: actionType, wait });
        throw salesSecurityError("Щ„Ш·ЩҒШ§ЩӢ " + wait + " Ш«Ш§ЩҶЫҢЩҮ ШөШЁШұ Ъ©ЩҶЫҢШҜ ЩҲ ШҜЩҲШЁШ§ШұЩҮ ШӘЩ„Ш§Шҙ Ъ©ЩҶЫҢШҜ.", "ACTION_COOLDOWN");
      }
    }
  }

  if (["order", "renewal", "volume"].includes(actionType)) {
    const row = await env.PASARGUARD_DB.prepare(`
      SELECT
        (SELECT COUNT(*) FROM sales_orders WHERE bot_id=? AND customer_id=? AND status IN ('awaiting_receipt','payment_pending','receipt_uploading','pending_review','processing','provisioning')) AS pending_count,
        (SELECT COUNT(*) FROM sales_orders WHERE bot_id=? AND customer_id=? AND created_at>=?) AS daily_count
    `).bind(bot.id, customer.id, bot.id, customer.id, dayStart).first();
    if (Number(row?.pending_count || 0) >= cfg.maxPendingOrders) {
      await recordSalesSecurityEvent(env, bot, customer, "pending_order_limit", "warning", 10, { count: row.pending_count, limit: cfg.maxPendingOrders });
      throw salesSecurityError("ШӘШ№ШҜШ§ШҜ ШіЩҒШ§ШұШҙвҖҢЩҮШ§ЫҢ ШҜШұ Ш§ЩҶШӘШёШ§Шұ ШҙЩ…Ш§ ШЁЩҮ ШӯШҜ Щ…Ш¬Ш§ШІ ШұШіЫҢШҜЩҮ Ш§ШіШӘ.", "PENDING_ORDER_LIMIT");
    }
    if (Number(row?.daily_count || 0) >= cfg.dailyOrderLimit) {
      await recordSalesSecurityEvent(env, bot, customer, "daily_order_limit", "high", 15, { count: row.daily_count, limit: cfg.dailyOrderLimit });
      throw salesSecurityError("ШіЩӮЩҒ ШӘШ№ШҜШ§ШҜ ШіЩҒШ§ШұШҙ ШұЩҲШІШ§ЩҶЩҮ ШҙЩ…Ш§ ШӘЪ©Щ…ЫҢЩ„ ШҙШҜЩҮ Ш§ШіШӘ.", "DAILY_ORDER_LIMIT");
    }
  }

  if (actionType === "wallet_charge" && cfg.dailyWalletLimit > 0) {
    const row = await env.PASARGUARD_DB.prepare(`
      SELECT COALESCE(SUM(amount_toman),0) AS total FROM sales_wallet_requests
      WHERE bot_id=? AND customer_id=? AND created_at>=? AND status NOT IN ('rejected','cancelled')
    `).bind(bot.id, customer.id, dayStart).first();
    if (Number(row?.total || 0) + Number(amountToman || 0) > cfg.dailyWalletLimit) {
      await recordSalesSecurityEvent(env, bot, customer, "daily_wallet_limit", "high", 20, { current: row?.total || 0, requested: amountToman, limit: cfg.dailyWalletLimit });
      throw salesSecurityError("Щ…ШЁЩ„Шә ШҙШ§ШұЪҳ Ш§ШІ ШіЩӮЩҒ Щ…Ш¬Ш§ШІ ШұЩҲШІШ§ЩҶЩҮ ШЁЫҢШҙШӘШұ Ш§ШіШӘ.", "DAILY_WALLET_LIMIT");
    }
  }

  await salesEvent(env, bot.id, customer.id, "security_action:" + actionType, { amountToman: Number(amountToman || 0) });
  return cfg;
}

async function salesReceiptFingerprint(bytes) {
  const digest = await crypto.subtle.digest("SHA-256", bytes);
  return "sha256:" + Array.from(new Uint8Array(digest)).map(x => x.toString(16).padStart(2, "0")).join("");
}

async function ensureUniqueSalesReceipt(env, bot, customer, fingerprint, currentType, currentId) {
  const cfg = resellerSecurityConfig(bot);
  const value = cleanText(fingerprint, 200);
  if (!cfg.enabled || !cfg.duplicateReceiptProtection || !value) return;
  const duplicate = await env.PASARGUARD_DB.prepare(`
    SELECT 'order' AS source_type,id,customer_id FROM sales_orders
      WHERE bot_id=? AND receipt_unique_id=? AND id<>?
    UNION ALL
    SELECT 'wallet' AS source_type,id,customer_id FROM sales_wallet_requests
      WHERE bot_id=? AND receipt_unique_id=? AND id<>?
    LIMIT 1
  `).bind(bot.id, value, currentType === "order" ? currentId : "", bot.id, value, currentType === "wallet" ? currentId : "").first();
  if (!duplicate) return;
  await recordSalesSecurityEvent(env, bot, customer, "duplicate_receipt", "critical", 35, {
    fingerprint: value, duplicateType: duplicate.source_type, duplicateId: duplicate.id
  });
  throw salesSecurityError("Ш§ЫҢЩҶ ШұШіЫҢШҜ ЩӮШЁЩ„Ш§ЩӢ ШҜШұ ШіШ§Щ…Ш§ЩҶЩҮ Ш«ШЁШӘ ШҙШҜЩҮ Ш§ШіШӘ.", "DUPLICATE_RECEIPT");
}

async function createSalesOrder(env, bot, customer, planId, options = {}) {
  salesRequireVerifiedPhone(bot, customer);
  const plan = await env.PASARGUARD_DB.prepare("SELECT p.*,COALESCE(l.backend_provider,'pasarguard') AS backend_provider FROM sales_plans p LEFT JOIN sales_locations l ON l.id=p.location_id WHERE p.id=? AND p.bot_id=? AND p.status='active'").bind(planId, bot.id).first();
  if (!plan) throw new Error("Ш§ЫҢЩҶ ЩҫЩ„ЩҶ ШҜЫҢЪҜШұ ЩҒШ№Ш§Щ„ ЩҶЫҢШіШӘ");
  const expectedPlanType = options.orderType === "renewal" ? "renew" : options.orderType === "volume" ? "volume" : "sale";
  let serviceProvider=normalizeServiceProvider(plan.backend_provider);
  if(expectedPlanType!=="sale"){
    const targetProvider=await env.PASARGUARD_DB.prepare("SELECT service_provider FROM sales_orders WHERE id=? AND bot_id=? AND customer_id=? AND status='delivered'").bind(options.targetOrderId||"",bot.id,customer.id).first();
    if(!targetProvider) throw new Error("ШіШұЩҲЫҢШі Щ…ЩӮШөШҜ ШЁШұШ§ЫҢ Ш§ЫҢЩҶ Ш№Щ…Щ„ЫҢШ§ШӘ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
    serviceProvider=normalizeServiceProvider(targetProvider.service_provider);
  }else{
    serviceProvider=locationServiceProvider(plan,await getSettings(env),env);
  }
  if (String(plan.plan_type || "sale") !== expectedPlanType) {
    const label = expectedPlanType === "renew" ? "ШӘЩ…ШҜЫҢШҜ" : expectedPlanType === "volume" ? "Ш§ЩҒШІШ§ЫҢШҙ ШӯШ¬Щ…" : "Ш®ШұЫҢШҜ Ш¬ШҜЫҢШҜ";
    throw new Error("Ш§ЫҢЩҶ ЩҫЩ„ЩҶ ШЁШұШ§ЫҢ В«" + label + "В» ЩӮШ§ШЁЩ„ Ш§ШіШӘЩҒШ§ШҜЩҮ ЩҶЫҢШіШӘ");
  }
  await enforceSalesSecurity(env, bot, customer, options.orderType === "renewal" ? "renewal" : options.orderType === "volume" ? "volume" : "order");
  const orderId = id("ord");
  const ts = nowIso();
  const requestedPaymentMethod = String(options.paymentMethod || resellerPaymentDefaultMethod(bot, "order") || "card").toLowerCase();
  const paymentMethod = ["wallet", "card", "blupal"].includes(requestedPaymentMethod) ? requestedPaymentMethod : "card";
  resellerRequirePaymentMethod(bot, paymentMethod, "order");
  const status = options.status || (paymentMethod === "wallet" ? "pending_review" : paymentMethod === "blupal" ? "payment_pending" : "awaiting_receipt");
  const origin = options.origin === "miniapp" ? "miniapp" : "bot";
  const requestedUsername = expectedPlanType === "sale" && cleanText(options.requestedUsername, 80)
    ? normalizeChosenSubscriptionUsername(options.requestedUsername)
    : null;
  if (expectedPlanType === "sale" && origin === "bot" && !requestedUsername) throw new Error("ЩҶШ§Щ… Ш§ШҙШӘШұШ§Ъ© Ш§ЩҶШӘШ®Ш§ШЁ ЩҶШҙШҜЩҮ Ш§ШіШӘ");
  const originalPrice = salesCustomerPlanPrice(plan, customer);

  if (["awaiting_receipt", "payment_pending"].includes(status)) {
    const old = await env.PASARGUARD_DB.prepare("SELECT id FROM sales_orders WHERE bot_id=? AND customer_id=? AND status IN ('awaiting_receipt','payment_pending')")
      .bind(bot.id, customer.id).all();
    await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='cancelled',updated_at=? WHERE bot_id=? AND customer_id=? AND status IN ('awaiting_receipt','payment_pending')")
      .bind(ts, bot.id, customer.id).run();
    for (const item of old.results || []) try { await salesReleasePromoForOrder(env, item.id); } catch (_) {}
  }

  // An activated code is applied only when the selected plan satisfies its minimum purchase.
  // Otherwise the customer can still buy the plan at the normal/wholesale price and keep the code for a later purchase.
  let promoRef = cleanText(options.promoCode, 80);
  if (!promoRef) {
    const activePromo = await salesActivePromoForCustomer(env, bot.id, customer);
    if (activePromo && originalPrice >= Number(activePromo.min_purchase_toman || 0) && salesPromoDiscountForAmount(activePromo, originalPrice) > 0) {
      promoRef = activePromo.id;
    }
  }
  let promoResult = null;
  if (promoRef) promoResult = await salesReservePromoForOrder(env, bot, customer, promoRef, originalPrice, orderId);
  const discountToman = Number(promoResult?.discount || 0);
  const finalPrice = Math.max(1000, originalPrice - discountToman);

  try {
    await env.PASARGUARD_DB.prepare(`
      INSERT INTO sales_orders(
        id,bot_id,plan_id,customer_id,amount_toman,original_amount_toman,discount_toman,promo_code_id,promo_code,
        status,order_type,target_order_id,payment_method,origin,remote_username,gift_sender_customer_id,gift_message,service_provider,created_at,updated_at
      ) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
    `).bind(
      orderId, bot.id, plan.id, customer.id, finalPrice, originalPrice, discountToman,
      promoResult?.promo?.id || null, promoResult?.promo?.code || null,
      status, options.orderType || "new", options.targetOrderId || null, paymentMethod, origin, requestedUsername,
      options.giftSenderCustomerId || null, cleanText(options.giftMessage,500) || null, serviceProvider, ts, ts
    ).run();
  } catch (error) {
    if (promoResult) try { await salesReleasePromoForOrder(env, orderId); } catch (_) {}
    throw error;
  }

  if (status === "awaiting_receipt" && origin !== "miniapp") await salesSessionSet(env, bot.id, customer.telegram_id, "awaiting_receipt", { orderId });
  await salesEvent(env, bot.id, customer.id, "order_created", {
    orderId, planId, paymentMethod, orderType: options.orderType || "new", originalPrice,
    discountToman, finalPrice, promoCode: promoResult?.promo?.code || "", origin, requestedUsername, serviceProvider
  });
  await queueReportEvent(env, bot.id, "orders", "ШіЩҒШ§ШұШҙ Ш¬ШҜЫҢШҜ Ш«ШЁШӘ ШҙШҜ",
    "Щ…ШҙШӘШұЫҢ: <b>" + botEscape(customer.first_name || customer.username || customer.telegram_id) + "</b>\n" +
    "ЩҫЩ„ЩҶ: <b>" + botEscape(plan.title) + "</b>\n" +
    "ЩҶЩҲШ№: <b>" + botEscape(options.orderType || "new") + "</b>\n" +
    "Щ…ШЁЩ„Шә: <b>" + botMoney(finalPrice) + " ШӘЩҲЩ…Ш§ЩҶ</b>\n" +
    "ЩҫШұШҜШ§Ш®ШӘ: <b>" + botEscape(paymentMethod) + "</b>\n" +
    (requestedUsername ? "ЩҶШ§Щ… Ш§ШҙШӘШұШ§Ъ©: <code>" + botEscape(requestedUsername) + "</code>\n" : "") +
    "ШіЩҒШ§ШұШҙ: <code>" + botEscape(orderId) + "</code>",
    "order-created:" + orderId);
  return {
    orderId, plan, amountToman: finalPrice, originalAmountToman: originalPrice, discountToman,
    promoCode: promoResult?.promo?.code || "", orderType: options.orderType || "new",
    targetOrderId: options.targetOrderId || null, origin, requestedUsername, serviceProvider
  };
}

function requireSalesPaymentCard(bot) {
  const card = normalizeCardNumber(bot.card_number);
  if (card.length < 16 || !cleanText(bot.card_holder, 160)) throw new Error("Ш§Ш·Щ„Ш§Ш№Ш§ШӘ Ъ©Ш§ШұШӘ ШЁШ§ЩҶЪ©ЫҢ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ЩҮЩҶЩҲШІ ШӘЪ©Щ…ЫҢЩ„ ЩҶШҙШҜЩҮ Ш§ШіШӘ");
}

function salesMiniAppPaymentPayload(bot, targetType, targetId, amountToman, extra = {}) {
  const bonusPercent = Math.max(0, Math.min(100, Number(extra.bonusPercent || 0)));
  const bonusToman = Math.max(0, Number(extra.bonusToman || 0));
  return {
    target_type: targetType,
    target_id: targetId,
    amount_toman: Number(amountToman || 0),
    original_amount_toman: Number(extra.originalAmountToman || amountToman || 0),
    discount_toman: Number(extra.discountToman || 0),
    promo_code: cleanText(extra.promoCode, 32),
    bonus_percent: bonusPercent,
    bonus_toman: bonusToman,
    final_wallet_credit: Number(amountToman || 0) + bonusToman,
    card_number: formatCardNumber(bot.card_number),
    card_number_raw: normalizeCardNumber(bot.card_number),
    card_holder: cleanText(bot.card_holder, 160),
    bank_name: cleanText(bot.bank_name, 120),
    title: cleanText(extra.title, 200)
  };
}

async function sendSalesPaymentInstructions(env, bot, customer, order) {
  const custom = await salesBotText(env, bot.id, "payment", SALES_TEXT_DEFAULTS.payment);
  const discountLines = Number(order.discountToman || 0) > 0
    ? "ЩӮЫҢЩ…ШӘ Ш§ШөЩ„ЫҢ: <s>" + botMoney(order.originalAmountToman) + " ШӘЩҲЩ…Ш§ЩҶ</s>\n" +
      "рҹҺҹ Ъ©ШҜ ШӘШ®ЩҒЫҢЩҒ: <code>" + botEscape(order.promoCode || "") + "</code>\n" +
      "Щ…ЩӮШҜШ§Шұ ШӘШ®ЩҒЫҢЩҒ: <b>" + botMoney(order.discountToman) + " ШӘЩҲЩ…Ш§ЩҶ</b>\n"
    : "";
  const text = "рҹ§ҫ <b>Ш«ШЁШӘ ШіЩҒШ§ШұШҙ Ш§ЩҶШ¬Ш§Щ… ШҙШҜ</b>\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n" +
    "ЩҫЩ„ЩҶ: <b>" + botEscape(order.plan.title) + "</b>\n" +
    (order.requestedUsername ? "ЩҶШ§Щ… Ш§ШҙШӘШұШ§Ъ©: <code>" + botEscape(order.requestedUsername) + "</code>\n" : "") + discountLines +
    "Щ…ШЁЩ„Шә ЩҫШұШҜШ§Ш®ШӘ: <b>" + botMoney(order.amountToman) + " ШӘЩҲЩ…Ш§ЩҶ</b>\n\n" +
    "рҹ’і ШҙЩ…Ш§ШұЩҮ Ъ©Ш§ШұШӘ:\n<code>" + botEscape(formatCardNumber(bot.card_number)) + "</code>\n" +
    "рҹ‘Ө ШЁЩҮ ЩҶШ§Щ…: <b>" + botEscape(bot.card_holder) + "</b>\n" +
    "рҹҸҰ ШЁШ§ЩҶЪ©: <b>" + botEscape(bot.bank_name) + "</b>\n\n" + botEscape(custom);
  await resellerTelegramApi(env, bot, "sendMessage", {
    chat_id: customer.telegram_id, text, parse_mode: "HTML", disable_web_page_preview: true,
    protect_content: Number(bot.forward_enabled ?? 1) !== 1,
    reply_markup: { inline_keyboard: [[{ text: "рҹ“Ӣ Ъ©ЩҫЫҢ ШҙЩ…Ш§ШұЩҮ Ъ©Ш§ШұШӘ", copy_text: { text: normalizeCardNumber(bot.card_number) } }], [{ text: "Щ„ШәЩҲ ЩҲ ШЁШ§ШІЪҜШҙШӘ", callback_data: "sale:home" }]] }
  });
}

async function sendSalesBlupalInvoiceMessage(env, bot, customer, invoice, title = "ЩҫШұШҜШ§Ш®ШӘ ШўЩҶЩ„Ш§ЫҢЩҶ", detail = "") {
  const providerKey = String(invoice.provider || "").toLowerCase();
  const isPlisio = providerKey === "plisio", isCubepay = providerKey === "cubepay";
  const providerLabel = isCubepay ? "CubePay" : isPlisio ? "Plisio" : "ШЁЩ„ЩҲЩҫШ§Щ„";
  const icon = isCubepay ? "рҹ’і" : isPlisio ? "рҹӘҷ" : "рҹ’ ";
  const exactLine = Number(invoice.final_amount_rial || 0)
    ? (isCubepay ? "Щ…ШЁЩ„Шә ШҜЩӮЫҢЩӮ ЩӮШ§ШЁЩ„ ЩҫШұШҜШ§Ш®ШӘ: <b>" + botMoney(invoice.final_amount_rial) + " ШұЫҢШ§Щ„</b>\n" : !isPlisio ? "Щ…ШЁЩ„Шә ЩҶЩҮШ§ЫҢЫҢ ШЁЩ„ЩҲЩҫШ§Щ„: <b>" + botMoney(invoice.final_amount_rial) + " ШұЫҢШ§Щ„</b>\n" : "")
    : "";
  const help = isCubepay
    ? "Щ…ШЁЩ„Шә ШҜЩӮЫҢЩӮ ЩҶЩ…Ш§ЫҢШҙвҖҢШҜШ§ШҜЩҮвҖҢШҙШҜЩҮ ШҜШұ ШөЩҒШӯЩҮ CubePay ШұШ§ ЩҲШ§ШұЫҢШІ Ъ©ЩҶЫҢШҜШӣ ШЁШ№ШҜ Ш§ШІ CallbackШҢ ШӘШ§ЫҢЫҢШҜ ЩҶЩҮШ§ЫҢЫҢ API Ш§ЩҶШ¬Ш§Щ… Щ…ЫҢвҖҢШҙЩҲШҜ."
    : isPlisio ? "ЩҫШі Ш§ШІ ЩҫШұШҜШ§Ш®ШӘШҢ Callback Ш§Щ…Ш¶Ш§ШҙШҜЩҮ Plisio ШҜШұЫҢШ§ЩҒШӘ ЩҲ ШӯШіШ§ШЁ ШҙЩ…Ш§ ЩҒЩӮШ· ЫҢЪ©вҖҢШЁШ§Шұ ШҙШ§ШұЪҳ Щ…ЫҢвҖҢШҙЩҲШҜ."
    : "ЩҫШі Ш§ШІ ЩҫШұШҜШ§Ш®ШӘШҢ ЩҲШ¶Ш№ЫҢШӘ Ш§ШІ API ШЁЩ„ЩҲЩҫШ§Щ„ Ш§ШіШӘШ№Щ„Ш§Щ… ЩҲ Ш№Щ…Щ„ЫҢШ§ШӘ ШЁЩҮвҖҢШөЩҲШұШӘ Ш®ЩҲШҜЪ©Ш§Шұ Ш§ЩҶШ¬Ш§Щ… Щ…ЫҢвҖҢШҙЩҲШҜ.";
  const text = icon + " <b>" + botEscape(title) + "</b>\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n" +
    (detail ? botEscape(detail) + "\n" : "") +
    "ШҙЩ…Ш§ШұЩҮ ЩҒШ§Ъ©ШӘЩҲШұ: <code>" + botEscape(invoice.invoice_id || invoice.provider_invoice_id || invoice.id) + "</code>\n" +
    "Щ…ШЁЩ„Шә ШіЩҒШ§ШұШҙ: <b>" + botMoney(invoice.amount_toman) + " ШӘЩҲЩ…Ш§ЩҶ</b>\n" + exactLine + "\n" + help;
  await resellerTelegramApi(env, bot, "sendMessage", {
    chat_id: customer.telegram_id, text, parse_mode: "HTML", disable_web_page_preview: true,
    protect_content: Number(bot.forward_enabled ?? 1) !== 1,
    reply_markup: { inline_keyboard: [
      [{ text: icon + " ШЁШ§ШІЪ©ШұШҜЩҶ ШөЩҒШӯЩҮ ЩҫШұШҜШ§Ш®ШӘ " + providerLabel, url: invoice.payment_link }],
      [{ text: "рҹ”„ ШЁШұШұШіЫҢ ЩҲШ¶Ш№ЫҢШӘ ЩҫШұШҜШ§Ш®ШӘ", callback_data: "sale:paystatus:" + invoice.id }],
      [{ text: "рҹ“Ӣ Ъ©ЩҫЫҢ ШҙЩ…Ш§ШұЩҮ ЩҒШ§Ъ©ШӘЩҲШұ", copy_text: { text: String(invoice.invoice_id || invoice.provider_invoice_id || invoice.id) } }],
      [{ text: "рҹҸ  Щ…ЩҶЩҲЫҢ Ш§ШөЩ„ЫҢ", callback_data: "sale:home" }]
    ] }
  });
}

async function salesWalletChargeInstructions(env, bot, customer, amount, options = {}) {
  salesRequireVerifiedPhone(bot, customer);
  await enforceSalesSecurity(env, bot, customer, "wallet_charge", amount);
  const requestId = id("wreq");
  const ts = nowIso();
  const origin = options.origin === "miniapp" ? "miniapp" : "bot";
  await env.PASARGUARD_DB.prepare(`
    INSERT INTO sales_wallet_requests(id,bot_id,customer_id,amount_toman,status,origin,created_at,updated_at)
    VALUES(?,?,?,?,'awaiting_receipt',?,?,?)
  `).bind(requestId, bot.id, customer.id, amount, origin, ts, ts).run();
  const bonusPercent = Math.max(0, Math.min(100, Number(bot.recharge_bonus_percent || 0)));
  const bonusAmount = Math.floor(Number(amount || 0) * bonusPercent / 100);
  const notifyCustomer = options.notifyCustomer !== false && origin !== "miniapp";
  if (notifyCustomer) {
    await salesSessionSet(env, bot.id, customer.telegram_id, "wallet_receipt", { requestId });
    await resellerTelegramApi(env, bot, "sendMessage", {
      chat_id: customer.telegram_id,
      text: "рҹ’і <b>ШҙШ§ШұЪҳ Ъ©ЫҢЩҒ ЩҫЩҲЩ„</b>\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nЩ…ШЁЩ„Шә ЩҫШұШҜШ§Ш®ШӘ: <b>" + botMoney(amount) + " ШӘЩҲЩ…Ш§ЩҶ</b>" +
        (bonusAmount > 0 ? "\nрҹҺү ШЁЩҲЩҶШі ШҙШ§ШұЪҳ: <b>" + botMoney(bonusAmount) + " ШӘЩҲЩ…Ш§ЩҶ</b> (" + bonusPercent + "ЩӘ)\nЩ…ШЁЩ„Шә ЩҶЩҮШ§ЫҢЫҢ Ъ©ЫҢЩҒ ЩҫЩҲЩ„: <b>" + botMoney(Number(amount)+bonusAmount) + " ШӘЩҲЩ…Ш§ЩҶ</b>" : "") +
        "\n\nШҙЩ…Ш§ШұЩҮ Ъ©Ш§ШұШӘ:\n<code>" + botEscape(formatCardNumber(bot.card_number)) + "</code>\nШЁЩҮ ЩҶШ§Щ…: <b>" + botEscape(bot.card_holder) + "</b>\nШЁШ§ЩҶЪ©: <b>" + botEscape(bot.bank_name) + "</b>\n\nЩҫШі Ш§ШІ ЩҲШ§ШұЫҢШІШҢ ШӘШөЩҲЫҢШұ ЫҢШ§ ЩҒШ§ЫҢЩ„ ШұШіЫҢШҜ ШұШ§ Ш§ШұШіШ§Щ„ Ъ©ЩҶЫҢШҜ.",
      parse_mode: "HTML",
      protect_content: Number(bot.forward_enabled ?? 1) !== 1,
      reply_markup: { inline_keyboard: [[{ text: "рҹ“Ӣ Ъ©ЩҫЫҢ ШҙЩ…Ш§ШұЩҮ Ъ©Ш§ШұШӘ", copy_text: { text: normalizeCardNumber(bot.card_number) } }], [{ text: "Щ„ШәЩҲ", callback_data: "sale:home" }]] }
    });
  }
  await salesEvent(env, bot.id, customer.id, "wallet_charge_created", { requestId, amount, bonusAmount, origin });
  await queueReportEvent(env, bot.id, "payments", "ШҜШұШ®ЩҲШ§ШіШӘ ШҙШ§ШұЪҳ Ъ©ЫҢЩҒ ЩҫЩҲЩ„ Ш«ШЁШӘ ШҙШҜ",
    "Щ…ШҙШӘШұЫҢ: <code>" + botEscape(customer.telegram_id) + "</code>\n" +
    "Щ…ШЁЩ„Шә: <b>" + botMoney(amount) + " ШӘЩҲЩ…Ш§ЩҶ</b>" +
    (bonusAmount > 0 ? "\nШЁЩҲЩҶШі Ш§ШӯШӘЩ…Ш§Щ„ЫҢ: <b>" + botMoney(bonusAmount) + " ШӘЩҲЩ…Ш§ЩҶ</b>" : "") +
    "\nШҙЩҶШ§ШіЩҮ: <code>" + botEscape(requestId) + "</code>",
    "wallet-created:" + requestId);
  return { requestId, amountToman: Number(amount), bonusPercent, bonusAmount, origin };
}

function parseSalesMiniAppReceipt(body) {
  const source = String(body.file_base64 || body.file_data || "");
  const match = source.match(/^data:([^;,]+);base64,([A-Za-z0-9+/=\s]+)$/);
  if (!match) throw new Error("ЩҒШ§ЫҢЩ„ ШұШіЫҢШҜ Щ…Ш№ШӘШЁШұ ЩҶЫҢШіШӘ");
  const mimeType = cleanText(match[1].toLowerCase(), 100);
  const allowed = new Set(["image/jpeg", "image/png", "image/webp", "application/pdf"]);
  if (!allowed.has(mimeType)) throw new Error("ЩҒШұЩ…ШӘ ШұШіЫҢШҜ ШЁШ§ЫҢШҜ JPGШҢ PNGШҢ WEBP ЫҢШ§ PDF ШЁШ§ШҙШҜ");
  const compact = match[2].replace(/\s+/g, "");
  if (compact.length > 7_500_000) throw new Error("ШӯШ¬Щ… ШұШіЫҢШҜ ШЁЫҢШҙШӘШұ Ш§ШІ ШӯШҜ Щ…Ш¬Ш§ШІ Ш§ШіШӘ");
  let bytes;
  try { bytes = base64ToBytes(compact); } catch (_) { throw new Error("Ш®ЩҲШ§ЩҶШҜЩҶ ЩҒШ§ЫҢЩ„ ШұШіЫҢШҜ ЩҶШ§Щ…ЩҲЩҒЩӮ ШЁЩҲШҜ"); }
  if (!bytes.length) throw new Error("ЩҒШ§ЫҢЩ„ ШұШіЫҢШҜ Ш®Ш§Щ„ЫҢ Ш§ШіШӘ");
  if (bytes.length > 5 * 1024 * 1024) throw new Error("ШӯШҜШ§Ъ©Ш«Шұ ШӯШ¬Щ… ШұШіЫҢШҜ Ыө Щ…ЪҜШ§ШЁШ§ЫҢШӘ Ш§ШіШӘ");
  const fallbackExt = mimeType === "application/pdf" ? "pdf" : mimeType.split("/")[1].replace("jpeg", "jpg");
  const safeName = cleanText(body.file_name, 160).replace(/[^a-zA-Z0-9._-]/g, "_") || ("receipt." + fallbackExt);
  return { bytes, mimeType, filename: safeName, caption: cleanText(body.caption, 500) };
}

async function sendResellerOwnerUploadedReceipt(env, bot, kind, row, customer, plan, upload) {
  if (!bot.owner_telegram_id) throw new Error("ШҙЩҶШ§ШіЩҮ Щ…Ш§Щ„Ъ© ШұШЁШ§ШӘ Ш«ШЁШӘ ЩҶШҙШҜЩҮ Ш§ШіШӘ");
  const isWallet = kind === "wallet";
  const caption = isWallet
    ? "рҹ’і <b>ШұШіЫҢШҜ ШҙШ§ШұЪҳ Ш§ШІ Щ…ЫҢЩҶЫҢвҖҢШ§Щҫ</b>\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nЩ…ШҙШӘШұЫҢ: <b>" + botEscape(customer.first_name || customer.username || customer.telegram_id) + "</b>\nШҙЩҶШ§ШіЩҮ: <code>" + botEscape(customer.telegram_id) + "</code>\nЩ…ШЁЩ„Шә: <b>" + botMoney(row.amount_toman) + " ШӘЩҲЩ…Ш§ЩҶ</b>\nШҜШұШ®ЩҲШ§ШіШӘ: <code>" + botEscape(row.id) + "</code>"
    : "рҹ§ҫ <b>ШұШіЫҢШҜ ШіЩҒШ§ШұШҙ Ш§ШІ Щ…ЫҢЩҶЫҢвҖҢШ§Щҫ</b>\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nЩ…ШҙШӘШұЫҢ: <b>" + botEscape(customer.first_name || customer.username || customer.telegram_id) + "</b>\nШҙЩҶШ§ШіЩҮ: <code>" + botEscape(customer.telegram_id) + "</code>\nЩҶЩҲШ№: <b>" + (row.order_type === "renewal" ? "ШӘЩ…ШҜЫҢШҜ ШіШұЩҲЫҢШі" : row.order_type === "volume" ? "Ш§ЩҒШІШ§ЫҢШҙ ШӯШ¬Щ…" : "Ш®ШұЫҢШҜ ШіШұЩҲЫҢШі") + "</b>\nЩҫЩ„ЩҶ: <b>" + botEscape(plan?.title || plan?.plan_title || "ЩҫЩ„ЩҶ ЩҒШұЩҲШҙ") + "</b>\nЩ…ШЁЩ„Шә: <b>" + botMoney(row.amount_toman) + " ШӘЩҲЩ…Ш§ЩҶ</b>\nШіЩҒШ§ШұШҙ: <code>" + botEscape(row.id) + "</code>";
  const replyMarkup = isWallet
    ? { inline_keyboard: [[{ text: "вң… ШӘШЈЫҢЫҢШҜ ШҙШ§ШұЪҳ", callback_data: "owner:wallet:approve:" + row.id }, { text: "вқҢ ШұШҜ", callback_data: "owner:wallet:reject:" + row.id }], [{ text: "вҶ©пёҸ ШҜШұШ®ЩҲШ§ШіШӘвҖҢЩҮШ§ЫҢ ШҙШ§ШұЪҳ", callback_data: "owner:wallets" }]] }
    : { inline_keyboard: [[{ text: "вң… ШӘШЈЫҢЫҢШҜ ЩҲ ШӘШӯЩҲЫҢЩ„", callback_data: "owner:approve:" + row.id }, { text: "вқҢ ШұШҜ ШұШіЫҢШҜ", callback_data: "owner:reject:" + row.id }], [{ text: "вҶ©пёҸ ШіЩҒШ§ШұШҙвҖҢЩҮШ§", callback_data: "owner:orders" }]] };
  const usePhoto = ["image/jpeg", "image/png"].includes(upload.mimeType);
  const method = usePhoto ? "sendPhoto" : "sendDocument";
  const field = usePhoto ? "photo" : "document";
  const form = new FormData();
  form.set("chat_id", String(bot.owner_telegram_id));
  form.set(field, new Blob([upload.bytes], { type: upload.mimeType }), upload.filename);
  form.set("caption", caption + (upload.caption ? "\n\nШӘЩҲШ¶ЫҢШӯ Щ…ШҙШӘШұЫҢ: " + botEscape(upload.caption) : ""));
  form.set("parse_mode", "HTML");
  form.set("reply_markup", JSON.stringify(replyMarkup));
  const token = await resellerBotToken(env, bot);
  const response = await fetch("https://api.telegram.org/bot" + token + "/" + method, { method: "POST", body: form });
  const data = await response.json().catch(() => ({}));
  if (!response.ok || data.ok === false) throw new Error(data.description || "Ш§ШұШіШ§Щ„ ШұШіЫҢШҜ ШЁШұШ§ЫҢ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ЩҶШ§Щ…ЩҲЩҒЩӮ ШЁЩҲШҜ");
  const result = data.result || {};
  const fileId = usePhoto
    ? String((Array.isArray(result.photo) && result.photo.length ? result.photo[result.photo.length - 1].file_id : "") || "")
    : String(result.document?.file_id || "");
  if (!fileId) throw new Error("ШҙЩҶШ§ШіЩҮ ЩҒШ§ЫҢЩ„ ШұШіЫҢШҜ Ш§ШІ ШӘЩ„ЪҜШұШ§Щ… ШҜШұЫҢШ§ЩҒШӘ ЩҶШҙШҜ");
  return { fileId, fileType: usePhoto ? "photo" : "document", messageId: String(result.message_id || "") };
}

async function submitSalesMiniAppReceipt(env, bot, customer, body) {
  const targetType = body.target_type === "wallet" ? "wallet" : "order";
  const targetId = cleanText(body.target_id, 100);
  if (!targetId) throw new Error("ШҙЩҶШ§ШіЩҮ ЩҫШұШҜШ§Ш®ШӘ Щ…ШҙШ®Шө ЩҶЫҢШіШӘ");
  const upload = parseSalesMiniAppReceipt(body);
  const receiptFingerprint = await salesReceiptFingerprint(upload.bytes);
  await ensureUniqueSalesReceipt(env, bot, customer, receiptFingerprint, targetType, targetId);
  if (targetType === "order") {
    const row = await env.PASARGUARD_DB.prepare(`
      SELECT o.*,p.title AS plan_title,p.data_limit_bytes,p.duration_days
      FROM sales_orders o JOIN sales_plans p ON p.id=o.plan_id
      WHERE o.id=? AND o.bot_id=? AND o.customer_id=? AND o.origin='miniapp'
    `).bind(targetId, bot.id, customer.id).first();
    if (!row || row.status !== "awaiting_receipt") throw new Error("Ш§ЫҢЩҶ ШіЩҒШ§ШұШҙ ШўЩ…Ш§ШҜЩҮ ШҜШұЫҢШ§ЩҒШӘ ШұШіЫҢШҜ ЩҶЫҢШіШӘ");
    const claim = await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='receipt_uploading',updated_at=? WHERE id=? AND status='awaiting_receipt'")
      .bind(nowIso(), row.id).run();
    if (!Number(claim?.meta?.changes || 0)) throw new Error("ШұШіЫҢШҜ Ш§ЫҢЩҶ ШіЩҒШ§ШұШҙ ЩҮЩ…вҖҢШІЩ…Ш§ЩҶ ШҜШұ ШӯШ§Щ„ Ш«ШЁШӘ Ш§ШіШӘ");
    try {
      const media = await sendResellerOwnerUploadedReceipt(env, bot, "order", row, customer, { title: row.plan_title }, upload);
      await env.PASARGUARD_DB.prepare(`
        UPDATE sales_orders SET status='pending_review',receipt_file_id=?,receipt_file_type=?,receipt_message_id=?,receipt_caption=?,receipt_unique_id=?,updated_at=?
        WHERE id=? AND status='receipt_uploading'
      `).bind(media.fileId, media.fileType, media.messageId, upload.caption, receiptFingerprint, nowIso(), row.id).run();
      await salesEvent(env, bot.id, customer.id, "miniapp_receipt_submitted", { orderId: row.id });
      return { targetType, targetId: row.id, status: "pending_review" };
    } catch (error) {
      await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='awaiting_receipt',updated_at=? WHERE id=? AND status='receipt_uploading'").bind(nowIso(), row.id).run();
      throw error;
    }
  }
  const row = await env.PASARGUARD_DB.prepare(`
    SELECT * FROM sales_wallet_requests WHERE id=? AND bot_id=? AND customer_id=? AND origin='miniapp'
  `).bind(targetId, bot.id, customer.id).first();
  if (!row || row.status !== "awaiting_receipt") throw new Error("Ш§ЫҢЩҶ ШҜШұШ®ЩҲШ§ШіШӘ ШҙШ§ШұЪҳ ШўЩ…Ш§ШҜЩҮ ШҜШұЫҢШ§ЩҒШӘ ШұШіЫҢШҜ ЩҶЫҢШіШӘ");
  const claim = await env.PASARGUARD_DB.prepare("UPDATE sales_wallet_requests SET status='receipt_uploading',updated_at=? WHERE id=? AND status='awaiting_receipt'")
    .bind(nowIso(), row.id).run();
  if (!Number(claim?.meta?.changes || 0)) throw new Error("ШұШіЫҢШҜ Ш§ЫҢЩҶ ШҙШ§ШұЪҳ ЩҮЩ…вҖҢШІЩ…Ш§ЩҶ ШҜШұ ШӯШ§Щ„ Ш«ШЁШӘ Ш§ШіШӘ");
  try {
    const media = await sendResellerOwnerUploadedReceipt(env, bot, "wallet", row, customer, null, upload);
    await env.PASARGUARD_DB.prepare(`
      UPDATE sales_wallet_requests SET status='pending_review',receipt_file_id=?,receipt_file_type=?,receipt_message_id=?,receipt_caption=?,receipt_unique_id=?,updated_at=?
      WHERE id=? AND status='receipt_uploading'
    `).bind(media.fileId, media.fileType, media.messageId, upload.caption, receiptFingerprint, nowIso(), row.id).run();
    await salesEvent(env, bot.id, customer.id, "miniapp_wallet_receipt_submitted", { requestId: row.id });
    return { targetType, targetId: row.id, status: "pending_review" };
  } catch (error) {
    await env.PASARGUARD_DB.prepare("UPDATE sales_wallet_requests SET status='awaiting_receipt',updated_at=? WHERE id=? AND status='receipt_uploading'").bind(nowIso(), row.id).run();
    throw error;
  }
}

async function sendMainBotMedia(env, method, chatId, bytes, filename, mimeType, caption, replyMarkup) {
  const settings = await getSettings(env);
  if (!settings.bot_token) throw new Error("ШӘЩҲЪ©ЩҶ ШұШЁШ§ШӘ Ш§ШөЩ„ЫҢ ШӘЩҶШёЫҢЩ… ЩҶШҙШҜЩҮ Ш§ШіШӘ");
  const form = new FormData();
  form.set("chat_id", String(chatId));
  form.set(method === "sendPhoto" ? "photo" : "document", new Blob([bytes], { type: mimeType || "application/octet-stream" }), filename || "receipt");
  form.set("caption", caption);
  form.set("parse_mode", "HTML");
  form.set("reply_markup", JSON.stringify(replyMarkup));
  const response = await fetch("https://api.telegram.org/bot" + settings.bot_token + "/" + method, { method: "POST", body: form });
  const data = await response.json().catch(() => ({}));
  if (!response.ok || data.ok === false) throw new Error(data.description || "Ш§ШұШіШ§Щ„ ШұШіЫҢШҜ ШЁШұШ§ЫҢ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ЩҶШ§Щ…ЩҲЩҒЩӮ ШЁЩҲШҜ");
  return data;
}

async function notifySalesOrderOwner(env, bot, order, customer, plan) {
  const caption = "рҹ§ҫ <b>ШұШіЫҢШҜ Ш¬ШҜЫҢШҜ ШұШЁШ§ШӘ ЩҒШұЩҲШҙ</b>\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n" +
    "ШЁШұЩҶШҜ: <b>" + botEscape(bot.brand_name) + "</b>\n" +
    "Щ…ШҙШӘШұЫҢ: <b>" + botEscape(customer.first_name || customer.username || customer.telegram_id) + "</b>\n" +
    "ШҙЩҶШ§ШіЩҮ: <code>" + botEscape(customer.telegram_id) + "</code>\n" +
    "ЩҶЩҲШ№: <b>" + (order.order_type === "renewal" ? "ШӘЩ…ШҜЫҢШҜ ШіШұЩҲЫҢШі" : order.order_type === "volume" ? "Ш§ЩҒШІШ§ЫҢШҙ ШӯШ¬Щ…" : "Ш®ШұЫҢШҜ ШіШұЩҲЫҢШі") + "</b>\n" +
    "ЩҫЩ„ЩҶ: <b>" + botEscape(plan.title || plan.plan_title || "ЩҫЩ„ЩҶ ЩҒШұЩҲШҙ") + "</b>\n" +
    "Щ…ШЁЩ„Шә: <b>" + botMoney(order.amount_toman) + " ШӘЩҲЩ…Ш§ЩҶ</b>\n" +
    "ШіЩҒШ§ШұШҙ: <code>" + botEscape(order.id) + "</code>";
  const replyMarkup = { inline_keyboard: [[
    { text: "вң… ШӘШЈЫҢЫҢШҜ ЩҲ ШӘШӯЩҲЫҢЩ„", callback_data: "bot:sales:approve:" + order.id },
    { text: "вқҢ ШұШҜ ШұШіЫҢШҜ", callback_data: "bot:sales:reject:" + order.id }
  ]] };
  let mediaSent = false;
  try {
    const token = await resellerBotToken(env, bot);
    const fileInfo = await telegramApiWithToken(token, "getFile", { file_id: order.receipt_file_id });
    const filePath = fileInfo?.result?.file_path;
    if (filePath) {
      const response = await fetch("https://api.telegram.org/file/bot" + token + "/" + filePath);
      if (response.ok) {
        const bytes = await response.arrayBuffer();
        const ext = String(filePath).split(".").pop() || (order.receipt_file_type === "photo" ? "jpg" : "bin");
        const method = order.receipt_file_type === "photo" ? "sendPhoto" : "sendDocument";
        const mime = response.headers.get("content-type") || (method === "sendPhoto" ? "image/jpeg" : "application/octet-stream");
        await sendMainBotMedia(env, method, bot.owner_telegram_id, bytes, "receipt." + ext, mime, caption, replyMarkup);
        mediaSent = true;
      }
    }
  } catch (error) {
    await audit(env, bot.user_id, "sales_receipt_media_forward_failed", { orderId: order.id, message: error.message });
  }
  if (!mediaSent) {
    try {
      if (order.receipt_message_id && Number(bot.forward_enabled ?? 1) === 1) {
        await resellerTelegramApi(env, bot, "forwardMessage", {
          chat_id: bot.owner_telegram_id,
          from_chat_id: customer.telegram_id,
          message_id: Number(order.receipt_message_id)
        });
      }
    } catch (_) {}
    await telegramApi(env, "sendMessage", { chat_id: bot.owner_telegram_id, text: caption, parse_mode: "HTML", reply_markup: replyMarkup });
  }
}

async function notifySalesWalletRequestOwner(env, bot, requestRow, customer) {
  const caption = "рҹ’і <b>ШұШіЫҢШҜ ШҙШ§ШұЪҳ Ъ©ЫҢЩҒ ЩҫЩҲЩ„ Щ…ШҙШӘШұЫҢ</b>\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n" +
    "ШЁШұЩҶШҜ: <b>" + botEscape(bot.brand_name) + "</b>\n" +
    "Щ…ШҙШӘШұЫҢ: <b>" + botEscape(customer.first_name || customer.username || customer.telegram_id) + "</b>\n" +
    "ШҙЩҶШ§ШіЩҮ: <code>" + botEscape(customer.telegram_id) + "</code>\n" +
    "Щ…ШЁЩ„Шә ШҙШ§ШұЪҳ: <b>" + botMoney(requestRow.amount_toman) + " ШӘЩҲЩ…Ш§ЩҶ</b>\n" +
    "ШҜШұШ®ЩҲШ§ШіШӘ: <code>" + botEscape(requestRow.id) + "</code>";
  const replyMarkup = { inline_keyboard: [[
    { text: "вң… ШӘШЈЫҢЫҢШҜ ШҙШ§ШұЪҳ", callback_data: "bot:sales:wallet:approve:" + requestRow.id },
    { text: "вқҢ ШұШҜ", callback_data: "bot:sales:wallet:reject:" + requestRow.id }
  ]] };
  let mediaSent = false;
  try {
    const token = await resellerBotToken(env, bot);
    const fileInfo = await telegramApiWithToken(token, "getFile", { file_id: requestRow.receipt_file_id });
    const filePath = fileInfo?.result?.file_path;
    if (filePath) {
      const response = await fetch("https://api.telegram.org/file/bot" + token + "/" + filePath);
      if (response.ok) {
        const bytes = await response.arrayBuffer();
        const method = requestRow.receipt_file_type === "photo" ? "sendPhoto" : "sendDocument";
        const ext = String(filePath).split(".").pop() || "bin";
        await sendMainBotMedia(env, method, bot.owner_telegram_id, bytes, "wallet-receipt." + ext,
          response.headers.get("content-type") || "application/octet-stream", caption, replyMarkup);
        mediaSent = true;
      }
    }
  } catch (_) {}
  if (!mediaSent) await telegramApi(env, "sendMessage", { chat_id: bot.owner_telegram_id, text: caption, parse_mode: "HTML", reply_markup: replyMarkup });
}

async function adjustSalesCustomerBalance(env, botId, customerId, amount, type, refType, refId, description) {
  const value = Number(amount || 0);
  if (!Number.isSafeInteger(value) || value === 0) throw new Error("Щ…ШЁЩ„Шә ШӘШәЫҢЫҢШұ Щ…ЩҲШ¬ЩҲШҜЫҢ Щ…Ш№ШӘШЁШұ ЩҶЫҢШіШӘ");
  const ts = nowIso();
  const result = value > 0
    ? await env.PASARGUARD_DB.prepare("UPDATE sales_customers SET wallet_balance=wallet_balance+?,updated_at=? WHERE id=? AND bot_id=?")
      .bind(value, ts, customerId, botId).run()
    : await env.PASARGUARD_DB.prepare("UPDATE sales_customers SET wallet_balance=wallet_balance+?,updated_at=? WHERE id=? AND bot_id=? AND wallet_balance>=?")
      .bind(value, ts, customerId, botId, Math.abs(value)).run();
  if (!Number(result?.meta?.changes || 0)) throw new Error(value < 0 ? "Щ…ЩҲШ¬ЩҲШҜЫҢ Ъ©ЫҢЩҒ ЩҫЩҲЩ„ Ъ©Ш§ЩҒЫҢ ЩҶЫҢШіШӘ" : "ШӘШәЫҢЫҢШұ Щ…ЩҲШ¬ЩҲШҜЫҢ Ш§ЩҶШ¬Ш§Щ… ЩҶШҙШҜ");
  const fresh = await env.PASARGUARD_DB.prepare("SELECT wallet_balance FROM sales_customers WHERE id=?").bind(customerId).first();
  await env.PASARGUARD_DB.prepare(`
    INSERT INTO sales_customer_ledger(id,bot_id,customer_id,type,amount,balance_after,ref_type,ref_id,description,created_at)
    VALUES(?,?,?,?,?,?,?,?,?,?)
  `).bind(id("cled"), botId, customerId, type, value, Number(fresh?.wallet_balance || 0), refType || null, refId || null, cleanText(description, 500), ts).run();
  return Number(fresh?.wallet_balance || 0);
}

async function registerSalesReceipt(env, bot, customer, message, session) {
  const order = await env.PASARGUARD_DB.prepare(`
    SELECT o.*,p.title AS plan_title,p.data_limit_bytes,p.duration_days,p.price_toman
    FROM sales_orders o JOIN sales_plans p ON p.id=o.plan_id
    WHERE o.id=? AND o.bot_id=? AND o.customer_id=? AND o.status='awaiting_receipt'
  `).bind(session.data.orderId, bot.id, customer.id).first();
  if (!order) throw new Error("ШіЩҒШ§ШұШҙ ЩҒШ№Ш§Щ„ ШЁШұШ§ЫҢ ШҜШұЫҢШ§ЩҒШӘ ШұШіЫҢШҜ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  let fileId = "", fileType = "", fileUniqueId = "";
  if (Array.isArray(message.photo) && message.photo.length) { const media = message.photo[message.photo.length - 1]; fileId = String(media.file_id || ""); fileUniqueId = String(media.file_unique_id || ""); fileType = "photo"; }
  else if (message.document?.file_id) { fileId = String(message.document.file_id); fileUniqueId = String(message.document.file_unique_id || ""); fileType = "document"; }
  if (!fileId) throw new Error("Щ„Ш·ЩҒШ§ЩӢ ШӘШөЩҲЫҢШұ ЫҢШ§ ЩҒШ§ЫҢЩ„ ШұШіЫҢШҜ ШұШ§ Ш§ШұШіШ§Щ„ Ъ©ЩҶЫҢШҜ");
  const receiptFingerprint = fileUniqueId ? "tg:" + fileUniqueId : "";
  await ensureUniqueSalesReceipt(env, bot, customer, receiptFingerprint, "order", order.id);
  const result = await env.PASARGUARD_DB.prepare(`
    UPDATE sales_orders SET status='pending_review',receipt_file_id=?,receipt_file_type=?,receipt_message_id=?,
      receipt_caption=?,receipt_unique_id=?,updated_at=? WHERE id=? AND status='awaiting_receipt'
  `).bind(fileId, fileType, String(message.message_id || ""), cleanText(message.caption, 500), receiptFingerprint, nowIso(), order.id).run();
  if (!Number(result?.meta?.changes || 0)) throw new Error("Ш§ЫҢЩҶ ШұШіЫҢШҜ ЩӮШЁЩ„Ш§ЩӢ Ш«ШЁШӘ ШҙШҜЩҮ Ш§ШіШӘ");
  await salesSessionClear(env, bot.id, customer.telegram_id);
  const fullBot = await getResellerBotById(env, bot.id);
  const freshOrder = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_orders WHERE id=?").bind(order.id).first();
  await notifySalesOrderOwner(env, fullBot, freshOrder, customer, order);
  await resellerTelegramApi(env, bot, "sendMessage", {
    chat_id: customer.telegram_id,
    text: "вң… <b>ШұШіЫҢШҜ ШҙЩ…Ш§ Ш«ШЁШӘ ШҙШҜ</b>\nЩҫШі Ш§ШІ ШЁШұШұШіЫҢ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮШҢ ЩҶШӘЫҢШ¬ЩҮ ЩҮЩ…ЫҢЩҶвҖҢШ¬Ш§ Ш§Ш№Щ„Ш§Щ… Щ…ЫҢвҖҢШҙЩҲШҜ.",
    parse_mode: "HTML",
    reply_markup: { inline_keyboard: [[{ text: "рҹ“Ұ ШіЩҒШ§ШұШҙвҖҢЩҮШ§ЫҢ Щ…ЩҶ", callback_data: "sale:orders" }]] }
  });
  await salesEvent(env, bot.id, customer.id, "receipt_submitted", { orderId: order.id });
}

