function normalizePlisioStatus(value) {
  const status = String(value || "new").trim().toLowerCase();
  if (status === "completed") return "PAID";
  if (status === "expired") return "EXPIRED";
  if (status === "cancelled" || status === "cancelled duplicate") return "CANCELED";
  if (status === "error" || status === "mismatch") return "FAILED";
  return "PENDING";
}

let sharedPlisioFxRefreshPromise = null;

function normalizeDigitsForFx(value) {
  const fa = "Ы°ЫұЫІЫіЫҙЫөЫ¶Ы·ЫёЫ№", ar = "Щ ЩЎЩўЩЈЩӨЩҘЩҰЩ§ЩЁЩ©";
  return String(value ?? "")
    .replace(/[Ы°-Ы№]/g, d => String(fa.indexOf(d)))
    .replace(/[Щ -Щ©]/g, d => String(ar.indexOf(d)))
    .replace(/[,Щ¬\s]/g, "")
    .replace(/[^0-9.\-]/g, "");
}

function parseSharedFxNumber(value) {
  const parsed = Number(normalizeDigitsForFx(value));
  return Number.isFinite(parsed) ? parsed : 0;
}

function sharedPlisioRateMode(settings) {
  return String(settings?.plisio_rate_mode || "auto").toLowerCase() === "manual" ? "manual" : "auto";
}

function sharedFxCacheAgeMinutes(settings) {
  const ts = Date.parse(settings?.plisio_fx_last_fetched_at || "");
  return Number.isFinite(ts) ? Math.max(0, (Date.now() - ts) / 60000) : Number.POSITIVE_INFINITY;
}

async function saveSharedFxState(env, values) {
  const ts = nowIso();
  const statements = Object.entries(values).map(([key, value]) => env.PASARGUARD_DB.prepare(
    "INSERT INTO app_settings(key,value,updated_at) VALUES(?,?,?) ON CONFLICT(key) DO UPDATE SET value=excluded.value,updated_at=excluded.updated_at"
  ).bind(key, String(value), ts));
  if (statements.length) await env.PASARGUARD_DB.batch(statements);
  settingsCache = null;
  settingsCacheAt = 0;
}

async function sharedPlisioFxApiKey(settings, env) {
  const raw = String(settings?.plisio_fx_api_key || "").trim();
  if (!raw) throw new Error("API Key ЩҶШұШ® ШҜЩ„Ш§Шұ ШҜШұ ШұШЁШ§ШӘ Щ…ШұЪ©ШІЫҢ Ш«ШЁШӘ ЩҶШҙШҜЩҮ Ш§ШіШӘ");
  if (!raw.startsWith("enc:")) return raw;
  try {
    const value = await decryptSecret(raw.slice(4), env);
    if (!value) throw new Error("empty");
    return value;
  } catch (_) {
    throw new Error("API Key ЩҶШұШ® ШҜЩ„Ш§Шұ ЩӮШ§ШЁЩ„ ШЁШ§ШІЫҢШ§ШЁЫҢ ЩҶЫҢШіШӘШӣ Щ…ШҜЫҢШұ Щ…ШұЪ©ШІЫҢ ШЁШ§ЫҢШҜ ШўЩҶ ШұШ§ ШҜЩҲШЁШ§ШұЩҮ Ш«ШЁШӘ Ъ©ЩҶШҜ");
  }
}

async function fetchSharedNavasanRate(settings, env) {
  const apiKey = await sharedPlisioFxApiKey(settings, env);
  const item = cleanText(settings?.plisio_fx_item || "usd_sell", 50).toLowerCase() || "usd_sell";
  const url = new URL("https://api.navasan.tech/latest/");
  url.searchParams.set("api_key", apiKey);
  url.searchParams.set("item", item);
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), 10000);
  let response;
  try { response = await fetch(url.toString(), { headers: { accept: "application/json" }, signal: controller.signal }); }
  finally { clearTimeout(timer); }
  const data = await response.json().catch(() => ({}));
  if (!response.ok) throw new Error(cleanText(data?.message || data?.error || ("Navasan HTTP " + response.status), 500));
  const entry = data?.[item] ?? data?.data?.[item] ?? data?.result?.[item] ?? data;
  const raw = parseSharedFxNumber(entry?.value ?? entry?.price ?? entry?.rate ?? entry);
  if (!Number.isFinite(raw) || raw <= 0) throw new Error("ЩҶШұШ® Щ…Ш№ШӘШЁШұ Ш§ШІ ШіШұЩҲЫҢШі ЩҶШұШ® Ш§ШұШІ ШҜШұЫҢШ§ЩҒШӘ ЩҶШҙШҜ");
  const unit = String(settings?.plisio_fx_unit || "toman").toLowerCase();
  const baseToman = unit === "rial" ? raw / 10 : raw;
  const markup = Math.max(-20, Math.min(50, Number(settings?.plisio_fx_markup_percent || 0)));
  const rateToman = Math.round(baseToman * (1 + markup / 100));
  if (!Number.isFinite(rateToman) || rateToman < 1000 || rateToman > 100000000) throw new Error("ЩҶШұШ® ШҜШұЫҢШ§ЩҒШӘЫҢ Ш®Ш§ШұШ¬ Ш§ШІ ШЁШ§ШІЩҮ Ш§Щ…ЩҶ Ш§ШіШӘ");
  return { rate_toman: rateToman, raw_rate: raw, source: "navasan", stale: false };
}

async function refreshSharedPlisioFxRate(env, { force = false } = {}) {
  const initial = await getSettings(env);
  const refreshMinutes = Math.max(5, Math.min(1440, Number(initial.plisio_fx_refresh_minutes || 15)));
  const cached = Number(initial.plisio_fx_last_rate_toman || 0);
  if (!force && cached > 0 && sharedFxCacheAgeMinutes(initial) < refreshMinutes) {
    return { rate_toman: cached, source: "cache", stale: false, fetched_at: initial.plisio_fx_last_fetched_at || "" };
  }
  if (sharedPlisioFxRefreshPromise) return sharedPlisioFxRefreshPromise;
  sharedPlisioFxRefreshPromise = (async () => {
    try {
      const result = await fetchSharedNavasanRate(initial, env);
      const fetchedAt = nowIso();
      await saveSharedFxState(env, {
        plisio_fx_last_rate_toman: String(result.rate_toman),
        plisio_fx_last_raw_rate: String(result.raw_rate),
        plisio_fx_last_fetched_at: fetchedAt,
        plisio_fx_last_error: "",
        plisio_source_currency: "USD"
      });
      return { ...result, fetched_at: fetchedAt };
    } catch (error) {
      await saveSharedFxState(env, { plisio_fx_last_error: cleanText(error.message, 800) }).catch(() => null);
      const current = await getSettings(env);
      const maxStale = Math.max(15, Math.min(10080, Number(current.plisio_fx_max_stale_minutes || 1440)));
      const last = Number(current.plisio_fx_last_rate_toman || 0);
      if (last > 0 && sharedFxCacheAgeMinutes(current) <= maxStale) return { rate_toman: last, source: "stale_cache", stale: true, warning: error.message, fetched_at: current.plisio_fx_last_fetched_at || "" };
      throw error;
    } finally { sharedPlisioFxRefreshPromise = null; }
  })();
  return sharedPlisioFxRefreshPromise;
}

function scheduleSalesInvoiceBackground(ctx, task, label = "sales invoice background task") {
  const guarded = Promise.resolve(task).catch(error => console.error(label, error));
  if (ctx && typeof ctx.waitUntil === "function") ctx.waitUntil(guarded);
  return guarded;
}

async function resolveResellerPlisioFxRateForInvoice(env, bot, ctx = null) {
  const settings = await getSettings(env);
  if (sharedPlisioRateMode(settings) === "auto") {
    const refreshMinutes = Math.max(5, Math.min(1440, Number(settings.plisio_fx_refresh_minutes || 15)));
    const maxStale = Math.max(15, Math.min(10080, Number(settings.plisio_fx_max_stale_minutes || 1440)));
    const age = sharedFxCacheAgeMinutes(settings);
    const cached = Number(settings.plisio_fx_last_rate_toman || 0);
    if (cached > 0 && age <= maxStale) {
      if (age >= refreshMinutes) scheduleSalesInvoiceBackground(ctx, refreshSharedPlisioFxRate(env, { force: true }), "shared Plisio FX refresh failed");
      return { rate_toman: cached, source: age < refreshMinutes ? "cache" : "stale_cache_refreshing", stale: age >= refreshMinutes, fetched_at: settings.plisio_fx_last_fetched_at || "" };
    }
    const localFallback = Number(bot?.plisio_toman_per_source_unit || 0);
    const centralFallback = Number(settings?.plisio_toman_per_source_unit || 0);
    const fallback = localFallback > 0 ? localFallback : centralFallback;
    if (fallback > 0) {
      scheduleSalesInvoiceBackground(ctx, refreshSharedPlisioFxRate(env, { force: true }), "shared Plisio fallback refresh failed");
      return { rate_toman: fallback, source: localFallback > 0 ? "reseller_manual_fallback_refreshing" : "central_manual_fallback_refreshing", stale: true, fetched_at: "" };
    }
    return refreshSharedPlisioFxRate(env, { force: true });
  }
  const local = Number(bot?.plisio_toman_per_source_unit || 0);
  const central = Number(settings?.plisio_toman_per_source_unit || 0);
  const rate = local > 0 ? local : central;
  if (rate <= 0) throw new Error("ЩҶШұШ® ШҜШіШӘЫҢ ШҜЩ„Ш§Шұ Ш«ШЁШӘ ЩҶШҙШҜЩҮ Ш§ШіШӘ");
  return { rate_toman: rate, source: local > 0 ? "reseller_manual" : "central_manual", stale: false };
}

async function resolveResellerPlisioFxRate(env, bot, { force = false } = {}) {
  const settings = await getSettings(env);
  if (sharedPlisioRateMode(settings) === "auto") {
    try { return await refreshSharedPlisioFxRate(env, { force }); }
    catch (error) {
      const localFallback = Number(bot?.plisio_toman_per_source_unit || 0);
      const centralFallback = Number(settings?.plisio_toman_per_source_unit || 0);
      const fallback = localFallback > 0 ? localFallback : centralFallback;
      if (fallback > 0) return { rate_toman: fallback, source: localFallback > 0 ? "reseller_manual_fallback" : "central_manual_fallback", stale: true, warning: error.message };
      throw error;
    }
  }
  const local = Number(bot?.plisio_toman_per_source_unit || 0);
  const central = Number(settings?.plisio_toman_per_source_unit || 0);
  const rate = local > 0 ? local : central;
  if (rate <= 0) throw new Error("ЩҶШұШ® ШҜШіШӘЫҢ ШҜЩ„Ш§Шұ Ш«ШЁШӘ ЩҶШҙШҜЩҮ Ш§ШіШӘ");
  return { rate_toman: rate, source: local > 0 ? "reseller_manual" : "central_manual", stale: false };
}

function resellerPlisioConfigured(bot) {
  return Number(bot?.plisio_enabled || 0) === 1 && !!String(bot?.plisio_api_key_enc || "").trim();
}

async function resellerPlisioApiKey(env, bot) {
  const encrypted = String(bot?.plisio_api_key_enc || "").trim();
  if (!encrypted) throw new Error("Secret Key ШҜШұЪҜШ§ЩҮ Plisio ШЁШұШ§ЫҢ Ш§ЫҢЩҶ ШұШЁШ§ШӘ Ш«ШЁШӘ ЩҶШҙШҜЩҮ Ш§ШіШӘ");
  const cacheKey = String(bot?.id || "") + ":" + encrypted;
  const cached = resellerPlisioSecretCache.get(cacheKey);
  if (cached?.value && Date.now() - cached.at < PLISIO_SECRET_CACHE_TTL_MS) return cached.value;
  try {
    const value = await decryptSecret(encrypted, env);
    if (!value) throw new Error("empty");
    if (resellerPlisioSecretCache.size > 500) resellerPlisioSecretCache.clear();
    resellerPlisioSecretCache.set(cacheKey, { value, at: Date.now() });
    return value;
  } catch (_) {
    throw new Error("Secret Key ШҜШұЪҜШ§ЩҮ Plisio ЩӮШ§ШЁЩ„ ШЁШ§ШІЫҢШ§ШЁЫҢ ЩҶЫҢШіШӘШӣ ШўЩҶ ШұШ§ ШҜЩҲШЁШ§ШұЩҮ Ш«ШЁШӘ Ъ©ЩҶЫҢШҜ");
  }
}

function resellerPlisioSourceAmount(amountToman, rateToman) {
  const rate = Number(rateToman || 0);
  if (!Number.isFinite(rate) || rate <= 0) throw new Error("ЩҶШұШ® ШӘШЁШҜЫҢЩ„ ШҜЩ„Ш§Шұ ШЁЩҮ ШӘЩҲЩ…Ш§ЩҶ ШҜШұ ШҜШіШӘШұШі ЩҶЫҢШіШӘ");
  const value = Number((Number(amountToman || 0) / rate).toFixed(2));
  if (!Number.isFinite(value) || value < 0.01) throw new Error("Щ…ШЁЩ„Шә ЩҒШ§Ъ©ШӘЩҲШұ ЩҫШі Ш§ШІ ШӘШЁШҜЫҢЩ„ Ъ©Щ…ШӘШұ Ш§ШІ ШӯШҜ Щ…Ш¬Ш§ШІ Plisio Ш§ШіШӘ");
  return value;
}

function resellerPlisioUrls(origin, bot) {
  const base = String(origin || "").replace(/\/+$/, "");
  const botId = encodeURIComponent(bot.id);
  return {
    callback_url: base + "/sales-payments/" + botId + "/plisio/callback?json=true",
    return_url: base + "/sales-payments/" + botId + "/plisio/return",
    miniapp_url: base + "/sales-app/" + botId
  };
}

async function resellerPlisioRequest(env, bot, path, params = {}, secretOverride = "") {
  if (path !== "/invoices/new") throw new Error("Щ…ШіЫҢШұ Plisio Щ…Ш¬Ш§ШІ ЩҶЫҢШіШӘ");
  const secret = secretOverride || await resellerPlisioApiKey(env, bot);
  const url = new URL("https://api.plisio.net/api/v1" + path);
  for (const [key, value] of Object.entries(params || {})) {
    if (value !== undefined && value !== null && String(value) !== "") url.searchParams.set(key, String(value));
  }
  url.searchParams.set("api_key", secret);
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), 12000);
  let response;
  try {
    response = await fetch(url.toString(), { method: "GET", headers: { accept: "application/json" }, signal: controller.signal });
  } finally {
    clearTimeout(timer);
  }
  const data = await response.json().catch(() => ({}));
  if (!response.ok || data?.status !== "success") {
    const message = cleanText(data?.data?.message || data?.message || data?.error || ("Plisio HTTP " + response.status), 700);
    const error = new Error(message || "Ш®Ш·Ш§ЫҢ ЩҶШ§ШҙЩҶШ§Ш®ШӘЩҮ Plisio");
    error.code = "PLISIO_ERROR";
    error.status = response.status;
    throw error;
  }
  return data.data || {};
}

function resellerPlisioOperationData(payload) {
  const data = payload?.data && typeof payload.data === "object" ? payload.data : (payload || {});
  const params = data?.params && typeof data.params === "object" ? data.params : {};
  return {
    txn_id: cleanText(data.txn_id || data.id || payload?.txn_id, 160),
    order_number: cleanText(data.order_number || params.order_number || payload?.order_number, 160),
    status: String(data.status || payload?.status || "new"),
    source_amount: Number(data.source_amount ?? params.source_amount ?? payload?.source_amount),
    source_currency: cleanText(data.source_currency || params.source_currency || payload?.source_currency, 20).toUpperCase(),
    currency: cleanText(data.currency || data.psys_cid || payload?.currency, 40).toUpperCase(),
    finished_at_utc: data.finished_at_utc || payload?.finished_at_utc || null,
    raw: payload
  };
}

async function resellerHmacSha1Hex(secret, text) {
  const key = await crypto.subtle.importKey("raw", new TextEncoder().encode(String(secret)), { name: "HMAC", hash: "SHA-1" }, false, ["sign"]);
  const signature = await crypto.subtle.sign("HMAC", key, new TextEncoder().encode(String(text)));
  return bytesToHex(signature);
}

async function verifyResellerPlisioCallback(payload, secret) {
  if (!payload || typeof payload !== "object" || !payload.verify_hash) return false;
  const ordered = { ...payload };
  const supplied = String(ordered.verify_hash || "").toLowerCase();
  delete ordered.verify_hash;
  const expected = await resellerHmacSha1Hex(secret, JSON.stringify(ordered));
  return constantTimeTextEqual(expected, supplied);
}

async function recordResellerPlisioState(env, botId, ok, message = "") {
  return saveResellerPlisioConfig(env, botId, ok
    ? { plisio_last_verified_at: nowIso(), plisio_last_error: null }
    : { plisio_last_error: cleanText(message, 800) });
}

async function testResellerPlisioConfig(env, bot) {
  const secret = await resellerPlisioApiKey(env, bot);
  if (String(secret).length < 12) throw new Error("Secret Key Щ…Ш№ШӘШЁШұ ЩҶЫҢШіШӘ");
  const fx = await resolveResellerPlisioFxRate(env, bot, { force: true });
  await recordResellerPlisioState(env, bot.id, true);
  return { configured: true, source_currency: "USD", rate_toman: fx.rate_toman, rate_source: fx.source, stale: !!fx.stale };
}

const CUBEPAY_API_BASE = "https://cubevps.ir/smspay/api";

function resellerCubepayConfigured(bot) {
  return Number(bot?.cubepay_enabled || 0) === 1 && !!String(bot?.cubepay_api_token_enc || "").trim();
}

async function resellerCubepayApiToken(env, bot) {
  const encrypted = String(bot?.cubepay_api_token_enc || "").trim();
  if (!encrypted) throw new Error("API Token ШҜШұЪҜШ§ЩҮ CubePay ШЁШұШ§ЫҢ Ш§ЫҢЩҶ ШұШЁШ§ШӘ Ш«ШЁШӘ ЩҶШҙШҜЩҮ Ш§ШіШӘ");
  const cacheKey = String(bot.id || "");
  const cached = resellerCubepayTokenCache.get(cacheKey);
  if (cached && Date.now() - cached.at < 300000) return cached.value;
  try {
    const value = await decryptSecret(encrypted, env);
    if (!value) throw new Error("empty");
    if (resellerCubepayTokenCache.size > 500) resellerCubepayTokenCache.clear();
    resellerCubepayTokenCache.set(cacheKey, { value, at: Date.now() });
    return value;
  } catch (_) {
    throw new Error("API Token ШҜШұЪҜШ§ЩҮ CubePay ЩӮШ§ШЁЩ„ ШЁШ§ШІЫҢШ§ШЁЫҢ ЩҶЫҢШіШӘШӣ ШўЩҶ ШұШ§ ШҜЩҲШЁШ§ШұЩҮ Ш«ШЁШӘ Ъ©ЩҶЫҢШҜ");
  }
}

function resellerCubepayUrls(origin, bot) {
  const base = String(origin || "").replace(/\/+$/, "");
  const botId = encodeURIComponent(bot.id);
  return {
    callback_url: base + "/sales-payments/" + botId + "/cubepay/callback",
    miniapp_url: base + "/sales-app/" + botId
  };
}

async function resellerCubepayRequest(env, bot, endpoint, body) {
  if (!["create-payment.php", "verify-payment.php"].includes(endpoint)) throw new Error("Щ…ШіЫҢШұ CubePay Щ…Ш¬Ш§ШІ ЩҶЫҢШіШӘ");
  const token = await resellerCubepayApiToken(env, bot);
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), 12000);
  let response;
  try {
    response = await fetch(CUBEPAY_API_BASE + "/" + endpoint, {
      method: "POST",
      headers: { "content-type": "application/json", "accept": "application/json", "authorization": "Bearer " + token },
      body: JSON.stringify(body || {}),
      signal: controller.signal
    });
  } catch (error) {
    if (error?.name === "AbortError") throw new Error("ЩҫШ§ШіШ® CubePay ШЁЫҢШҙ Ш§ШІ ШӯШҜ Ш·ЩҲЩ„ Ъ©ШҙЫҢШҜ");
    throw error;
  } finally { clearTimeout(timer); }
  const data = await response.json().catch(() => ({}));
  return { ok: response.ok, status: response.status, data };
}

async function recordResellerCubepayState(env, botId, ok, message = "") {
  return saveResellerCubepayConfig(env, botId, ok
    ? { cubepay_last_verified_at: nowIso(), cubepay_last_error: null }
    : { cubepay_last_error: cleanText(message, 800) });
}

async function testResellerCubepayConfig(env, bot) {
  const token = await resellerCubepayApiToken(env, bot);
  if (String(token).length < 8) throw new Error("API Token Щ…Ш№ШӘШЁШұ ЩҶЫҢШіШӘ");
  return { configured: true };
}

async function createSalesCubepayInvoice(env, bot, customer, targetType, targetId, amountToman, origin, ctx = null) {
  if (!resellerCubepayConfigured(bot)) throw new Error("ШҜШұЪҜШ§ЩҮ CubePay Ш§ЫҢЩҶ ШұШЁШ§ШӘ ЩҮЩҶЩҲШІ Ъ©Ш§Щ…Щ„ ШӘЩҶШёЫҢЩ… ЩҶШҙШҜЩҮ Ш§ШіШӘ");
  if (targetType !== "wallet") throw new Error("CubePay ШҜШұ Ш§ЫҢЩҶ ЩҶШіШ®ЩҮ ШЁШұШ§ЫҢ ШҙШ§ШұЪҳ Ъ©ЫҢЩҒ ЩҫЩҲЩ„ ЩҒШ№Ш§Щ„ Ш§ШіШӘ");
  const safeAmountToman = clampInt(amountToman, 0, 1000000000000);
  if (safeAmountToman < 10000) throw new Error("ШӯШҜШ§ЩӮЩ„ Щ…ШЁЩ„Шә ШҙШ§ШұЪҳ ЫұЫ°Щ¬Ы°Ы°Ы° ШӘЩҲЩ…Ш§ЩҶ Ш§ШіШӘ");
  const invoiceId = id("scpay"), amountRial = safeAmountToman * 10;
  const requestBody = {
    amount: amountRial,
    order_id: invoiceId,
    callback_url: resellerCubepayUrls(origin, bot).callback_url,
    type: "card",
    customer_user_id: String(customer.telegram_id || customer.id),
    description: "ШҙШ§ШұЪҳ Ъ©ЫҢЩҒ ЩҫЩҲЩ„ " + safeAmountToman + " ШӘЩҲЩ…Ш§ЩҶ"
  };
  let result;
  try { result = await resellerCubepayRequest(env, bot, "create-payment.php", requestBody); }
  catch (error) {
    scheduleSalesInvoiceBackground(ctx, recordResellerCubepayState(env, bot.id, false, error.message), "record reseller CubePay error failed");
    throw new Error("ШіШ§Ш®ШӘ ЩҒШ§Ъ©ШӘЩҲШұ CubePay ЩҶШ§Щ…ЩҲЩҒЩӮ ШЁЩҲШҜ: " + error.message);
  }
  const provider = result.data || {};
  if (!result.ok || provider.success !== true) {
    const message = cleanText(provider.message || provider.error || ("CubePay HTTP " + result.status), 700);
    scheduleSalesInvoiceBackground(ctx, recordResellerCubepayState(env, bot.id, false, message), "record reseller CubePay error failed");
    throw new Error(message || "ШіШ§Ш®ШӘ ЩҒШ§Ъ©ШӘЩҲШұ CubePay ЩҶШ§Щ…ЩҲЩҒЩӮ ШЁЩҲШҜ");
  }
  const authority = cleanText(provider.authority, 160), paymentLink = cleanText(provider.payment_link, 1000);
  const payAmountRial = clampInt(provider.pay_amount, 0, Number.MAX_SAFE_INTEGER);
  const payAmountToman = clampInt(provider.pay_amount_toman, 0, Number.MAX_SAFE_INTEGER);
  if (!authority || !paymentLink || !payAmountRial || !payAmountToman) throw new Error("ЩҫШ§ШіШ® CubePay ЩҶШ§ЩӮШө Ш§ШіШӘ");
  const ts = nowIso();
  await env.PASARGUARD_DB.prepare(`
    INSERT INTO sales_payment_invoices(
      id,bot_id,customer_id,provider,provider_invoice_id,target_type,target_id,
      amount_rial,amount_toman,final_amount_rial,status,payment_link,card_number,provider_payload,created_at,updated_at
    ) VALUES(?,?,?,'cubepay',?,?,?,?,?,?,?,?,NULL,?,?,?)
  `).bind(
    invoiceId, bot.id, customer.id, authority, "wallet", targetId,
    amountRial, safeAmountToman, payAmountRial, "PENDING", paymentLink,
    JSON.stringify({ request: requestBody, response: provider, callback_received: false, pay_amount_toman: payAmountToman }), ts, ts
  ).run();
  scheduleSalesInvoiceBackground(ctx, salesEvent(env, bot.id, customer.id, "cubepay_invoice_created", {
    invoiceId, authority, targetId, amountToman: safeAmountToman, payAmountRial, payAmountToman
  }), "reseller CubePay invoice event failed");
  return { id: invoiceId, provider: "cubepay", invoice_id: authority, provider_invoice_id: authority, target_type: "wallet", target_id: targetId, amount_toman: safeAmountToman, amount_rial: amountRial, final_amount_rial: payAmountRial, final_amount_toman: payAmountToman, status: "PENDING", payment_link: paymentLink };
}

async function createSalesCubepayWalletCharge(env, bot, customer, amount, origin, ctx = null) {
  salesRequireVerifiedPhone(bot, customer);
  const safeAmount = clampInt(amount, 0, 1000000000000);
  if (safeAmount < 10000) throw new Error("ШӯШҜШ§ЩӮЩ„ Щ…ШЁЩ„Шә ШҙШ§ШұЪҳ ЫұЫ°Щ¬Ы°Ы°Ы° ШӘЩҲЩ…Ш§ЩҶ Ш§ШіШӘ");
  await enforceSalesSecurity(env, bot, customer, "wallet_charge", safeAmount);
  const requestId = id("wreq"), ts = nowIso();
  await env.PASARGUARD_DB.prepare(`INSERT INTO sales_wallet_requests(id,bot_id,customer_id,amount_toman,status,origin,created_at,updated_at) VALUES(?,?,?,?,'payment_pending',?,?,?)`)
    .bind(requestId, bot.id, customer.id, safeAmount, origin === "miniapp" ? "miniapp" : "bot", ts, ts).run();
  try {
    const invoice = await createSalesCubepayInvoice(env, bot, customer, "wallet", requestId, safeAmount, origin, ctx);
    const bonusPercent = Math.max(0, Math.min(100, Number(bot.recharge_bonus_percent || 0)));
    const bonusAmount = Math.floor(safeAmount * bonusPercent / 100);
    return { requestId, amountToman: safeAmount, bonusPercent, bonusAmount, invoice };
  } catch (error) {
    await env.PASARGUARD_DB.prepare("UPDATE sales_wallet_requests SET status='rejected',updated_at=? WHERE id=?").bind(nowIso(), requestId).run();
    throw error;
  }
}

async function finalizeSalesCubepayWallet(env, bot, payment) {
  const requestRow = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_wallet_requests WHERE id=? AND bot_id=? AND customer_id=?")
    .bind(payment.target_id, bot.id, payment.customer_id).first();
  if (!requestRow) throw new Error("ШҜШұШ®ЩҲШ§ШіШӘ ШҙШ§ШұЪҳ Щ…ШұШӘШЁШ· ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  if (requestRow.status === "approved" || payment.processed_at) return { already_processed: true };
  const bonusPercent = Math.max(0, Math.min(100, Number(bot.recharge_bonus_percent || 0)));
  const baseAmount = Number(payment.amount_toman || 0), bonusAmount = Math.floor(baseAmount * bonusPercent / 100), creditedAmount = baseAmount + bonusAmount;
  const token = uniqueProcessedAtToken(), ledgerId = "cled_cubepay_" + String(payment.id).replace(/[^a-zA-Z0-9_]/g, "");
  const results = await env.PASARGUARD_DB.batch([
    env.PASARGUARD_DB.prepare(`UPDATE sales_payment_invoices SET processed_at=?,updated_at=?,error_message=NULL WHERE id=? AND processed_at IS NULL AND status='PAID'`).bind(token, token, payment.id),
    env.PASARGUARD_DB.prepare(`UPDATE sales_wallet_requests SET status='approved',bonus_toman=?,reviewed_at=?,updated_at=? WHERE id=? AND EXISTS(SELECT 1 FROM sales_payment_invoices WHERE id=? AND processed_at=?)`).bind(bonusAmount, token, token, requestRow.id, payment.id, token),
    env.PASARGUARD_DB.prepare(`UPDATE sales_customers SET wallet_balance=wallet_balance+?,updated_at=? WHERE id=? AND bot_id=? AND EXISTS(SELECT 1 FROM sales_payment_invoices WHERE id=? AND processed_at=?)`).bind(creditedAmount, token, payment.customer_id, bot.id, payment.id, token),
    env.PASARGUARD_DB.prepare(`INSERT OR IGNORE INTO sales_customer_ledger(id,bot_id,customer_id,type,amount,balance_after,ref_type,ref_id,description,created_at) SELECT ?,?,?, 'recharge', ?, wallet_balance, 'cubepay', ?, ?, ? FROM sales_customers WHERE id=? AND bot_id=? AND EXISTS(SELECT 1 FROM sales_payment_invoices WHERE id=? AND processed_at=?)`).bind(
      ledgerId, bot.id, payment.customer_id, creditedAmount, payment.id,
      bonusAmount > 0 ? ("ШҙШ§ШұЪҳ CubePay + ШЁЩҲЩҶШі " + bonusPercent + "ЩӘ") : "ШҙШ§ШұЪҳ Ш®ЩҲШҜЪ©Ш§Шұ CubePay",
      token, payment.customer_id, bot.id, payment.id, token
    )
  ]);
  const processed = Number(results?.[0]?.meta?.changes || 0) > 0;
  if (processed) {
    const customer = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_customers WHERE id=?").bind(payment.customer_id).first();
    if (customer) {
      await createSalesNotification(env, bot, customer, null, "payment_success", "ШҙШ§ШұЪҳ CubePay Щ…ЩҲЩҒЩӮ", "Щ…ШЁЩ„Шә " + botMoney(creditedAmount) + " ШӘЩҲЩ…Ш§ЩҶ ШЁЩҮ Ъ©ЫҢЩҒ ЩҫЩҲЩ„ ШҙЩ…Ш§ Ш§Ш¶Ш§ЩҒЩҮ ШҙШҜ.", "cubepay_wallet:" + payment.id, { sendBot: false });
      try { await resellerTelegramApi(env, bot, "sendMessage", { chat_id: customer.telegram_id, text: "вң… ЩҫШұШҜШ§Ш®ШӘ CubePay ШӘШЈЫҢЫҢШҜ ШҙШҜ.\\nЩ…ШЁЩ„Шә Ш§ЩҒШІЩҲШҜЩҮвҖҢШҙШҜЩҮ: <b>" + botMoney(creditedAmount) + " ШӘЩҲЩ…Ш§ЩҶ</b>", parse_mode: "HTML" }); } catch (_) {}
    }
    await salesEvent(env, bot.id, payment.customer_id, "cubepay_wallet_credited", { paymentId: payment.id, baseAmount, bonusAmount, creditedAmount });
    await queueReportEvent(env, bot.id, "payments", "ШҙШ§ШұЪҳ Ш®ЩҲШҜЪ©Ш§Шұ CubePay ШӘШЈЫҢЫҢШҜ ШҙШҜ",
      "Щ…ШҙШӘШұЫҢ: <code>" + botEscape(customer?.telegram_id || payment.customer_id) + "</code>\\nЩ…ШЁЩ„Шә: <b>" + botMoney(baseAmount) + " ШӘЩҲЩ…Ш§ЩҶ</b>" + (bonusAmount > 0 ? "\\nШЁЩҲЩҶШі: <b>" + botMoney(bonusAmount) + " ШӘЩҲЩ…Ш§ЩҶ</b>" : "") + "\\nЩҒШ§Ъ©ШӘЩҲШұ: <code>" + botEscape(payment.provider_invoice_id) + "</code>",
      "cubepay-wallet:" + payment.id).catch(() => null);
  }
  return { processed, bonusAmount, creditedAmount };
}

async function reconcileSalesCubepayPayment(env, bot, payment) {
  if (payment.processed_at) return payment;
  let stored = {};
  try { stored = JSON.parse(payment.provider_payload || "{}"); } catch (_) {}
  if (!stored.callback_received) return payment;
  const result = await resellerCubepayRequest(env, bot, "verify-payment.php", { authority: payment.provider_invoice_id });
  const data = result.data || {};
  const verified = (result.ok && data.success === true && String(data.status || "").toLowerCase() === "verified") || result.status === 409;
  if (!verified) {
    if (result.status === 402) return payment;
    if (result.status === 410) {
      const ts = nowIso();
      await env.PASARGUARD_DB.batch([
        env.PASARGUARD_DB.prepare("UPDATE sales_payment_invoices SET status='EXPIRED',error_message=?,updated_at=? WHERE id=? AND processed_at IS NULL").bind(cleanText(data.message || "ЩҒШ§Ъ©ШӘЩҲШұ Щ…ЩҶЩӮШ¶ЫҢ ЫҢШ§ ЩҶШ§Щ…ЩҲЩҒЩӮ Ш§ШіШӘ",800),ts,payment.id),
        env.PASARGUARD_DB.prepare("UPDATE sales_wallet_requests SET status='rejected',updated_at=? WHERE id=? AND status='payment_pending'").bind(ts,payment.target_id)
      ]);
      return env.PASARGUARD_DB.prepare("SELECT * FROM sales_payment_invoices WHERE id=?").bind(payment.id).first();
    }
    throw new Error(cleanText(data.message || data.error || ("CubePay HTTP " + result.status), 800));
  }
  const verifiedOrder = cleanText(data.order_id || stored?.callback?.order_id || stored?.callback?.query?.order_id, 160);
  if (verifiedOrder && verifiedOrder !== String(payment.id)) throw new Error("ШҙЩ…Ш§ШұЩҮ ШіЩҒШ§ШұШҙ CubePay ШӘШ·ШЁЫҢЩӮ ЩҶШҜШ§ШұШҜ");
  const verifiedAmount = Number(data.amount || stored?.callback?.amount || stored?.callback?.json?.amount || 0);
  if (verifiedAmount > 0 && verifiedAmount !== Number(payment.amount_rial || 0)) throw new Error("Щ…ШЁЩ„Шә ШӘШ§ЫҢЫҢШҜ CubePay ШЁШ§ ЩҒШ§Ъ©ШӘЩҲШұ ШҜШ§Ш®Щ„ЫҢ ШӘШ·ШЁЫҢЩӮ ЩҶШҜШ§ШұШҜ");
  const ts = nowIso();
  await env.PASARGUARD_DB.prepare("UPDATE sales_payment_invoices SET status='PAID',paid_at=COALESCE(paid_at,?),provider_payload=?,updated_at=?,error_message=NULL WHERE id=?")
    .bind(ts, JSON.stringify({ ...stored, verify: data, verify_http_status: result.status }), ts, payment.id).run();
  await recordResellerCubepayState(env, bot.id, true).catch(() => null);
  const fresh = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_payment_invoices WHERE id=?").bind(payment.id).first();
  if (!fresh.processed_at) await finalizeSalesCubepayWallet(env, bot, fresh);
  return env.PASARGUARD_DB.prepare("SELECT * FROM sales_payment_invoices WHERE id=?").bind(payment.id).first();
}

async function resellerCubepayCallback(request, env, botId) {
  await ensureDb(env);
  const bot = await getResellerBotById(env, botId);
  if (!bot) return fail("Not found", 404, "NOT_FOUND");
  const url = new URL(request.url);
  let body = {};
  if (request.method === "POST") { try { body = await parseBody(request); } catch (_) { body = {}; } }
  const authority = cleanText(body.authority || url.searchParams.get("authority"), 160);
  const orderId = cleanText(body.order_id || url.searchParams.get("order_id"), 160);
  const callbackStatus = cleanText(body.status || url.searchParams.get("status"), 50).toLowerCase();
  const amount = clampInt(body.amount, 0, Number.MAX_SAFE_INTEGER);
  if (!authority && !orderId) return fail("Invalid callback payload", 400, "INVALID_CALLBACK");
  let payment = null;
  if (authority) payment = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_payment_invoices WHERE bot_id=? AND provider='cubepay' AND provider_invoice_id=?").bind(bot.id, authority).first();
  if (!payment && orderId) payment = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_payment_invoices WHERE bot_id=? AND provider='cubepay' AND id=?").bind(bot.id, orderId).first();
  if (!payment) return fail("Invoice not found", 404, "NOT_FOUND");
  if (orderId && orderId !== String(payment.id)) return fail("Order mismatch", 422, "ORDER_MISMATCH");
  if (amount > 0 && amount !== Number(payment.amount_rial || 0)) return fail("Amount mismatch", 422, "AMOUNT_MISMATCH");
  let stored = {};
  try { stored = JSON.parse(payment.provider_payload || "{}"); } catch (_) {}
  const ts = nowIso();
  await env.PASARGUARD_DB.prepare("UPDATE sales_payment_invoices SET provider_payload=?,updated_at=? WHERE id=?")
    .bind(JSON.stringify({ ...stored, callback_received: true, callback: { json: body, query: Object.fromEntries(url.searchParams.entries()), authority, order_id: orderId, status: callbackStatus, amount, received_at: ts } }), ts, payment.id).run();
  try {
    const fresh = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_payment_invoices WHERE id=?").bind(payment.id).first();
    await reconcileSalesCubepayPayment(env, bot, fresh);
    return json({ received: true });
  } catch (error) {
    await recordResellerCubepayState(env, bot.id, false, error.message).catch(() => null);
    await env.PASARGUARD_DB.prepare("UPDATE sales_payment_invoices SET error_message=?,updated_at=? WHERE id=?").bind(cleanText(error.message,800),nowIso(),payment.id).run();
    return fail("Callback processing failed", 500, "CALLBACK_FAILED");
  }
}

function resellerBlupalConfigured(bot) {
  return Number(bot?.blupal_enabled || 0) === 1 && !!String(bot?.blupal_api_key_enc || "").trim();
}

const SALES_PAYMENT_METHODS = Object.freeze(["card", "blupal", "wallet"]);

const SALES_PAYMENT_METHOD_LABELS = Object.freeze({ card: "Ъ©Ш§ШұШӘвҖҢШЁЩҮвҖҢЪ©Ш§ШұШӘ", blupal: "ШЁЩ„ЩҲЩҫШ§Щ„", wallet: "Ъ©ЫҢЩҒ ЩҫЩҲЩ„" });

function salesCardConfigured(bot) {
  return normalizeCardNumber(bot?.card_number).length >= 16 && !!cleanText(bot?.card_holder, 160);
}

function resellerPaymentMethodOrder(bot) {
  const raw = String(bot?.payment_method_order || "card,blupal,wallet").split(",").map(x => x.trim().toLowerCase());
  const unique = [];
  for (const method of [...raw, ...SALES_PAYMENT_METHODS]) if (SALES_PAYMENT_METHODS.includes(method) && !unique.includes(method)) unique.push(method);
  return unique;
}

function resellerPaymentMethodEnabled(bot, method, context = "order") {
  const key = String(method || "").toLowerCase();
  if (key === "card") return Number(bot?.payment_card_enabled ?? 1) === 1 && salesCardConfigured(bot);
  if (key === "blupal") return resellerBlupalConfigured(bot);
  if (key === "wallet") return context !== "recharge" && Number(bot?.payment_wallet_enabled ?? 1) === 1;
  return false;
}

function resellerPaymentDefaultMethod(bot, context = "order") {
  const enabled = resellerPaymentMethodOrder(bot).filter(method => resellerPaymentMethodEnabled(bot, method, context));
  const preferred = String(bot?.payment_default_method || "card").toLowerCase();
  return enabled.includes(preferred) ? preferred : (enabled[0] || "");
}

function resellerRequirePaymentMethod(bot, method, context = "order") {
  const key = String(method || "").toLowerCase();
  if (resellerPaymentMethodEnabled(bot, key, context)) return key;
  const label = SALES_PAYMENT_METHOD_LABELS[key] || "ШұЩҲШҙ ЩҫШұШҜШ§Ш®ШӘ Ш§ЩҶШӘШ®Ш§ШЁвҖҢШҙШҜЩҮ";
  const error = new Error(label + " ШЁШұШ§ЫҢ Ш§ЫҢЩҶ ШұШЁШ§ШӘ ЩҒШ№Ш§Щ„ ЫҢШ§ Ъ©Ш§Щ…Щ„ ШӘЩҶШёЫҢЩ… ЩҶШҙШҜЩҮ Ш§ШіШӘ");
  error.code = "PAYMENT_METHOD_DISABLED";
  throw error;
}

function resellerPaymentUrls(origin, bot) {
  const base = String(origin || "").replace(/\/+$/, "");
  const botId = encodeURIComponent(bot.id);
  const token = encodeURIComponent(String(bot.blupal_webhook_token || ""));
  return {
    webhook_url: base + "/sales-payments/" + botId + "/blupal/webhook?token=" + token,
    callback_url: base + "/sales-payments/" + botId + "/return",
    miniapp_url: base + "/sales-app/" + botId
  };
}

async function ensureResellerBlupalWebhookToken(env, bot) {
  let token = String(bot.blupal_webhook_token || "").trim();
  if (token) return token;
  token = randomHex(32);
  await env.PASARGUARD_DB.prepare("UPDATE reseller_bots SET blupal_webhook_token=?,updated_at=? WHERE id=?")
    .bind(token, nowIso(), bot.id).run();
  bot.blupal_webhook_token = token;
  return token;
}

async function resellerBlupalApiKey(env, bot) {
  const encrypted = String(bot.blupal_api_key_enc || "").trim();
  if (!encrypted) throw new Error("API Key ШЁЩ„ЩҲЩҫШ§Щ„ ШЁШұШ§ЫҢ Ш§ЫҢЩҶ ШұШЁШ§ШӘ Ш«ШЁШӘ ЩҶШҙШҜЩҮ Ш§ШіШӘ");
  try {
    const value = await decryptSecret(encrypted, env);
    if (!value) throw new Error("empty");
    return value;
  } catch (_) {
    throw new Error("API Key ШЁЩ„ЩҲЩҫШ§Щ„ ЩӮШ§ШЁЩ„ ШЁШ§ШІЫҢШ§ШЁЫҢ ЩҶЫҢШіШӘШӣ ШўЩҶ ШұШ§ ШҜЩҲШЁШ§ШұЩҮ Ш«ШЁШӘ Ъ©ЩҶЫҢШҜ");
  }
}

async function resellerBlupalRequest(env, bot, method, path, body = undefined) {
  if (Number(bot.blupal_enabled || 0) !== 1) throw new Error("ЩҫШұШҜШ§Ш®ШӘ ШўЩҶЩ„Ш§ЫҢЩҶ ШЁЩ„ЩҲЩҫШ§Щ„ ШЁШұШ§ЫҢ Ш§ЫҢЩҶ ШұШЁШ§ШӘ ШәЫҢШұЩҒШ№Ш§Щ„ Ш§ШіШӘ");
  const apiKey = await resellerBlupalApiKey(env, bot);
  const headers = { "X-API-Key": apiKey, "accept": "application/json" };
  if (body !== undefined) headers["content-type"] = "application/json";
  const response = await fetch(normalizeBlupalBaseUrl(bot.blupal_base_url || "https://blupal.net/api") + path, {
    method,
    headers,
    body: body === undefined ? undefined : JSON.stringify(body)
  });
  const data = await response.json().catch(() => ({}));
  if (!response.ok || data.success === false) {
    const message = data.message || data.error || ("BluePal HTTP " + response.status);
    const error = new Error(message);
    error.code = data.error || "BLUPAL_ERROR";
    error.status = response.status;
    throw error;
  }
  return data;
}

async function createSalesBlupalInvoice(env, bot, customer, targetType, targetId, amountToman) {
  if (!resellerBlupalConfigured(bot)) throw new Error("ШҜШұЪҜШ§ЩҮ ШЁЩ„ЩҲЩҫШ§Щ„ Ш§ЫҢЩҶ ШұШЁШ§ШӘ ЩҮЩҶЩҲШІ Ъ©Ш§Щ…Щ„ ШӘЩҶШёЫҢЩ… ЩҶШҙШҜЩҮ Ш§ШіШӘ");
  const safeTargetType = targetType === "wallet" ? "wallet" : "order";
  const safeAmountToman = clampInt(amountToman, 0, 1000000000000);
  if (safeAmountToman < 1000) throw new Error("Щ…ШЁЩ„Шә ЩҫШұШҜШ§Ш®ШӘ ШўЩҶЩ„Ш§ЫҢЩҶ Щ…Ш№ШӘШЁШұ ЩҶЫҢШіШӘ");
  const amountRial = safeAmountToman * 10;
  const requestBody = { amount: amountRial };
  const preferredCard = normalizeCardNumber(bot.blupal_card_number);
  if (preferredCard) requestBody.card_number = preferredCard;
  let provider;
  try {
    provider = await resellerBlupalRequest(env, bot, "POST", "/v1/invoices/create", requestBody);
  } catch (error) {
    await env.PASARGUARD_DB.prepare("UPDATE reseller_bots SET blupal_last_error=?,updated_at=? WHERE id=?")
      .bind(cleanText(error.message, 500), nowIso(), bot.id).run();
    throw new Error("ШіШ§Ш®ШӘ ЩҒШ§Ъ©ШӘЩҲШұ ШЁЩ„ЩҲЩҫШ§Щ„ ЩҶШ§Щ…ЩҲЩҒЩӮ ШЁЩҲШҜ: " + error.message);
  }
  const providerInvoiceId = cleanText(provider.invoice_id, 100);
  const finalAmountRial = clampInt(provider.final_amount, 0, Number.MAX_SAFE_INTEGER);
  const paymentLink = cleanText(provider.payment_link, 1000);
  if (!providerInvoiceId || !finalAmountRial || !paymentLink) throw new Error("ЩҫШ§ШіШ® ШЁЩ„ЩҲЩҫШ§Щ„ ЩҶШ§ЩӮШө Ш§ШіШӘ");
  if (clampInt(provider.amount, 0) !== amountRial) throw new Error("Щ…ШЁЩ„Шә ШЁШұЪҜШҙШӘЫҢ ШЁЩ„ЩҲЩҫШ§Щ„ ШЁШ§ ШіЩҒШ§ШұШҙ ШӘШ·ШЁЫҢЩӮ ЩҶШҜШ§ШұШҜ");
  const invoiceId = id("spay");
  const ts = nowIso();
  await env.PASARGUARD_DB.prepare(`
    INSERT INTO sales_payment_invoices(
      id,bot_id,customer_id,provider,provider_invoice_id,target_type,target_id,
      amount_rial,amount_toman,final_amount_rial,status,payment_link,card_number,provider_payload,created_at,updated_at
    ) VALUES(?,?,?,'blupal',?,?,?,?,?,?,?,?,?,?,?,?)
  `).bind(
    invoiceId, bot.id, customer.id, providerInvoiceId, safeTargetType, targetId,
    amountRial, safeAmountToman, finalAmountRial, normalizePaymentStatus(provider.status), paymentLink,
    cleanText(provider.card_number, 100), JSON.stringify(provider), ts, ts
  ).run();
  await env.PASARGUARD_DB.prepare("UPDATE reseller_bots SET blupal_last_error=NULL,blupal_last_verified_at=?,updated_at=? WHERE id=?")
    .bind(ts, ts, bot.id).run();
  await salesEvent(env, bot.id, customer.id, "blupal_invoice_created", { invoiceId, providerInvoiceId, targetType: safeTargetType, targetId, amountToman: safeAmountToman });
  return {
    id: invoiceId,
    invoice_id: providerInvoiceId,
    target_type: safeTargetType,
    target_id: targetId,
    amount_toman: safeAmountToman,
    amount_rial: amountRial,
    final_amount_rial: finalAmountRial,
    status: normalizePaymentStatus(provider.status),
    payment_link: paymentLink,
    card_number: cleanText(provider.card_number, 100)
  };
}

async function createSalesBlupalWalletCharge(env, bot, customer, amount) {
  salesRequireVerifiedPhone(bot, customer);
  const safeAmount = clampInt(amount, 0, 1000000000000);
  if (safeAmount < 10000) throw new Error("ШӯШҜШ§ЩӮЩ„ Щ…ШЁЩ„Шә ШҙШ§ШұЪҳ ЫұЫ°Щ¬Ы°Ы°Ы° ШӘЩҲЩ…Ш§ЩҶ Ш§ШіШӘ");
  await enforceSalesSecurity(env, bot, customer, "wallet_charge", safeAmount);
  const requestId = id("wreq");
  const ts = nowIso();
  await env.PASARGUARD_DB.prepare(`
    INSERT INTO sales_wallet_requests(id,bot_id,customer_id,amount_toman,status,origin,created_at,updated_at)
    VALUES(?,?,?,?,'payment_pending','miniapp',?,?)
  `).bind(requestId, bot.id, customer.id, safeAmount, ts, ts).run();
  try {
    const invoice = await createSalesBlupalInvoice(env, bot, customer, "wallet", requestId, safeAmount);
    const bonusPercent = Math.max(0, Math.min(100, Number(bot.recharge_bonus_percent || 0)));
    const bonusAmount = Math.floor(safeAmount * bonusPercent / 100);
    return { requestId, amountToman: safeAmount, bonusPercent, bonusAmount, invoice };
  } catch (error) {
    await env.PASARGUARD_DB.prepare("UPDATE sales_wallet_requests SET status='rejected',updated_at=? WHERE id=?")
      .bind(nowIso(), requestId).run();
    throw error;
  }
}

async function finalizeSalesBlupalWallet(env, bot, payment) {
  const requestRow = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_wallet_requests WHERE id=? AND bot_id=? AND customer_id=?")
    .bind(payment.target_id, bot.id, payment.customer_id).first();
  if (!requestRow) throw new Error("ШҜШұШ®ЩҲШ§ШіШӘ ШҙШ§ШұЪҳ Щ…ШұШӘШЁШ· ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  if (requestRow.status === "approved") {
    await env.PASARGUARD_DB.prepare("UPDATE sales_payment_invoices SET processed_at=COALESCE(processed_at,?),updated_at=? WHERE id=?")
      .bind(nowIso(), nowIso(), payment.id).run();
    return { already_processed: true };
  }
  const bonusPercent = Math.max(0, Math.min(100, Number(bot.recharge_bonus_percent || 0)));
  const baseAmount = Number(payment.amount_toman || 0);
  const bonusAmount = Math.floor(baseAmount * bonusPercent / 100);
  const creditedAmount = baseAmount + bonusAmount;
  const token = nowIso();
  const ledgerId = "cled_blupal_" + String(payment.id).replace(/[^a-zA-Z0-9_]/g, "");
  const results = await env.PASARGUARD_DB.batch([
    env.PASARGUARD_DB.prepare(`
      UPDATE sales_payment_invoices SET processed_at=?,updated_at=?,error_message=NULL
      WHERE id=? AND processed_at IS NULL AND status='PAID'
    `).bind(token, token, payment.id),
    env.PASARGUARD_DB.prepare(`
      UPDATE sales_wallet_requests SET status='approved',bonus_toman=?,reviewed_at=?,updated_at=?
      WHERE id=? AND EXISTS(SELECT 1 FROM sales_payment_invoices WHERE id=? AND processed_at=?)
    `).bind(bonusAmount, token, token, requestRow.id, payment.id, token),
    env.PASARGUARD_DB.prepare(`
      UPDATE sales_customers SET wallet_balance=wallet_balance+?,updated_at=?
      WHERE id=? AND bot_id=? AND EXISTS(SELECT 1 FROM sales_payment_invoices WHERE id=? AND processed_at=?)
    `).bind(creditedAmount, token, payment.customer_id, bot.id, payment.id, token),
    env.PASARGUARD_DB.prepare(`
      INSERT OR IGNORE INTO sales_customer_ledger(id,bot_id,customer_id,type,amount,balance_after,ref_type,ref_id,description,created_at)
      SELECT ?,?,?, 'recharge', ?, wallet_balance, 'blupal', ?, ?, ?
      FROM sales_customers WHERE id=? AND bot_id=? AND EXISTS(SELECT 1 FROM sales_payment_invoices WHERE id=? AND processed_at=?)
    `).bind(ledgerId, bot.id, payment.customer_id, creditedAmount, payment.id,
      bonusAmount > 0 ? ("ШҙШ§ШұЪҳ ШўЩҶЩ„Ш§ЫҢЩҶ ШЁЩ„ЩҲЩҫШ§Щ„ + ШЁЩҲЩҶШі " + bonusPercent + "ЩӘ") : "ШҙШ§ШұЪҳ ШўЩҶЩ„Ш§ЫҢЩҶ ШЁЩ„ЩҲЩҫШ§Щ„",
      token, payment.customer_id, bot.id, payment.id, token)
  ]);
  const processed = Number(results?.[0]?.meta?.changes || 0) > 0;
  if (processed) {
    const customer = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_customers WHERE id=?").bind(payment.customer_id).first();
    if (customer) await createSalesNotification(env, bot, customer, null, "payment_success", "ШҙШ§ШұЪҳ ШўЩҶЩ„Ш§ЫҢЩҶ Щ…ЩҲЩҒЩӮ", "Щ…ШЁЩ„Шә " + botMoney(creditedAmount) + " ШӘЩҲЩ…Ш§ЩҶ ШЁЩҮ Ъ©ЫҢЩҒ ЩҫЩҲЩ„ ШҙЩ…Ш§ Ш§Ш¶Ш§ЩҒЩҮ ШҙШҜ.", "blupal_wallet:" + payment.id, { sendBot: false });
    await salesEvent(env, bot.id, payment.customer_id, "blupal_wallet_credited", { paymentId: payment.id, baseAmount, bonusAmount, creditedAmount });
  }
  return { processed, bonusAmount, creditedAmount };
}

async function finalizeSalesBlupalOrder(env, bot, payment) {
  const order = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_orders WHERE id=? AND bot_id=? AND customer_id=?")
    .bind(payment.target_id, bot.id, payment.customer_id).first();
  if (!order) throw new Error("ШіЩҒШ§ШұШҙ Щ…ШұШӘШЁШ· ШЁШ§ ЩҒШ§Ъ©ШӘЩҲШұ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  if (order.status === "delivered") {
    await env.PASARGUARD_DB.prepare("UPDATE sales_payment_invoices SET processed_at=COALESCE(processed_at,?),updated_at=?,error_message=NULL WHERE id=?")
      .bind(nowIso(), nowIso(), payment.id).run();
    return { delivered: true, already_processed: true, order };
  }
  if (!["payment_pending", "payment_paid", "pending_review", "provision_failed"].includes(String(order.status))) {
    throw new Error("ЩҲШ¶Ш№ЫҢШӘ ШіЩҒШ§ШұШҙ ШЁШұШ§ЫҢ ШӘШӯЩҲЫҢЩ„ ШўЩҶЩ„Ш§ЫҢЩҶ Щ…Ш№ШӘШЁШұ ЩҶЫҢШіШӘ");
  }
  await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='pending_review',updated_at=? WHERE id=? AND status IN ('payment_pending','payment_paid')")
    .bind(nowIso(), order.id).run();
  const owner = await env.PASARGUARD_DB.prepare("SELECT * FROM users WHERE id=?").bind(bot.user_id).first();
  if (!owner) throw new Error("ШӯШіШ§ШЁ Щ…Ш§Щ„Ъ© ШұШЁШ§ШӘ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  try {
    const delivered = await provisionSalesOrder(env, owner, order.id);
    await env.PASARGUARD_DB.prepare("UPDATE sales_payment_invoices SET processed_at=?,updated_at=?,error_message=NULL WHERE id=? AND processed_at IS NULL")
      .bind(nowIso(), nowIso(), payment.id).run();
    const customer = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_customers WHERE id=?").bind(payment.customer_id).first();
    if (customer) await createSalesNotification(env, bot, customer, order.id, "payment_success", "ЩҫШұШҜШ§Ш®ШӘ ЩҲ ШӘШӯЩҲЫҢЩ„ Щ…ЩҲЩҒЩӮ", "ЩҫШұШҜШ§Ш®ШӘ ШўЩҶЩ„Ш§ЫҢЩҶ ШӘШЈЫҢЫҢШҜ ШҙШҜ ЩҲ ШіШұЩҲЫҢШі ШҙЩ…Ш§ ШўЩ…Ш§ШҜЩҮ Ш§ШіШӘ.", "blupal_order:" + payment.id, { sendBot: false });
    await salesEvent(env, bot.id, payment.customer_id, "blupal_order_delivered", { paymentId: payment.id, orderId: order.id });
    return { delivered: true, order: delivered };
  } catch (error) {
    await env.PASARGUARD_DB.prepare("UPDATE sales_payment_invoices SET error_message=?,updated_at=? WHERE id=?")
      .bind(cleanText(error.message, 800), nowIso(), payment.id).run();
    throw error;
  }
}

async function applyVerifiedSalesBlupalPayment(env, bot, payment, providerData) {
  const providerInvoiceId = String(providerData.invoice_id || "");
  const status = normalizePaymentStatus(providerData.status);
  const amountRial = clampInt(providerData.amount, 0, Number.MAX_SAFE_INTEGER);
  const finalAmountRial = clampInt(providerData.final_amount, 0, Number.MAX_SAFE_INTEGER);
  if (providerInvoiceId !== String(payment.provider_invoice_id)) throw new Error("ШҙЩҶШ§ШіЩҮ ЩҒШ§Ъ©ШӘЩҲШұ ШӘШ·ШЁЫҢЩӮ ЩҶШҜШ§ШұШҜ");
  if (amountRial !== Number(payment.amount_rial) || finalAmountRial !== Number(payment.final_amount_rial)) throw new Error("Щ…ШЁЩ„Шә ЩҒШ§Ъ©ШӘЩҲШұ ШЁЩ„ЩҲЩҫШ§Щ„ ШЁШ§ ШұЪ©ЩҲШұШҜ ШҜШ§Ш®Щ„ЫҢ ШӘШ·ШЁЫҢЩӮ ЩҶШҜШ§ШұШҜ");
  const ts = nowIso();
  if (status !== "PAID") {
    await env.PASARGUARD_DB.prepare("UPDATE sales_payment_invoices SET status=?,provider_payload=?,updated_at=? WHERE id=? AND processed_at IS NULL")
      .bind(status, JSON.stringify(providerData), ts, payment.id).run();
    if (["EXPIRED", "CANCELED"].includes(status)) {
      if (payment.target_type === "order") {
        await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='cancelled',updated_at=? WHERE id=? AND status='payment_pending'").bind(ts, payment.target_id).run();
        try { await salesReleasePromoForOrder(env, payment.target_id); } catch (_) {}
      } else {
        await env.PASARGUARD_DB.prepare("UPDATE sales_wallet_requests SET status='rejected',updated_at=? WHERE id=? AND status='payment_pending'").bind(ts, payment.target_id).run();
      }
    }
    return { status, processed: false };
  }
  await env.PASARGUARD_DB.prepare("UPDATE sales_payment_invoices SET status='PAID',paid_at=?,provider_payload=?,updated_at=? WHERE id=?")
    .bind(cleanText(providerData.paid_at, 100) || ts, JSON.stringify(providerData), ts, payment.id).run();
  await env.PASARGUARD_DB.prepare("UPDATE reseller_bots SET blupal_last_verified_at=?,blupal_last_error=NULL,updated_at=? WHERE id=?")
    .bind(ts, ts, bot.id).run();
  const fresh = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_payment_invoices WHERE id=?").bind(payment.id).first();
  if (fresh.processed_at) return { status: "PAID", processed: true };
  return fresh.target_type === "wallet" ? finalizeSalesBlupalWallet(env, bot, fresh) : finalizeSalesBlupalOrder(env, bot, fresh);
}

async function reconcileSalesBlupalInvoice(env, payment) {
  const bot = await getResellerBotById(env, payment.bot_id);
  if (!bot) throw new Error("ШұШЁШ§ШӘ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ЩҒШ§Ъ©ШӘЩҲШұ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  const providerData = await resellerBlupalRequest(env, bot, "GET", "/v1/invoices/" + encodeURIComponent(payment.provider_invoice_id));
  await applyVerifiedSalesBlupalPayment(env, bot, payment, providerData);
  return await env.PASARGUARD_DB.prepare("SELECT * FROM sales_payment_invoices WHERE id=?").bind(payment.id).first();
}

async function pollPendingSalesBlupalPayments(env, limit = 50, botId = "") {
  const sql = `SELECT spi.* FROM sales_payment_invoices spi JOIN reseller_bots rb ON rb.id=spi.bot_id
    WHERE spi.status IN ('PENDING','PAID') AND spi.processed_at IS NULL AND rb.blupal_enabled=1
    ${botId ? "AND spi.bot_id=?" : ""} ORDER BY spi.updated_at ASC LIMIT ?`;
  const stmt = env.PASARGUARD_DB.prepare(sql);
  const rows = botId ? await stmt.bind(botId, Math.max(1, Math.min(200, Number(limit || 50)))).all() : await stmt.bind(Math.max(1, Math.min(200, Number(limit || 50)))).all();
  let checked = 0, processed = 0;
  const errors = [];
  for (const payment of rows.results || []) {
    try {
      const updated = await reconcileSalesBlupalInvoice(env, payment);
      checked++;
      if (updated?.processed_at) processed++;
    } catch (error) {
      errors.push({ paymentId: payment.id, error: error.message });
      await env.PASARGUARD_DB.prepare("UPDATE sales_payment_invoices SET error_message=?,updated_at=? WHERE id=?")
        .bind(cleanText(error.message, 800), nowIso(), payment.id).run();
    }
  }
  return { checked, processed, errors };
}

async function salesBlupalPaymentStatus(env, bot, customer, paymentId) {
  const payment = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_payment_invoices WHERE id=? AND bot_id=? AND customer_id=?")
    .bind(paymentId, bot.id, customer.id).first();
  if (!payment) throw new Error("ЩҒШ§Ъ©ШӘЩҲШұ ШўЩҶЩ„Ш§ЫҢЩҶ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  if (!payment.processed_at && ["PENDING", "PAID"].includes(String(payment.status))) {
    try { return await reconcileSalesBlupalInvoice(env, payment); } catch (_) {}
  }
  return await env.PASARGUARD_DB.prepare("SELECT * FROM sales_payment_invoices WHERE id=?").bind(payment.id).first();
}

async function createSalesPlisioInvoice(env, bot, customer, targetType, targetId, amountToman, origin, ctx = null) {
  if (!resellerPlisioConfigured(bot)) throw new Error("ШҜШұЪҜШ§ЩҮ Plisio Ш§ЫҢЩҶ ШұШЁШ§ШӘ ЩҮЩҶЩҲШІ Ъ©Ш§Щ…Щ„ ШӘЩҶШёЫҢЩ… ЩҶШҙШҜЩҮ Ш§ШіШӘ");
  const safeTargetType = targetType === "wallet" ? "wallet" : "order";
  if (safeTargetType !== "wallet") throw new Error("Plisio ШҜШұ Ш§ЫҢЩҶ ЩҶШіШ®ЩҮ ШЁШұШ§ЫҢ ШҙШ§ШұЪҳ Ъ©ЫҢЩҒ ЩҫЩҲЩ„ ЩҒШ№Ш§Щ„ Ш§ШіШӘ");
  const safeAmountToman = clampInt(amountToman, 0, 1000000000000);
  if (safeAmountToman < 10000) throw new Error("ШӯШҜШ§ЩӮЩ„ Щ…ШЁЩ„Шә ШҙШ§ШұЪҳ ЫұЫ°Щ¬Ы°Ы°Ы° ШӘЩҲЩ…Ш§ЩҶ Ш§ШіШӘ");
  const invoiceId = id("spli");
  const fx = await resolveResellerPlisioFxRateForInvoice(env, bot, ctx);
  const sourceAmount = resellerPlisioSourceAmount(safeAmountToman, fx.rate_toman);
  const sourceCurrency = "USD";
  const urls = resellerPlisioUrls(origin, bot);
  const params = {
    source_currency: sourceCurrency,
    source_amount: sourceAmount.toFixed(2),
    order_number: invoiceId,
    order_name: "BluePanel wallet recharge",
    description: "Wallet recharge " + safeAmountToman + " toman",
    callback_url: urls.callback_url,
    success_invoice_url: urls.return_url + "?status=success",
    fail_invoice_url: urls.return_url + "?status=failed",
    expire_min: Math.max(5, Math.min(1440, Number(bot.plisio_expire_minutes || 60))),
    return_existing: "true"
  };
  const allowed = cleanText(bot.plisio_allowed_currencies || "", 500).replace(/\s+/g, "").toUpperCase();
  if (allowed) params.allowed_psys_cids = allowed;
  let provider;
  try {
    provider = await resellerPlisioRequest(env, bot, "/invoices/new", params);
  } catch (error) {
    scheduleSalesInvoiceBackground(ctx, recordResellerPlisioState(env, bot.id, false, error.message), "record reseller Plisio error failed");
    throw new Error("ШіШ§Ш®ШӘ ЩҒШ§Ъ©ШӘЩҲШұ Plisio ЩҶШ§Щ…ЩҲЩҒЩӮ ШЁЩҲШҜ: " + error.message);
  }
  const providerInvoiceId = cleanText(provider.txn_id || provider.id, 160);
  const paymentLink = cleanText(provider.invoice_url || provider.url, 1000);
  if (!providerInvoiceId || !paymentLink) throw new Error("ЩҫШ§ШіШ® Plisio ЩҶШ§ЩӮШө Ш§ШіШӘ");
  const ts = nowIso();
  const amountRial = safeAmountToman * 10;
  await env.PASARGUARD_DB.prepare(`
    INSERT INTO sales_payment_invoices(
      id,bot_id,customer_id,provider,provider_invoice_id,target_type,target_id,
      amount_rial,amount_toman,final_amount_rial,status,payment_link,card_number,provider_payload,created_at,updated_at
    ) VALUES(?,?,?,'plisio',?,?,?,?,?,?,?,?,NULL,?,?,?)
  `).bind(
    invoiceId, bot.id, customer.id, providerInvoiceId, safeTargetType, targetId,
    amountRial, safeAmountToman, amountRial, normalizePlisioStatus(provider.status), paymentLink,
    JSON.stringify({ request: params, response: provider, fx: { rate_toman: fx.rate_toman, source: fx.source, stale: !!fx.stale, fetched_at: fx.fetched_at || "" } }), ts, ts
  ).run();
  scheduleSalesInvoiceBackground(ctx, recordResellerPlisioState(env, bot.id, true), "record reseller Plisio success failed");
  scheduleSalesInvoiceBackground(ctx, salesEvent(env, bot.id, customer.id, "plisio_invoice_created", {
    invoiceId, providerInvoiceId, targetType: safeTargetType, targetId,
    amountToman: safeAmountToman, sourceAmount, sourceCurrency, fxRateToman: fx.rate_toman, fxSource: fx.source
  }), "reseller Plisio invoice event failed");
  return {
    id: invoiceId,
    provider: "plisio",
    invoice_id: providerInvoiceId,
    provider_invoice_id: providerInvoiceId,
    target_type: safeTargetType,
    target_id: targetId,
    amount_toman: safeAmountToman,
    amount_rial: amountRial,
    final_amount_rial: amountRial,
    source_amount: sourceAmount,
    source_currency: sourceCurrency,
    fx_rate_toman: fx.rate_toman,
    fx_source: fx.source,
    status: normalizePlisioStatus(provider.status),
    payment_link: paymentLink
  };
}

async function createSalesPlisioWalletCharge(env, bot, customer, amount, origin, ctx = null) {
  salesRequireVerifiedPhone(bot, customer);
  const safeAmount = clampInt(amount, 0, 1000000000000);
  if (safeAmount < 10000) throw new Error("ШӯШҜШ§ЩӮЩ„ Щ…ШЁЩ„Шә ШҙШ§ШұЪҳ ЫұЫ°Щ¬Ы°Ы°Ы° ШӘЩҲЩ…Ш§ЩҶ Ш§ШіШӘ");
  await enforceSalesSecurity(env, bot, customer, "wallet_charge", safeAmount);
  const requestId = id("wreq");
  const ts = nowIso();
  await env.PASARGUARD_DB.prepare(`
    INSERT INTO sales_wallet_requests(id,bot_id,customer_id,amount_toman,status,origin,created_at,updated_at)
    VALUES(?,?,?,?,'payment_pending',?,?,?)
  `).bind(requestId, bot.id, customer.id, safeAmount, origin === "miniapp" ? "miniapp" : "bot", ts, ts).run();
  try {
    const invoice = await createSalesPlisioInvoice(env, bot, customer, "wallet", requestId, safeAmount, origin, ctx);
    const bonusPercent = Math.max(0, Math.min(100, Number(bot.recharge_bonus_percent || 0)));
    const bonusAmount = Math.floor(safeAmount * bonusPercent / 100);
    return { requestId, amountToman: safeAmount, bonusPercent, bonusAmount, invoice };
  } catch (error) {
    await env.PASARGUARD_DB.prepare("UPDATE sales_wallet_requests SET status='rejected',updated_at=? WHERE id=?")
      .bind(nowIso(), requestId).run();
    throw error;
  }
}

function uniqueProcessedAtToken() {
  const suffix = String(crypto.getRandomValues(new Uint32Array(1))[0]).padStart(10, "0").slice(0, 6);
  return nowIso().replace("Z", suffix + "Z");
}

async function finalizeSalesPlisioWallet(env, bot, payment) {
  const requestRow = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_wallet_requests WHERE id=? AND bot_id=? AND customer_id=?")
    .bind(payment.target_id, bot.id, payment.customer_id).first();
  if (!requestRow) throw new Error("ШҜШұШ®ЩҲШ§ШіШӘ ШҙШ§ШұЪҳ Щ…ШұШӘШЁШ· ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  if (requestRow.status === "approved" || payment.processed_at) return { already_processed: true };
  const bonusPercent = Math.max(0, Math.min(100, Number(bot.recharge_bonus_percent || 0)));
  const baseAmount = Number(payment.amount_toman || 0);
  const bonusAmount = Math.floor(baseAmount * bonusPercent / 100);
  const creditedAmount = baseAmount + bonusAmount;
  const token = uniqueProcessedAtToken();
  const ledgerId = "cled_plisio_" + String(payment.id).replace(/[^a-zA-Z0-9_]/g, "");
  const results = await env.PASARGUARD_DB.batch([
    env.PASARGUARD_DB.prepare(`
      UPDATE sales_payment_invoices SET processed_at=?,updated_at=?,error_message=NULL
      WHERE id=? AND processed_at IS NULL AND status='PAID'
    `).bind(token, token, payment.id),
    env.PASARGUARD_DB.prepare(`
      UPDATE sales_wallet_requests SET status='approved',bonus_toman=?,reviewed_at=?,updated_at=?
      WHERE id=? AND EXISTS(SELECT 1 FROM sales_payment_invoices WHERE id=? AND processed_at=?)
    `).bind(bonusAmount, token, token, requestRow.id, payment.id, token),
    env.PASARGUARD_DB.prepare(`
      UPDATE sales_customers SET wallet_balance=wallet_balance+?,updated_at=?
      WHERE id=? AND bot_id=? AND EXISTS(SELECT 1 FROM sales_payment_invoices WHERE id=? AND processed_at=?)
    `).bind(creditedAmount, token, payment.customer_id, bot.id, payment.id, token),
    env.PASARGUARD_DB.prepare(`
      INSERT OR IGNORE INTO sales_customer_ledger(id,bot_id,customer_id,type,amount,balance_after,ref_type,ref_id,description,created_at)
      SELECT ?,?,?, 'recharge', ?, wallet_balance, 'plisio', ?, ?, ?
      FROM sales_customers WHERE id=? AND bot_id=? AND EXISTS(SELECT 1 FROM sales_payment_invoices WHERE id=? AND processed_at=?)
    `).bind(
      ledgerId, bot.id, payment.customer_id, creditedAmount, payment.id,
      bonusAmount > 0 ? ("ШҙШ§ШұЪҳ ШұЩ…ШІШ§ШұШІЫҢ Plisio + ШЁЩҲЩҶШі " + bonusPercent + "ЩӘ") : "ШҙШ§ШұЪҳ ШұЩ…ШІШ§ШұШІЫҢ Plisio",
      token, payment.customer_id, bot.id, payment.id, token
    )
  ]);
  const processed = Number(results?.[0]?.meta?.changes || 0) > 0;
  if (processed) {
    const customer = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_customers WHERE id=?").bind(payment.customer_id).first();
    if (customer) {
      await createSalesNotification(env, bot, customer, null, "payment_success", "ШҙШ§ШұЪҳ ШұЩ…ШІШ§ШұШІЫҢ Щ…ЩҲЩҒЩӮ", "Щ…ШЁЩ„Шә " + botMoney(creditedAmount) + " ШӘЩҲЩ…Ш§ЩҶ ШЁЩҮ Ъ©ЫҢЩҒ ЩҫЩҲЩ„ ШҙЩ…Ш§ Ш§Ш¶Ш§ЩҒЩҮ ШҙШҜ.", "plisio_wallet:" + payment.id, { sendBot: false });
      try {
        await resellerTelegramApi(env, bot, "sendMessage", {
          chat_id: customer.telegram_id,
          text: "вң… ЩҫШұШҜШ§Ш®ШӘ ШұЩ…ШІШ§ШұШІЫҢ Plisio ШӘШЈЫҢЫҢШҜ ШҙШҜ.\nЩ…ШЁЩ„Шә Ш§ЩҒШІЩҲШҜЩҮвҖҢШҙШҜЩҮ: <b>" + botMoney(creditedAmount) + " ШӘЩҲЩ…Ш§ЩҶ</b>",
          parse_mode: "HTML"
        });
      } catch (_) {}
    }
    await salesEvent(env, bot.id, payment.customer_id, "plisio_wallet_credited", { paymentId: payment.id, baseAmount, bonusAmount, creditedAmount });
    await queueReportEvent(env, bot.id, "payments", "ШҙШ§ШұЪҳ Ш®ЩҲШҜЪ©Ш§Шұ Plisio ШӘШЈЫҢЫҢШҜ ШҙШҜ",
      "Щ…ШҙШӘШұЫҢ: <code>" + botEscape(customer?.telegram_id || payment.customer_id) + "</code>\n" +
      "Щ…ШЁЩ„Шә: <b>" + botMoney(baseAmount) + " ШӘЩҲЩ…Ш§ЩҶ</b>" +
      (bonusAmount > 0 ? "\nШЁЩҲЩҶШі: <b>" + botMoney(bonusAmount) + " ШӘЩҲЩ…Ш§ЩҶ</b>" : "") +
      "\nЩҒШ§Ъ©ШӘЩҲШұ: <code>" + botEscape(payment.provider_invoice_id) + "</code>",
      "plisio-wallet:" + payment.id).catch(() => null);
  }
  return { processed, bonusAmount, creditedAmount };
}

async function applyVerifiedSalesPlisioPayment(env, bot, payment, payload) {
  const operation = resellerPlisioOperationData(payload);
  if (operation.order_number && operation.order_number !== String(payment.id)) throw new Error("ШҙЩ…Ш§ШұЩҮ ШіЩҒШ§ШұШҙ Plisio ШӘШ·ШЁЫҢЩӮ ЩҶШҜШ§ШұШҜ");
  if (!operation.order_number && operation.txn_id !== String(payment.provider_invoice_id)) throw new Error("ШҙЩҶШ§ШіЩҮ ЩҒШ§Ъ©ШӘЩҲШұ Plisio ШӘШ·ШЁЫҢЩӮ ЩҶШҜШ§ШұШҜ");
  let stored = {};
  try { stored = JSON.parse(payment.provider_payload || "{}"); } catch (_) {}
  const expectedSourceAmount = Number(stored?.request?.source_amount);
  const expectedSourceCurrency = cleanText(stored?.request?.source_currency || "", 20).toUpperCase();
  if (Number.isFinite(expectedSourceAmount) && Number.isFinite(operation.source_amount) && Math.abs(expectedSourceAmount - operation.source_amount) > 0.011) {
    throw new Error("Щ…ШЁЩ„Шә Callback ШЁШ§ ЩҒШ§Ъ©ШӘЩҲШұ ШҜШ§Ш®Щ„ЫҢ ШӘШ·ШЁЫҢЩӮ ЩҶШҜШ§ШұШҜ");
  }
  if (expectedSourceCurrency && operation.source_currency && expectedSourceCurrency !== operation.source_currency) {
    throw new Error("Ш§ШұШІ Щ…ШЁЩҶШ§ЫҢ Callback ШЁШ§ ЩҒШ§Ъ©ШӘЩҲШұ ШҜШ§Ш®Щ„ЫҢ ШӘШ·ШЁЫҢЩӮ ЩҶШҜШ§ШұШҜ");
  }
  const status = normalizePlisioStatus(operation.status);
  const ts = nowIso();
  if (status !== "PAID") {
    await env.PASARGUARD_DB.prepare("UPDATE sales_payment_invoices SET status=?,provider_payload=?,updated_at=? WHERE id=? AND processed_at IS NULL")
      .bind(status, JSON.stringify({ ...(stored || {}), callback: payload }), ts, payment.id).run();
    if (["EXPIRED", "CANCELED", "FAILED"].includes(status)) {
      await env.PASARGUARD_DB.prepare("UPDATE sales_wallet_requests SET status='rejected',updated_at=? WHERE id=? AND status='payment_pending'")
        .bind(ts, payment.target_id).run();
    }
    return { status, processed: false };
  }
  await env.PASARGUARD_DB.prepare("UPDATE sales_payment_invoices SET status='PAID',paid_at=?,provider_payload=?,updated_at=? WHERE id=?")
    .bind(cleanText(operation.finished_at_utc, 100) || ts, JSON.stringify({ ...(stored || {}), callback: payload }), ts, payment.id).run();
  await recordResellerPlisioState(env, bot.id, true).catch(() => null);
  const fresh = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_payment_invoices WHERE id=?").bind(payment.id).first();
  if (fresh.processed_at) return { status: "PAID", processed: true };
  return finalizeSalesPlisioWallet(env, bot, fresh);
}

async function salesPaymentStatus(env, bot, customer, paymentId) {
  const payment = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_payment_invoices WHERE id=? AND bot_id=? AND customer_id=?")
    .bind(paymentId, bot.id, customer.id).first();
  if (!payment) throw new Error("ЩҒШ§Ъ©ШӘЩҲШұ ШўЩҶЩ„Ш§ЫҢЩҶ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  const provider = String(payment.provider || "").toLowerCase();
  if (provider === "plisio") return payment;
  if (provider === "cubepay") return reconcileSalesCubepayPayment(env, bot, payment);
  return salesBlupalPaymentStatus(env, bot, customer, paymentId);
}

async function resellerPlisioCallback(request, env, botId) {
  await ensureDb(env);
  const bot = await getResellerBotById(env, botId);
  if (!bot) return fail("Not found", 404, "NOT_FOUND");
  let payload;
  try { payload = await parseBody(request); } catch (_) { return fail("Invalid callback payload", 400, "INVALID_CALLBACK"); }
  let secret;
  try { secret = await resellerPlisioApiKey(env, bot); } catch (error) { return fail(error.message, 503, "PLISIO_NOT_CONFIGURED"); }
  if (!(await verifyResellerPlisioCallback(payload, secret))) {
    await recordResellerPlisioState(env, bot.id, false, "Ш§Щ…Ш¶Ш§ЫҢ Callback ЩҶШ§Щ…Ш№ШӘШЁШұ ШЁЩҲШҜ").catch(() => null);
    return fail("Invalid callback signature", 422, "INVALID_SIGNATURE");
  }
  const operation = resellerPlisioOperationData(payload);
  if (!operation.txn_id && !operation.order_number) return fail("Invalid callback payload", 400, "INVALID_CALLBACK");
  let payment = null;
  if (operation.txn_id) payment = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_payment_invoices WHERE bot_id=? AND provider='plisio' AND provider_invoice_id=?")
    .bind(bot.id, operation.txn_id).first();
  if (!payment && operation.order_number) payment = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_payment_invoices WHERE bot_id=? AND provider='plisio' AND id=?")
    .bind(bot.id, operation.order_number).first();
  if (!payment) return fail("Invoice not found", 404, "NOT_FOUND");
  try {
    await applyVerifiedSalesPlisioPayment(env, bot, payment, payload);
    return json({ received: true });
  } catch (error) {
    await recordResellerPlisioState(env, bot.id, false, error.message).catch(() => null);
    await env.PASARGUARD_DB.prepare("UPDATE sales_payment_invoices SET error_message=?,updated_at=? WHERE id=?")
      .bind(cleanText(error.message, 800), nowIso(), payment.id).run();
    return fail("Callback processing failed", 500, "CALLBACK_FAILED");
  }
}

function resellerPlisioReturnPage(bot, origin, url) {
  const urls = resellerPlisioUrls(origin, bot);
  const deepLink = "https://t.me/" + String(bot.bot_username || "").replace(/^@/, "") + "?startapp=payment";
  const ok = String(url?.searchParams?.get("status") || "").toLowerCase() === "success";
  return `<!doctype html><html lang="fa" dir="rtl"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><meta name="robots" content="noindex,nofollow"><meta name="theme-color" content="#f4f7ff"><title>ШЁШ§ШІЪҜШҙШӘ Ш§ШІ Plisio</title><style>*{box-sizing:border-box}body{margin:0;min-height:100vh;display:grid;place-items:center;padding:20px;background:radial-gradient(circle at 90% 0,#536dfe22,transparent 38%),linear-gradient(180deg,#f8faff,#eef4ff);color:#18233a;font-family:Tahoma,Arial}.card{width:min(100%,480px);border-radius:28px;padding:28px;background:#fffffff2;box-shadow:0 24px 70px #40508025;text-align:center}.icon{width:72px;height:72px;display:grid;place-items:center;margin:auto;border-radius:24px;background:#35d39a22;font-size:36px}.muted{color:#6d7890;line-height:1.9;font-size:13px}.btn{display:block;text-decoration:none;margin-top:12px;border-radius:16px;padding:14px;background:linear-gradient(135deg,#4e8cff,#765eff);color:#fff;font-weight:900}.secondary{background:#eef2ff;color:#425073}</style></head><body><main class="card"><div class="icon">${ok ? "вң…" : "вҶ©пёҸ"}</div><h1>ШЁШ§ШІЪҜШҙШӘ Ш§ШІ ЩҫШұШҜШ§Ш®ШӘ Plisio</h1><p class="muted">ЩҲШ¶Ш№ЫҢШӘ ЩҶЩҮШ§ЫҢЫҢ ЩҒЩӮШ· Ш§ШІ Callback Ш§Щ…Ш¶Ш§ШҙШҜЩҮ Plisio ШҜШұЫҢШ§ЩҒШӘ Щ…ЫҢвҖҢШҙЩҲШҜ. ШЁШұШ§ЫҢ Щ…ШҙШ§ЩҮШҜЩҮ Щ…ЩҲШ¬ЩҲШҜЫҢ Ш¬ШҜЫҢШҜ ШЁЩҮ Щ…ЫҢЩҶЫҢвҖҢШ§Щҫ ${String(bot.brand_name || "ЩҒШұЩҲШҙЪҜШ§ЩҮ").replace(/[<>&]/g, "")} ШЁШұЪҜШұШҜЫҢШҜ.</p><a class="btn" href="${deepLink}">ШЁШ§ШІЪ©ШұШҜЩҶ Щ…ЫҢЩҶЫҢвҖҢШ§Щҫ ШҜШұ ШӘЩ„ЪҜШұШ§Щ…</a><a class="btn secondary" href="${urls.miniapp_url}#wallet">Щ…ШҙШ§ЩҮШҜЩҮ ЩҲШ¶Ш№ЫҢШӘ ЩҫШұШҜШ§Ш®ШӘ</a></main></body></html>`;
}

async function resellerBlupalWebhook(request, env, ctx, botId) {
  await ensureDb(env);
  const bot = await getResellerBotById(env, botId);
  if (!bot) return fail("Not found", 404, "NOT_FOUND");
  const url = new URL(request.url);
  const supplied = url.searchParams.get("token") || request.headers.get("x-webhook-token") || "";
  if (!bot.blupal_webhook_token || !constantTimeTextEqual(supplied, bot.blupal_webhook_token)) return fail("Forbidden", 403, "FORBIDDEN");
  const payload = await parseBody(request);
  if (!payload || payload.success !== true || payload.event !== "payment.completed" || normalizePaymentStatus(payload.status) !== "PAID" || !payload.invoice_id) {
    return fail("Invalid webhook payload", 400, "INVALID_WEBHOOK");
  }
  ctx.waitUntil((async () => {
    const payment = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_payment_invoices WHERE bot_id=? AND provider='blupal' AND provider_invoice_id=?")
      .bind(bot.id, cleanText(payload.invoice_id, 100)).first();
    if (!payment) return;
    try { await reconcileSalesBlupalInvoice(env, payment); }
    catch (error) { await env.PASARGUARD_DB.prepare("UPDATE sales_payment_invoices SET error_message=?,updated_at=? WHERE id=?").bind(cleanText(error.message,800),nowIso(),payment.id).run(); }
  })());
  return json({ received: true });
}

function resellerBlupalReturnPage(bot, origin) {
  const urls = resellerPaymentUrls(origin, bot);
  const deepLink = "https://t.me/" + String(bot.bot_username || "").replace(/^@/, "") + "?startapp=payment";
  return `<!doctype html><html lang="fa" dir="rtl"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><meta name="theme-color" content="#f4f7ff"><title>ШЁШ§ШІЪҜШҙШӘ Ш§ШІ ЩҫШұШҜШ§Ш®ШӘ</title><style>*{box-sizing:border-box}body{margin:0;min-height:100vh;display:grid;place-items:center;padding:20px;background:radial-gradient(circle at 90% 0,#536dfe22,transparent 38%),linear-gradient(180deg,#f8faff,#eef4ff);color:#18233a;font-family:Tahoma,Arial}.card{width:min(100%,480px);border:1px solid #ffffff22;border-radius:28px;padding:28px;background:#fffffff2;box-shadow:0 24px 70px #40508025;text-align:center}.icon{width:72px;height:72px;display:grid;place-items:center;margin:auto;border-radius:24px;background:#35d39a22;font-size:36px}.muted{color:#6d7890;line-height:1.9;font-size:13px}.btn{display:block;text-decoration:none;margin-top:12px;border-radius:16px;padding:14px;background:linear-gradient(135deg,#4e8cff,#765eff);color:#fff;font-weight:900}.secondary{background:#eef2ff;color:#425073}</style></head><body><main class="card"><div class="icon">вң…</div><h1>ШЁШ§ШІЪҜШҙШӘ Ш§ШІ ЩҫШұШҜШ§Ш®ШӘ</h1><p class="muted">ЩҲШ¶Ш№ЫҢШӘ ЩҫШұШҜШ§Ш®ШӘ ШЁЩҮвҖҢШөЩҲШұШӘ Ш§Щ…ЩҶ Ш§ШІ ШЁЩ„ЩҲЩҫШ§Щ„ Ш§ШіШӘШ№Щ„Ш§Щ… Щ…ЫҢвҖҢШҙЩҲШҜ. ШЁШұШ§ЫҢ Щ…ШҙШ§ЩҮШҜЩҮ ЩҶШӘЫҢШ¬ЩҮ ЩҲ ШҜШұЫҢШ§ЩҒШӘ ШіШұЩҲЫҢШіШҢ ШЁЩҮ Щ…ЫҢЩҶЫҢвҖҢШ§Щҫ ${String(bot.brand_name || "ЩҒШұЩҲШҙЪҜШ§ЩҮ").replace(/[<>&]/g, "")} ШЁШұЪҜШұШҜЫҢШҜ.</p><a class="btn" href="${deepLink}">ШЁШ§ШІЪ©ШұШҜЩҶ Щ…ЫҢЩҶЫҢвҖҢШ§Щҫ ШҜШұ ШӘЩ„ЪҜШұШ§Щ…</a><a class="btn secondary" href="${urls.miniapp_url}#wallet">Щ…ШҙШ§ЩҮШҜЩҮ ЩҲШ¶Ш№ЫҢШӘ ЩҫШұШҜШ§Ш®ШӘ</a></main></body></html>`;
}

async function authenticateSalesMiniApp(request, env, botId, ctx = null) {
  await ensureDb(env);
  const bot = await getResellerBotForWebhook(env, botId);
  if (!bot) throw new Error("ШұШЁШ§ШӘ ЩҶЩ…Ш§ЫҢЩҶШҜЪҜЫҢ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
  scheduleResellerRuntimeUpdate(env, bot, ctx);
  if (bot.status !== "active") throw new Error("ЩҒШұЩҲШҙ Ш§ЫҢЩҶ ШұШЁШ§ШӘ Щ…ЩҲЩӮШӘШ§ЩӢ Щ…ШӘЩҲЩӮЩҒ Ш§ШіШӘ");
  resellerRequireActiveLicense(bot);
  const initData = request.headers.get("x-telegram-init-data") || "";
  if (initData) {
    const telegramUser = await validateTelegramInitData(initData, await resellerBotToken(env, bot), 86400);
    const isOwner = String(telegramUser.id || "") === String(bot.owner_telegram_id || "");
    const joinStatus = await resellerRequiredJoinStatus(env, bot, telegramUser.id, isOwner);
    if (!joinStatus.ok) throw joinRequiredError(joinStatus.missing);
    const customer = await ensureSalesCustomer(env, bot, telegramUser);
    return { bot, customer, telegramUser, authMode: "telegram" };
  }
  const session = await webSessionFromRequest(request, env, "sales", bot.id);
  if (!session?.customer_id) throw webAuthError("ШЁШұШ§ЫҢ ЩҲШұЩҲШҜ ШЁЩҮ ЩҒШұЩҲШҙЪҜШ§ЩҮШҢ Ъ©ШҜ ЫҢЪ©вҖҢШЁШ§ШұЩ…ШөШұЩҒ ШҜШұЫҢШ§ЩҒШӘ Ъ©ЩҶЫҢШҜ");
  const customer = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_customers WHERE id=? AND bot_id=? AND status='active'").bind(session.customer_id, bot.id).first();
  if (!customer) throw webAuthError("ЩҶШҙШіШӘ ЩҶШіШ®ЩҮ ЩҲШЁ Щ…Ш№ШӘШЁШұ ЩҶЫҢШіШӘШӣ ШҜЩҲШЁШ§ШұЩҮ ЩҲШ§ШұШҜ ШҙЩҲЫҢШҜ");
  const isOwner = String(customer.telegram_id || "") === String(bot.owner_telegram_id || "");
  const joinStatus = await resellerRequiredJoinStatus(env, bot, customer.telegram_id, isOwner);
  if (!joinStatus.ok) throw joinRequiredError(joinStatus.missing);
  return { bot, customer, telegramUser: { id: customer.telegram_id, username: customer.username, first_name: customer.first_name, last_name: customer.last_name }, authMode: "web" };
}

async function salesMiniAppBootstrap(request, env, botId, ctx = null) {
  try {
    const { bot, customer, authMode } = await authenticateSalesMiniApp(request, env, botId, ctx);
    // One remote D1 batch replaces twelve Edge -> Core round-trips during initial panel load.
    const bootstrapBatch = await env.PASARGUARD_DB.batch([
      env.PASARGUARD_DB.prepare("SELECT id,title,emoji,location_id,sort_order FROM sales_categories WHERE bot_id=? AND status='active' ORDER BY sort_order,created_at").bind(bot.id),
      env.PASARGUARD_DB.prepare("SELECT id,title,emoji,description,sort_order FROM sales_locations WHERE bot_id=? AND status='active' ORDER BY sort_order,created_at").bind(bot.id),
      env.PASARGUARD_DB.prepare(`SELECT p.id,p.title,p.data_limit_bytes,p.duration_days,p.price_toman,p.category_id,p.location_id,p.plan_type,c.title AS category_title,c.emoji AS category_emoji,l.title AS location_title,l.emoji AS location_emoji FROM sales_plans p LEFT JOIN sales_categories c ON c.id=p.category_id LEFT JOIN sales_locations l ON l.id=p.location_id WHERE p.bot_id=? AND p.status='active' ORDER BY p.sort_order,p.price_toman,p.created_at`).bind(bot.id),
      env.PASARGUARD_DB.prepare(`SELECT o.id,o.service_provider,o.amount_toman,o.original_amount_toman,o.discount_toman,o.promo_code,o.cashback_toman,o.status,o.order_type,o.target_order_id,o.payment_method,o.origin,o.remote_username,o.subscription_url,o.remote_status,o.remote_data_limit,o.remote_used_traffic,o.remote_expire,o.remote_online_at,o.remote_last_synced_at,o.error_message,o.created_at,o.updated_at,p.title AS plan_title,p.data_limit_bytes,p.duration_days,p.category_id,p.location_id,c.title AS category_title,c.emoji AS category_emoji,l.title AS location_title,l.emoji AS location_emoji FROM sales_orders o JOIN sales_plans p ON p.id=o.plan_id LEFT JOIN sales_categories c ON c.id=p.category_id LEFT JOIN sales_locations l ON l.id=p.location_id WHERE o.bot_id=? AND o.customer_id=? ORDER BY o.created_at DESC LIMIT 80`).bind(bot.id,customer.id),
      env.PASARGUARD_DB.prepare("SELECT type,amount,balance_after,description,created_at FROM sales_customer_ledger WHERE customer_id=? ORDER BY created_at DESC LIMIT 30").bind(customer.id),
      env.PASARGUARD_DB.prepare("SELECT id,amount_toman,status,bonus_toman,origin,created_at,updated_at FROM sales_wallet_requests WHERE bot_id=? AND customer_id=? ORDER BY created_at DESC LIMIT 20").bind(bot.id,customer.id),
      env.PASARGUARD_DB.prepare("SELECT COUNT(*) AS c FROM sales_customers WHERE referrer_customer_id=?").bind(customer.id),
      env.PASARGUARD_DB.prepare("SELECT id,status,origin,remote_username,subscription_url,error_message,created_at,updated_at FROM sales_trials WHERE bot_id=? AND customer_id=?").bind(bot.id,customer.id),
      env.PASARGUARD_DB.prepare("SELECT text_key,text_value FROM reseller_bot_texts WHERE bot_id=?").bind(bot.id),
      env.PASARGUARD_DB.prepare("SELECT id,order_id,type,title,message,status,created_at,read_at FROM sales_notifications WHERE bot_id=? AND customer_id=? ORDER BY created_at DESC LIMIT 40").bind(bot.id,customer.id),
      env.PASARGUARD_DB.prepare("SELECT id,public_code,category,priority,subject,status,last_message_at,created_at,updated_at,closed_at FROM sales_tickets WHERE bot_id=? AND customer_id=? ORDER BY last_message_at DESC LIMIT 50").bind(bot.id,customer.id),
      env.PASARGUARD_DB.prepare("SELECT id,provider,provider_invoice_id,target_type,target_id,amount_toman,final_amount_rial,status,payment_link,card_number,paid_at,processed_at,error_message,created_at,updated_at FROM sales_payment_invoices WHERE bot_id=? AND customer_id=? ORDER BY created_at DESC LIMIT 30").bind(bot.id,customer.id)
    ]);
    const batchRows = index => bootstrapBatch[index] || { results: [] };
    const categories = batchRows(0);
    const locations = batchRows(1);
    const plans = batchRows(2);
    const orders = batchRows(3);
    const ledger = batchRows(4);
    const walletRequests = batchRows(5);
    const referralCount = (batchRows(6).results || [])[0] || {};
    const trial = (batchRows(7).results || [])[0] || null;
    const textRows = batchRows(8);
    const notifications = batchRows(9);
    const tickets = batchRows(10);
    const paymentInvoices = batchRows(11);
    const orderRows = orders.results || [];
    const services = buildSalesServices(orderRows);
    const activePromo = await salesActivePromoForCustomer(env, bot.id, customer);
    const texts = { ...SALES_TEXT_DEFAULTS };
    for (const row of textRows.results || []) if (SALES_TEXT_LABELS[row.text_key]) texts[row.text_key] = cleanText(row.text_value, 3500) || texts[row.text_key];
    const referralLink = "https://t.me/" + bot.bot_username.replace(/^@/, "") + "?start=ref_" + customer.referral_code;
    return json({
      success: true,
      version: APP_VERSION,
      auth_mode: authMode || "telegram",
      bot: {
        id: bot.id, brand_name: bot.brand_name, bot_username: bot.bot_username,
        support_url: salesSupportUrl(bot), card_holder: bot.card_holder,
        card_number: formatCardNumber(bot.card_number), card_number_raw: normalizeCardNumber(bot.card_number), bank_name: bot.bank_name,
        trial_enabled: Number(bot.trial_enabled || 0) === 1,
        trial_data_limit_bytes: Number(bot.trial_data_limit_bytes || 0),
        trial_duration_days: Number(bot.trial_duration_days || 0),
        trial_duration_hours: Number(bot.trial_duration_hours || Number(bot.trial_duration_days || 1) * 24),
        referral_reward_toman: Number(bot.referral_reward_toman || 0),
        referral_reward_type: String(bot.referral_reward_type || "fixed"),
        referral_reward_percent: Number(bot.referral_reward_percent || 0),
        recharge_bonus_percent: Number(bot.recharge_bonus_percent || 0),
        cashback_enabled: Number(bot.cashback_enabled || 0) === 1,
        cashback_percent: Number(bot.cashback_percent || 0),
        cashback_min_purchase_toman: Number(bot.cashback_min_purchase_toman || 0),
        cashback_max_toman: Number(bot.cashback_max_toman || 0),
        notifications_enabled: Number(bot.notifications_enabled ?? 1) === 1,
        expiry_reminder_hours: Number(bot.expiry_reminder_hours || 48),
        usage_reminder_percent: Number(bot.usage_reminder_percent || 80),
        ticketing_enabled: Number(bot.ticketing_enabled ?? 1) === 1,
        phone_verification_required: Number(bot.phone_verification_required || 0) === 1,
        ticket_auto_close_hours: Number(bot.ticket_auto_close_hours || 72),
        sales_automation_enabled: Number(bot.sales_automation_enabled ?? 1) === 1,
        loyalty_enabled: Number(bot.loyalty_enabled ?? 1) === 1,
        loyalty_profile: String(bot.loyalty_profile || "standard"),
        fraud_protection_enabled: Number(bot.fraud_protection_enabled ?? 1) === 1,
        payment_card_enabled: resellerPaymentMethodEnabled(bot, "card"),
        payment_wallet_enabled: resellerPaymentMethodEnabled(bot, "wallet"),
        payment_methods_order: resellerPaymentMethodOrder(bot),
        payment_default_method: resellerPaymentDefaultMethod(bot, "order"),
        blupal_enabled: resellerPaymentMethodEnabled(bot, "blupal"),
        plisio_enabled: resellerPlisioConfigured(bot),
        cubepay_enabled: resellerCubepayConfigured(bot),
        online_payment_label: "ЩҫШұШҜШ§Ш®ШӘ ШўЩҶЩ„Ш§ЫҢЩҶ ШЁЩ„ЩҲЩҫШ§Щ„",
        plisio_payment_label: "ЩҫШұШҜШ§Ш®ШӘ ШұЩ…ШІШ§ШұШІЫҢ Plisio",
        cubepay_payment_label: "Ъ©Ш§ШұШӘвҖҢШЁЩҮвҖҢЪ©Ш§ШұШӘ Ш®ЩҲШҜЪ©Ш§Шұ CubePay",
        bot_version: APP_VERSION
      },
      customer: {
        id: customer.id, telegram_id: customer.telegram_id, username: customer.username,
        first_name: customer.first_name, last_name: customer.last_name,
        wallet_balance: Number(customer.wallet_balance || 0), referral_code: customer.referral_code,
        customer_type: String(customer.customer_type || "retail"), discount_percent: Number(customer.discount_percent || 0),
        lifetime_spend_toman: Number(customer.lifetime_spend_toman || 0), loyalty_level: String(customer.loyalty_level || "bronze"),
        loyalty_discount_percent: Number(customer.loyalty_discount_percent || 0), last_purchase_at: customer.last_purchase_at || null,
        risk_level: String(customer.risk_level || "normal"),
        phone_number: normalizeSalesPhone(customer.phone_number), phone_verified: salesPhoneVerified(customer),
        phone_verified_at: customer.phone_verified_at || null,
        active_promo: salesPromoPublic(activePromo),
        referral_link: referralLink, referrals_count: Number(referralCount?.c || 0)
      },
      texts,
      categories: categories.results || [], locations: locations.results || [], plans: plans.results || [],
      orders: orderRows, services, ledger: ledger.results || [], wallet_requests: walletRequests.results || [], trial: trial || null,
      notifications: notifications.results || [],
      unread_notifications: (notifications.results || []).filter(row => row.status === "unread").length,
      tickets: tickets.results || [],
      open_tickets: (tickets.results || []).filter(row => row.status !== "closed").length,
      payment_invoices: paymentInvoices.results || []
    });
  } catch (error) {
    if (error?.code === "JOIN_REQUIRED") return json({ success: false, error: error.message, code: "JOIN_REQUIRED", channels: error.channels || [] }, 403);
    if (error?.code === "WEB_LOGIN_REQUIRED") return fail(error.message || "ЩҲШұЩҲШҜ ЩҶШіШ®ЩҮ ЩҲШЁ Щ„Ш§ШІЩ… Ш§ШіШӘ", 401, "WEB_LOGIN_REQUIRED");
    return fail(error.message || "Ш®Ш·Ш§ ШҜШұ ЩҲШұЩҲШҜ ШЁЩҮ Щ…ЫҢЩҶЫҢвҖҢШ§Щҫ", 401, error?.code || "SALES_APP_AUTH_FAILED");
  }
}

async function salesMiniAppAction(request, env, botId, ctx = null) {
  try {
    const { bot, customer } = await authenticateSalesMiniApp(request, env, botId, ctx);
    if (bot.status !== "active") throw new Error("ЩҒШұЩҲШҙ Ш§ЫҢЩҶ ШұШЁШ§ШӘ Щ…ЩҲЩӮШӘШ§ЩӢ Щ…ШӘЩҲЩӮЩҒ Ш§ШіШӘ");
    const body = await parseBody(request);
    const action = String(body.action || "");
    const promoCode = cleanText(body.promo_code, 80);
    const phoneProtectedActions = new Set([
      "create_order", "wallet_buy", "renew_order", "renew_wallet",
      "volume_order", "volume_wallet", "trial", "wallet_charge",
      "ticket_create", "ticket_reply"
    ]);
    if (phoneProtectedActions.has(action)) salesRequireVerifiedPhone(bot, customer);
    if (action === "notifications_read") {
      await env.PASARGUARD_DB.prepare("UPDATE sales_notifications SET status='read',read_at=? WHERE bot_id=? AND customer_id=? AND status='unread'").bind(nowIso(), bot.id, customer.id).run();
      return json({ success: true, message: "ЩҮЩ…ЩҮ Ш§Ш№Щ„Ш§ЩҶвҖҢЩҮШ§ Ш®ЩҲШ§ЩҶШҜЩҮ ШҙШҜЩҶШҜ." });
    }
    if (action === "payment_status") {
      const payment = await salesPaymentStatus(env, bot, customer, cleanText(body.payment_id, 100));
      const order = payment.target_type === "order" ? await env.PASARGUARD_DB.prepare("SELECT id,status,remote_username,subscription_url,order_type,cashback_toman FROM sales_orders WHERE id=? AND bot_id=? AND customer_id=?").bind(payment.target_id,bot.id,customer.id).first() : null;
      const wallet = payment.target_type === "wallet" ? await env.PASARGUARD_DB.prepare("SELECT id,status,bonus_toman FROM sales_wallet_requests WHERE id=? AND bot_id=? AND customer_id=?").bind(payment.target_id,bot.id,customer.id).first() : null;
      return json({ success: true, payment, order, wallet, message: payment.processed_at ? "ЩҫШұШҜШ§Ш®ШӘ ШЁШ§ Щ…ЩҲЩҒЩӮЫҢШӘ ЩҫШұШҜШ§ШІШҙ ШҙШҜ." : "ЩҲШ¶Ш№ЫҢШӘ ЩҒШ§Ъ©ШӘЩҲШұ ШЁШұЩҲШІШұШіШ§ЩҶЫҢ ШҙШҜ." });
    }
    if (action === "ticket_create") {
      const ticket = await createSalesTicket(env, bot, customer, {
        category: body.category, priority: body.priority, subject: body.subject, message: body.message
      });
      return json({ success: true, message: "ШӘЫҢЪ©ШӘ " + ticket.public_code + " Ш«ШЁШӘ ШҙШҜ ЩҲ ШҜШұ Ш§ЩҶШӘШёШ§Шұ ЩҫШ§ШіШ® ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ Ш§ШіШӘ.", ticket });
    }
    if (action === "ticket_detail") {
      const detail = await salesTicketDetailForCustomer(env, bot, customer, cleanText(body.ticket_id, 80));
      return json({ success: true, ...detail });
    }
    if (action === "ticket_reply") {
      const ticket = await replySalesTicketByCustomer(env, bot, customer, cleanText(body.ticket_id, 80), body.message);
      return json({ success: true, message: "ЩҫШ§ШіШ® ШҙЩ…Ш§ Ш«ШЁШӘ ШҙШҜ.", ticket });
    }
    if (action === "ticket_close") {
      const ticket = await closeSalesTicketByCustomer(env, bot, customer, cleanText(body.ticket_id, 80));
      return json({ success: true, message: "ШӘЫҢЪ©ШӘ ШЁШіШӘЩҮ ШҙШҜ.", ticket });
    }
    if (action === "promo_redeem") {
      const result = await salesActivatePromoCode(env, bot, customer, body.code);
      const message = result.kind === "gift"
        ? "Ъ©ШҜ ЩҮШҜЫҢЩҮ ЩҒШ№Ш§Щ„ ШҙШҜ ЩҲ " + botMoney(result.credit) + " ШӘЩҲЩ…Ш§ЩҶ ШЁЩҮ Ъ©ЫҢЩҒ ЩҫЩҲЩ„ Ш§Ш¶Ш§ЩҒЩҮ ШҙШҜ."
        : "Ъ©ШҜ ШӘШ®ЩҒЫҢЩҒ ЩҒШ№Ш§Щ„ ШҙШҜ ЩҲ ШұЩҲЫҢ Ш®ШұЫҢШҜ ШЁШ№ШҜЫҢ Ш§Ш№Щ…Ш§Щ„ Щ…ЫҢвҖҢШҙЩҲШҜ.";
      return json({ success: true, message, result });
    }
    if (action === "create_order") {
      const online = String(body.payment_method || "card") === "blupal";
      if (!online) requireSalesPaymentCard(bot);
      const order = await createSalesOrder(env, bot, customer, cleanText(body.plan_id, 80), { origin: "miniapp", promoCode, paymentMethod: online ? "blupal" : "card", status: online ? "payment_pending" : "awaiting_receipt" });
      if (online) {
        try {
          const invoice = await createSalesBlupalInvoice(env, bot, customer, "order", order.orderId, order.amountToman);
          return json({ success: true, message: "ЩҒШ§Ъ©ШӘЩҲШұ ШўЩҶЩ„Ш§ЫҢЩҶ ШіШ§Ш®ШӘЩҮ ШҙШҜШӣ ЩҫШі Ш§ШІ ЩҫШұШҜШ§Ш®ШӘШҢ ШіШұЩҲЫҢШі Ш®ЩҲШҜЪ©Ш§Шұ ШӘШӯЩҲЫҢЩ„ Щ…ЫҢвҖҢШҙЩҲШҜ.", online_payment: invoice });
        } catch (error) {
          await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='cancelled',error_message=?,updated_at=? WHERE id=?").bind(cleanText(error.message,800),nowIso(),order.orderId).run();
          try { await salesReleasePromoForOrder(env, order.orderId); } catch (_) {}
          throw error;
        }
      }
      return json({ success: true, message: "ШіЩҒШ§ШұШҙ ШіШ§Ш®ШӘЩҮ ШҙШҜШӣ Ш§Ш·Щ„Ш§Ш№Ш§ШӘ ЩҫШұШҜШ§Ш®ШӘ ЩҲ Ш«ШЁШӘ ШұШіЫҢШҜ ШҜШ§Ш®Щ„ Щ…ЫҢЩҶЫҢвҖҢШ§Щҫ Ш§ЩҶШ¬Ш§Щ… Щ…ЫҢвҖҢШҙЩҲШҜ.", payment: salesMiniAppPaymentPayload(bot, "order", order.orderId, order.amountToman, { title: order.plan.title, originalAmountToman: order.originalAmountToman, discountToman: order.discountToman, promoCode: order.promoCode }) });
    }
    if (action === "wallet_buy") {
      const delivered = await purchaseSalesPlanFromWallet(env, bot, customer, cleanText(body.plan_id, 80), { origin: "miniapp", promoCode });
      return json({ success: true, message: "Ш®ШұЫҢШҜ ШЁШ§ Щ…ЩҲЩҒЩӮЫҢШӘ Ш§ЩҶШ¬Ш§Щ… ШҙШҜ.", delivery: { id: delivered.id, title: delivered.plan_title, username: delivered.remote_username, subscription_url: delivered.subscription_url, order_type: delivered.order_type || "new", amount_toman: delivered.amount_toman, discount_toman: delivered.discount_toman, promo_code: delivered.promo_code, cashback_toman: Number(delivered.cashback_toman || 0) } });
    }
    if (action === "renew_order") {
      const online = String(body.payment_method || "card") === "blupal";
      if (!online) requireSalesPaymentCard(bot);
      const targetOrderId = cleanText(body.target_order_id, 80);
      const target = await env.PASARGUARD_DB.prepare("SELECT id FROM sales_orders WHERE id=? AND bot_id=? AND customer_id=? AND status='delivered'").bind(targetOrderId,bot.id,customer.id).first();
      if (!target) throw new Error("ШіШұЩҲЫҢШі Щ…ЩӮШөШҜ ШӘЩ…ШҜЫҢШҜ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
      const order = await createSalesOrder(env, bot, customer, cleanText(body.plan_id,80), { orderType: "renewal", targetOrderId, origin: "miniapp", promoCode, paymentMethod: online ? "blupal" : "card", status: online ? "payment_pending" : "awaiting_receipt" });
      if (online) {
        try { const invoice = await createSalesBlupalInvoice(env, bot, customer, "order", order.orderId, order.amountToman); return json({ success: true, message: "ЩҒШ§Ъ©ШӘЩҲШұ ШӘЩ…ШҜЫҢШҜ ШўЩҶЩ„Ш§ЫҢЩҶ ШіШ§Ш®ШӘЩҮ ШҙШҜ.", online_payment: invoice }); }
        catch (error) { await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='cancelled',error_message=?,updated_at=? WHERE id=?").bind(cleanText(error.message,800),nowIso(),order.orderId).run(); try { await salesReleasePromoForOrder(env,order.orderId); } catch (_) {} throw error; }
      }
      return json({ success: true, message: "ШіЩҒШ§ШұШҙ ШӘЩ…ШҜЫҢШҜ ШіШ§Ш®ШӘЩҮ ШҙШҜШӣ ЩҫШұШҜШ§Ш®ШӘ ЩҲ ШұШіЫҢШҜ ШҜШ§Ш®Щ„ Щ…ЫҢЩҶЫҢвҖҢШ§Щҫ Ш§ЩҶШ¬Ш§Щ… Щ…ЫҢвҖҢШҙЩҲШҜ.", payment: salesMiniAppPaymentPayload(bot, "order", order.orderId, order.amountToman, { title: order.plan.title, originalAmountToman: order.originalAmountToman, discountToman: order.discountToman, promoCode: order.promoCode }) });
    }
    if (action === "renew_wallet") {
      const targetOrderId = cleanText(body.target_order_id,80);
      const target = await env.PASARGUARD_DB.prepare("SELECT id FROM sales_orders WHERE id=? AND bot_id=? AND customer_id=? AND status='delivered'").bind(targetOrderId,bot.id,customer.id).first();
      if (!target) throw new Error("ШіШұЩҲЫҢШі Щ…ЩӮШөШҜ ШӘЩ…ШҜЫҢШҜ ЩҫЫҢШҜШ§ ЩҶШҙШҜ");
      const delivered = await purchaseSalesPlanFromWallet(env, bot, customer, cleanText(body.plan_id,80), { orderType: "renewal", targetOrderId, origin: "miniapp", promoCode });
      return json({ success: true, message: "ШӘЩ…ШҜЫҢШҜ ШЁШ§ Щ…ЩҲЩҒЩӮЫҢШӘ Ш§ЩҶШ¬Ш§Щ… ШҙШҜ.", delivery: { id: delivered.id, title: delivered.plan_title, username: delivered.remote_username, subscription_url: delivered.subscription_url, order_type: "renewal", amount_toman: delivered.amount_toman, discount_toman: delivered.discount_toman, promo_code: delivered.promo_code, cashback_toman: Number(delivered.cashback_toman || 0) } });
    }
    if (action === "volume_order") {
      const online = String(body.payment_method || "card") === "blupal";
      if (!online) requireSalesPaymentCard(bot);
      const targetOrderId = cleanText(body.target_order_id, 80);
      await getSalesServiceOrder(env, bot, customer, targetOrderId);
      const order = await createSalesOrder(env, bot, customer, cleanText(body.plan_id, 80), { orderType: "volume", targetOrderId, origin: "miniapp", promoCode, paymentMethod: online ? "blupal" : "card", status: online ? "payment_pending" : "awaiting_receipt" });
      if (online) {
        try { const invoice = await createSalesBlupalInvoice(env, bot, customer, "order", order.orderId, order.amountToman); return json({ success: true, message: "ЩҒШ§Ъ©ШӘЩҲШұ Ш§ЩҒШІШ§ЫҢШҙ ШӯШ¬Щ… ШўЩҶЩ„Ш§ЫҢЩҶ ШіШ§Ш®ШӘЩҮ ШҙШҜ.", online_payment: invoice }); }
        catch (error) { await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='cancelled',error_message=?,updated_at=? WHERE id=?").bind(cleanText(error.message,800),nowIso(),order.orderId).run(); try { await salesReleasePromoForOrder(env,order.orderId); } catch (_) {} throw error; }
      }
      return json({ success: true, message: "ШіЩҒШ§ШұШҙ Ш§ЩҒШІШ§ЫҢШҙ ШӯШ¬Щ… ШіШ§Ш®ШӘЩҮ ШҙШҜШӣ ЩҫШұШҜШ§Ш®ШӘ ЩҲ ШұШіЫҢШҜ ШҜШ§Ш®Щ„ Щ…ЫҢЩҶЫҢвҖҢШ§Щҫ Ш§ЩҶШ¬Ш§Щ… Щ…ЫҢвҖҢШҙЩҲШҜ.", payment: salesMiniAppPaymentPayload(bot, "order", order.orderId, order.amountToman, { title: order.plan.title, originalAmountToman: order.originalAmountToman, discountToman: order.discountToman, promoCode: order.promoCode }) });
    }
    if (action === "volume_wallet") {
      const targetOrderId = cleanText(body.target_order_id, 80);
      await getSalesServiceOrder(env, bot, customer, targetOrderId);
      const delivered = await purchaseSalesPlanFromWallet(env, bot, customer, cleanText(body.plan_id, 80), { orderType: "volume", targetOrderId, origin: "miniapp", promoCode });
      return json({ success: true, message: "ШӯШ¬Щ… ШіШұЩҲЫҢШі ШЁШ§ Щ…ЩҲЩҒЩӮЫҢШӘ Ш§ЩҒШІШ§ЫҢШҙ ЫҢШ§ЩҒШӘ.", delivery: { id: delivered.id, title: delivered.plan_title, username: delivered.remote_username, subscription_url: delivered.subscription_url, order_type: "volume", amount_toman: delivered.amount_toman, discount_toman: delivered.discount_toman, promo_code: delivered.promo_code, cashback_toman: Number(delivered.cashback_toman || 0) } });
    }
    if (action === "import_service") {
      const service = await importSalesServiceBySubscriptionLink(env, bot, customer, body.subscription_url);
      return json({ success: true, message: service.alreadyLinked ? "ШіШұЩҲЫҢШі Ш§ШІ ЩӮШЁЩ„ Щ…ШӘШөЩ„ ШЁЩҲШҜ ЩҲ ШЁШұЩҲШІШұШіШ§ЩҶЫҢ ШҙШҜ." : "ШіШұЩҲЫҢШі ЩӮШЁЩ„ЫҢ ШЁШ§ Щ…ЩҲЩҒЩӮЫҢШӘ ШЁЩҮ ШӯШіШ§ШЁ ШҙЩ…Ш§ Щ…ШӘШөЩ„ ШҙШҜ.", service });
    }
    if (action === "service_refresh") {
      const service = await syncSalesService(env, bot, customer, cleanText(body.service_id, 80));
      return json({ success: true, message: "Ш§Ш·Щ„Ш§Ш№Ш§ШӘ ШіШұЩҲЫҢШі ШЁШ§ ЩҫЩҶЩ„ ЩҮЩ…ЪҜШ§Щ… ШҙШҜ.", service });
    }
    if (action === "service_revoke") {
      const service = await revokeSalesServiceSubscription(env, bot, customer, cleanText(body.service_id, 80));
      return json({ success: true, message: "Щ„ЫҢЩҶЪ© Ш§ШҙШӘШұШ§Ъ© ЩӮШЁЩ„ЫҢ ШЁШ§Ш·Щ„ ЩҲ Щ„ЫҢЩҶЪ© Ш¬ШҜЫҢШҜ ШіШ§Ш®ШӘЩҮ ШҙШҜ.", service });
    }
    if (action === "trial") {
      const delivered = await requestSalesTrial(env, bot, customer, { origin: "miniapp" });
      return json({ success: true, message: "ШӘШіШӘ ШұШ§ЫҢЪҜШ§ЩҶ ШўЩ…Ш§ШҜЩҮ ШҙШҜ.", delivery: { id: delivered.id, title: delivered.title || "ШӘШіШӘ ШұШ§ЫҢЪҜШ§ЩҶ", username: delivered.username, subscription_url: delivered.subscriptionUrl, duration_hours: delivered.durationHours, data_limit_bytes: delivered.dataBytes, order_type: "trial" } });
    }
    if (action === "wallet_charge") {
      const amount = clampInt(body.amount, 0, 1000000000000);
      if (amount < 10000) throw new Error("ШӯШҜШ§ЩӮЩ„ Щ…ШЁЩ„Шә ШҙШ§ШұЪҳ ЫұЫ°Щ¬Ы°Ы°Ы° ШӘЩҲЩ…Ш§ЩҶ Ш§ШіШӘ");
      const walletPaymentMethod = String(body.payment_method || resellerPaymentDefaultMethod(bot, "recharge") || "card").toLowerCase();
      if (walletPaymentMethod === "cubepay") {
        if (!resellerCubepayConfigured(bot)) throw new Error("ШҜШұЪҜШ§ЩҮ CubePay Ш§ЫҢЩҶ ШұШЁШ§ШӘ ЩҒШ№Ш§Щ„ ЫҢШ§ Ъ©Ш§Щ…Щ„ ШӘЩҶШёЫҢЩ… ЩҶШҙШҜЩҮ Ш§ШіШӘ");
        const requestRow = await createSalesCubepayWalletCharge(env, bot, customer, amount, request.headers.get("x-bluepanel-public-origin") || new URL(request.url).origin, ctx);
        return json({ success: true, message: "ЩҒШ§Ъ©ШӘЩҲШұ Ъ©Ш§ШұШӘвҖҢШЁЩҮвҖҢЪ©Ш§ШұШӘ Ш®ЩҲШҜЪ©Ш§Шұ CubePay ШіШ§Ш®ШӘЩҮ ШҙШҜ.", online_payment: requestRow.invoice, bonus_percent: requestRow.bonusPercent, bonus_toman: requestRow.bonusAmount });
      }
      if (walletPaymentMethod === "plisio") {
        if (!resellerPlisioConfigured(bot)) throw new Error("ШҜШұЪҜШ§ЩҮ Plisio Ш§ЫҢЩҶ ШұШЁШ§ШӘ ЩҒШ№Ш§Щ„ ЫҢШ§ Ъ©Ш§Щ…Щ„ ШӘЩҶШёЫҢЩ… ЩҶШҙШҜЩҮ Ш§ШіШӘ");
        const requestRow = await createSalesPlisioWalletCharge(env, bot, customer, amount, request.headers.get("x-bluepanel-public-origin") || new URL(request.url).origin, ctx);
        return json({ success: true, message: "ЩҒШ§Ъ©ШӘЩҲШұ ШұЩ…ШІШ§ШұШІЫҢ Plisio ШіШ§Ш®ШӘЩҮ ШҙШҜ.", online_payment: requestRow.invoice, bonus_percent: requestRow.bonusPercent, bonus_toman: requestRow.bonusAmount });
      }
      resellerRequirePaymentMethod(bot, walletPaymentMethod, "recharge");
      if (walletPaymentMethod === "blupal") {
        const requestRow = await createSalesBlupalWalletCharge(env, bot, customer, amount);
        return json({ success: true, message: "ЩҒШ§Ъ©ШӘЩҲШұ ШҙШ§ШұЪҳ ШўЩҶЩ„Ш§ЫҢЩҶ ШіШ§Ш®ШӘЩҮ ШҙШҜ.", online_payment: requestRow.invoice, bonus_percent: requestRow.bonusPercent, bonus_toman: requestRow.bonusAmount });
      }
      requireSalesPaymentCard(bot);
      const requestRow = await salesWalletChargeInstructions(env, bot, customer, amount, { origin: "miniapp", notifyCustomer: false });
      return json({ success: true, message: "Ш§Ш·Щ„Ш§Ш№Ш§ШӘ Ъ©Ш§ШұШӘ ШўЩ…Ш§ШҜЩҮ ШҙШҜШӣ ШұШіЫҢШҜ ШұШ§ ЩҮЩ…ЫҢЩҶвҖҢШ¬Ш§ Ш«ШЁШӘ Ъ©ЩҶЫҢШҜ.", payment: salesMiniAppPaymentPayload(bot, "wallet", requestRow.requestId, requestRow.amountToman, { bonusPercent: requestRow.bonusPercent, bonusToman: requestRow.bonusAmount, title: "ШҙШ§ШұЪҳ Ъ©ЫҢЩҒ ЩҫЩҲЩ„" }) });
    }
    if (action === "submit_receipt") {
      const result = await submitSalesMiniAppReceipt(env, bot, customer, body);
      return json({ success: true, message: "ШұШіЫҢШҜ Ш«ШЁШӘ ШҙШҜ ЩҲ ШҜШұ Ш§ЩҶШӘШёШ§Шұ ШЁШұШұШіЫҢ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ Ш§ШіШӘ.", receipt: result });
    }
    return fail("Ш№Щ…Щ„ЫҢШ§ШӘ Щ…ЫҢЩҶЫҢвҖҢШ§Щҫ ШҙЩҶШ§Ш®ШӘЩҮ ЩҶШҙШҜ", 404, "ACTION_NOT_FOUND");
  } catch (error) {
    if (error?.code === "WEB_LOGIN_REQUIRED") return fail(error.message || "ЩҲШұЩҲШҜ ЩҶШіШ®ЩҮ ЩҲШЁ Щ„Ш§ШІЩ… Ш§ШіШӘ", 401, "WEB_LOGIN_REQUIRED");
    if (error?.code === "JOIN_REQUIRED") return json({ success: false, error: error.message, code: "JOIN_REQUIRED", channels: error.channels || [] }, 403);
    return fail(error.message || "Ш§ЩҶШ¬Ш§Щ… Ш№Щ…Щ„ЫҢШ§ШӘ ЩҶШ§Щ…ЩҲЩҒЩӮ ШЁЩҲШҜ", 400, error?.code || "SALES_APP_ACTION_FAILED");
  }
}

