function phoneCardHtml(compact){var b=state.bot,c=state.customer,verified=!!c.phone_verified;if(verified)return compact?"":'<div class="phoneBanner ok"><strong>вң… ШҙЩ…Ш§ШұЩҮ Щ…ЩҲШЁШ§ЫҢЩ„ ШӘШЈЫҢЫҢШҜ ШҙШҜЩҮ</strong><div class="muted">'+esc(c.phone_number||"ШҙЩ…Ш§ШұЩҮ Щ…ШӘШ№Щ„ЩӮ ШЁЩҮ ШӯШіШ§ШЁ ШӘЩ„ЪҜШұШ§Щ…")+'</div></div>';if(!b.phone_verification_required&&compact)return"";return'<div class="phoneBanner"><strong>рҹ“ұ '+(b.phone_verification_required?"ШӘШЈЫҢЫҢШҜ ШҙЩ…Ш§ШұЩҮ Ш§Щ„ШІШ§Щ…ЫҢ Ш§ШіШӘ":"ШӘШЈЫҢЫҢШҜ ШҙЩ…Ш§ШұЩҮ Щ…ЩҲШЁШ§ЫҢЩ„")+'</strong><div class="muted">'+(b.phone_verification_required?"ШЁШұШ§ЫҢ Ш®ШұЫҢШҜШҢ ШҙШ§ШұЪҳШҢ ШӘШіШӘ ШұШ§ЫҢЪҜШ§ЩҶ ЩҲ Ш«ШЁШӘ ШӘЫҢЪ©ШӘ ШЁШ§ЫҢШҜ ШҙЩ…Ш§ШұЩҮ Щ…ШӘШ№Щ„ЩӮ ШЁЩҮ ЩҮЩ…ЫҢЩҶ ШӯШіШ§ШЁ ШӘЩ„ЪҜШұШ§Щ… ШӘШЈЫҢЫҢШҜ ШҙЩҲШҜ.":"ШЁШ§ ШӘШЈЫҢЫҢШҜ ШҙЩ…Ш§ШұЩҮШҢ ЩҫЫҢЪҜЫҢШұЫҢ ШӯШіШ§ШЁ ЩҲ ЩҫШҙШӘЫҢШЁШ§ЩҶЫҢ Ш§Щ…ЩҶвҖҢШӘШұ Щ…ЫҢвҖҢШҙЩҲШҜ.")+'</div><button class="btn full" style="margin-top:9px" onclick="verifyPhone()">Ш§ШұШіШ§Щ„ ЩҲ ШӘШЈЫҢЫҢШҜ ШҙЩ…Ш§ШұЩҮ Щ…ЩҶ</button></div>'}
