    duplicate_receipt_protection: Number(bot.duplicate_receipt_protection ?? 1) === 1,
    auto_block_risk_score: Number(bot.auto_block_risk_score || 100),
    payment_card_enabled: Number(bot.payment_card_enabled ?? 1) === 1,
    payment_wallet_enabled: Number(bot.payment_wallet_enabled ?? 1) === 1,
    payment_method_order: String(bot.payment_method_order || "card,blupal,wallet"),
    payment_default_method: String(bot.payment_default_method || "card"),
