function openPlanForm(x){x=x||{};openModal(x.id?"ЩҲЫҢШұШ§ЫҢШҙ ЩҫЩ„ЩҶ":"ЩҫЩ„ЩҶ Ш¬ШҜЫҢШҜ",'<form id="modalForm"><div class="formGrid"><div class="field"><label>Ш№ЩҶЩҲШ§ЩҶ ЩҫЩ„ЩҶ</label><input id="mfTitle" class="input" value="'+esc(x.title||"")+'" required></div><div class="field"><label>ЩҶЩҲШ№ ЩҫЩ„ЩҶ</label><select id="mfType" class="input"><option value="sale"'+(x.plan_type==="sale"?' selected':'')+'>ЩҒШұЩҲШҙ Ш¬ШҜЫҢШҜ</option><option value="renew"'+(x.plan_type==="renew"?' selected':'')+'>ШӘЩ…ШҜЫҢШҜ</option><option value="volume"'+(x.plan_type==="volume"?' selected':'')+'>Ш§ЩҒШІШ§ЫҢШҙ ШӯШ¬Щ…</option></select></div><div class="field"><label>ШӯШ¬Щ… ЪҜЫҢЪҜШ§ШЁШ§ЫҢШӘ</label><input id="mfGb" class="input" type="number" step="0.01" min="0.01" value="'+esc(x.data_limit_bytes?Number(x.data_limit_bytes)/1073741824:"")+'" required></div><div class="field"><label>Щ…ШҜШӘ ШұЩҲШІ</label><input id="mfDays" class="input" type="number" min="1" value="'+esc(x.duration_days||30)+'" required></div><div class="field"><label>ЩӮЫҢЩ…ШӘ ШӘЩҲЩ…Ш§ЩҶ</label><input id="mfPrice" class="input" type="number" min="0" value="'+esc(x.price_toman||0)+'" required></div><div class="field"><label>Ш§ЩҲЩ„ЩҲЫҢШӘ ЩҶЩ…Ш§ЫҢШҙ</label><input id="mfSort" class="input" type="number" value="'+esc(x.sort_order||0)+'"></div><div class="field"><label>Щ„ЩҲЪ©ЫҢШҙЩҶ</label><select id="mfLocation" class="input" required>'+locationOptions(x.location_id).replace('<option value="">ШЁШҜЩҲЩҶ Щ„ЩҲЪ©ЫҢШҙЩҶ</option>','<option value="">Ш§ЩҶШӘШ®Ш§ШЁ Щ„ЩҲЪ©ЫҢШҙЩҶ</option>')+'</select></div><div class="field"><label>ШҜШіШӘЩҮвҖҢШЁЩҶШҜЫҢ ЩҮЩ…Ш§ЩҶ Щ„ЩҲЪ©ЫҢШҙЩҶ</label><select id="mfCategory" class="input">'+categoryOptions(x.category_id,x.location_id)+'</select></div></div><button class="btn" type="submit">Ш°Ш®ЫҢШұЩҮ ЩҫЩ„ЩҶ</button></form>');el("mfLocation").onchange=function(){el("mfCategory").innerHTML=categoryOptions("",this.value)};el("modalForm").onsubmit=function(e){e.preventDefault();run({action:"plan_save",id:x.id||"",title:el("mfTitle").value,plan_type:el("mfType").value,data_gb:el("mfGb").value,duration_days:el("mfDays").value,price_toman:el("mfPrice").value,sort_order:el("mfSort").value,category_id:el("mfCategory").value,location_id:el("mfLocation").value})}}
function openPromoForm(x){x=x||{};var localDate="";if(x.expires_at){var d=new Date(x.expires_at);if(!isNaN(d.getTime()))localDate=d.toISOString().slice(0,10)}openModal(x.id?"ЩҲЫҢШұШ§ЫҢШҙ Ъ©ШҜ":"Ъ©ШҜ Ш¬ШҜЫҢШҜ",'<form id="modalForm"><div class="formGrid"><div class="field"><label>Ъ©ШҜ</label><input id="mfCode" class="input ltr" value="'+esc(x.code||"")+'" required></div><div class="field"><label>ЩҶЩҲШ№</label><select id="mfKind" class="input"><option value="discount"'+(x.kind!=="gift"?' selected':'')+'>ШӘШ®ЩҒЫҢЩҒ</option><option value="gift"'+(x.kind==="gift"?' selected':'')+'>ЩҮШҜЫҢЩҮ Ъ©ЫҢЩҒ ЩҫЩҲЩ„</option></select></div><div class="field"><label>ЩҶЩҲШ№ Щ…ЩӮШҜШ§Шұ</label><select id="mfValueType" class="input"><option value="percent"'+(x.value_type!=="fixed"?' selected':'')+'>ШҜШұШөШҜ</option><option value="fixed"'+(x.value_type==="fixed"?' selected':'')+'>Щ…ШЁЩ„Шә Ш«Ш§ШЁШӘ</option></select></div><div class="field"><label>Щ…ЩӮШҜШ§Шұ</label><input id="mfValue" class="input" type="number" min="1" value="'+esc(x.value||"")+'" required></div><div class="field"><label>ШӯШҜШ§ЩӮЩ„ Ш®ШұЫҢШҜ ШӘЩҲЩ…Ш§ЩҶ</label><input id="mfMin" class="input" type="number" min="0" value="'+esc(x.min_purchase_toman||0)+'"></div><div class="field"><label>ШӯШҜШ§Ъ©Ш«Шұ Ш§ШіШӘЩҒШ§ШҜЩҮ Ъ©Щ„ <small>Ы° ЩҶШ§Щ…ШӯШҜЩҲШҜ</small></label><input id="mfMax" class="input" type="number" min="0" value="'+esc(x.max_uses||0)+'"></div><div class="field"><label>ШіЩҮЩ… ЩҮШұ Ъ©Ш§ШұШЁШұ</label><input id="mfPer" class="input" type="number" min="1" value="'+esc(x.per_user_limit||1)+'"></div><div class="field"><label>ШӘШ§ШұЫҢШ® Ш§ЩҶЩӮШ¶Ш§</label><input id="mfExpire" class="input ltr" type="date" value="'+esc(localDate)+'"></div></div><div class="field"><label>ШӘЩҲШ¶ЫҢШӯ</label><textarea id="mfDesc" class="input" rows="3">'+esc(x.description||"")+'</textarea></div><button class="btn" type="submit">Ш°Ш®ЫҢШұЩҮ Ъ©ШҜ</button></form>');el("modalForm").onsubmit=function(e){e.preventDefault();run({action:"promo_save",id:x.id||"",code:el("mfCode").value,kind:el("mfKind").value,value_type:el("mfValueType").value,value:el("mfValue").value,min_purchase_toman:el("mfMin").value,max_uses:el("mfMax").value,per_user_limit:el("mfPer").value,expires_at:el("mfExpire").value,description:el("mfDesc").value})}}
function openBalance(x){openModal("Ш§ШөЩ„Ш§Шӯ Щ…ЩҲШ¬ЩҲШҜЫҢ "+nameOf(x),'<form id="modalForm"><div class="field"><label>ЩҶЩҲШ№ Ш№Щ…Щ„ЫҢШ§ШӘ</label><select id="mfOperation" class="input"><option value="increase">Ш§ЩҒШІШ§ЫҢШҙ Щ…ЩҲШ¬ЩҲШҜЫҢ</option><option value="decrease">Ъ©Ш§ЩҮШҙ Щ…ЩҲШ¬ЩҲШҜЫҢ</option></select></div><div class="field"><label>Щ…ШЁЩ„Шә ШӘЩҲЩ…Ш§ЩҶ</label><input id="mfAmount" class="input" type="number" min="1" required></div><div class="field"><label>ШӘЩҲШ¶ЫҢШӯ</label><input id="mfNote" class="input" placeholder="Ш§ШөЩ„Ш§Шӯ Щ…ЩҲШ¬ЩҲШҜЫҢ ШӘЩҲШіШ· ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ"></div><button class="btn" type="submit">Ш«ШЁШӘ ШӘШәЫҢЫҢШұ</button></form>');el("modalForm").onsubmit=function(e){e.preventDefault();run({action:"customer_balance",id:x.id,operation:el("mfOperation").value,amount:el("mfAmount").value,note:el("mfNote").value})}}
function openCustomerType(x){openModal("ЩҶЩҲШ№ ЩҲ ШӘШ®ЩҒЫҢЩҒ "+nameOf(x),'<form id="modalForm"><div class="field"><label>ЩҶЩҲШ№ Щ…ШҙШӘШұЫҢ</label><select id="mfCustomerType" class="input"><option value="retail"'+(x.customer_type!=="wholesale"?' selected':'')+'>Ш№Ш§ШҜЫҢ</option><option value="wholesale"'+(x.customer_type==="wholesale"?' selected':'')+'>Ш№Щ…ШҜЩҮ</option></select></div><div class="field"><label>ШҜШұШөШҜ ШӘШ®ЩҒЫҢЩҒ Ш§Ш®ШӘШөШ§ШөЫҢ</label><input id="mfDiscount" class="input" type="number" min="0" max="100" value="'+esc(x.discount_percent||0)+'"></div><button class="btn" type="submit">Ш°Ш®ЫҢШұЩҮ</button></form>');el("modalForm").onsubmit=function(e){e.preventDefault();run({action:"customer_type",id:x.id,customer_type:el("mfCustomerType").value,discount_percent:el("mfDiscount").value})}}
async function openTicket(id){openModal("ШӘЫҢЪ©ШӘ","<div class=\"loading\"><div class=\"spinner\"></div>ШҜШұ ШӯШ§Щ„ ШҜШұЫҢШ§ЩҒШӘ ЪҜЩҒШӘвҖҢЩҲЪҜЩҲвҖҰ</div>");try{var d=await action({action:"ticket_detail",id:id}),t=d.ticket,msgs=d.messages||[];var thread=msgs.length?msgs.map(function(m){return'<div class="bubble '+(m.sender_type==="owner"?'owner':'customer')+'">'+esc(m.message_text)+'<small>'+(m.sender_type==="owner"?'ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ':'Щ…ШҙШӘШұЫҢ')+' В· '+date(m.created_at)+'</small></div>'}).join(""):empty("рҹ’¬","ЩҫЫҢШ§Щ…ЫҢ ЩҲШ¬ЩҲШҜ ЩҶШҜШ§ШұШҜ");openModal(t.public_code+' В· '+t.subject,'<div class="notice">'+esc(nameOf(t))+' В· '+esc(statusLabel(t.category))+' В· Ш§ЩҲЩ„ЩҲЫҢШӘ '+esc(statusLabel(t.priority))+' В· '+esc(statusLabel(t.status))+'</div><div class="thread" style="margin:12px 0">'+thread+'</div>'+(t.status!=="closed"?'<form id="ticketReplyForm"><div class="field"><label>ЩҫШ§ШіШ® ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ</label><textarea id="ticketReplyText" class="input" rows="4" required></textarea></div><button class="btn" type="submit">Ш§ШұШіШ§Щ„ ЩҫШ§ШіШ®</button></form>':'<div class="warningNotice notice">Ш§ЫҢЩҶ ШӘЫҢЪ©ШӘ ШЁШіШӘЩҮ ШҙШҜЩҮ Ш§ШіШӘ. ШЁШұШ§ЫҢ ЩҫШ§ШіШ® Ш§ШЁШӘШҜШ§ ШўЩҶ ШұШ§ ШЁШ§ШІ Ъ©ЩҶЫҢШҜ.</div>'));if(t.status!=="closed")el("ticketReplyForm").onsubmit=function(e){e.preventDefault();run({action:"ticket_reply",id:id,message:el("ticketReplyText").value})}}catch(e){toast(e.message);closeModal()}}
function collectSettings(){return{action:"save_settings",brand_name:el("setBrand").value,welcome_text:el("setWelcome").value,support_username:el("setSupport").value,status:el("setStatus").value,miniapp_enabled:el("setMiniapp").checked,forward_enabled:el("setForward").checked,card_holder:el("setHolder").value,card_number:el("setCard").value,bank_name:el("setBank").value,iban:el("setIban").value,recharge_bonus_percent:el("setBonus").value,payment_card_enabled:el("setPayCard").checked,payment_wallet_enabled:el("setPayWallet").checked,blupal_enabled:el("setBlupal").checked,blupal_base_url:el("setBlupalBase").value,blupal_api_key:el("setBlupalKey").value,blupal_card_number:el("setBlupalCard").value,payment_default_method:el("setDefaultPayment").value,payment_method_order:el("setPaymentOrder").value,trial_enabled:el("setTrial").checked,trial_data_limit_mb:el("setTrialMb").value,trial_duration_hours:el("setTrialHours").value,referral_reward_type:el("setReferralType").value,referral_reward_toman:el("setReferralFixed").value,referral_reward_percent:el("setReferralPercent").value,loyalty_enabled:el("setLoyalty").checked,loyalty_profile:el("setLoyaltyProfile").value,cashback_enabled:el("setCashback").checked,cashback_percent:el("setCashbackPercent").value,cashback_min_purchase_toman:el("setCashbackMin").value,cashback_max_toman:el("setCashbackMax").value,notifications_enabled:el("setNotifications").checked,ticketing_enabled:el("setTickets").checked,phone_verification_required:el("setPhone").checked,expiry_reminder_hours:el("setExpiryHours").value,usage_reminder_percent:el("setUsagePercent").value,ticket_auto_close_hours:el("setTicketClose").value,daily_report_enabled:el("setDailyReport").checked,daily_report_hour_utc:el("setDailyHour").value,sales_automation_enabled:el("setAutomation").checked,abandoned_reminder_minutes:el("setAbandoned").value,winback_days:el("setWinback").value,fraud_protection_enabled:el("setFraud").checked,duplicate_receipt_protection:el("setDuplicateReceipt").checked,order_cooldown_seconds:el("setCooldown").value,max_pending_orders:el("setMaxPending").value,daily_order_limit:el("setDailyOrders").value,daily_wallet_charge_limit_toman:el("setDailyWallet").value,auto_block_risk_score:el("setAutoBlock").value,auto_backup_enabled:el("setAutoBackup").checked,backup_hour_utc:el("setBackupHour").value,backup_retention_days:el("setBackupRetention").value}}
el("loginForm").onsubmit=async function(e){e.preventDefault();var b=el("loginBtn"),authenticated=false;b.disabled=true;el("loginError").textContent="";try{var r=await fetch("/reseller-control-auth/"+encodeURIComponent(BOT_ID)+"/login",{method:"POST",credentials:"same-origin",headers:{"content-type":"application/json"},body:JSON.stringify({username:el("loginUsername").value,password:el("loginPassword").value})}),raw=await r.text(),d;try{d=JSON.parse(raw)}catch(_){throw new Error("ЩҫШ§ШіШ® ЩҲШұЩҲШҜ ЩҶШ§Щ…Ш№ШӘШЁШұ Ш§ШіШӘ")};if(!r.ok||d.success===false)throw new Error(d.error||"ЩҲШұЩҲШҜ ЩҶШ§Щ…ЩҲЩҒЩӮ ШЁЩҲШҜ");authenticated=true;el("loginPassword").value=""}catch(x){el("loginError").textContent=x.message||"ЩҲШұЩҲШҜ ЩҶШ§Щ…ЩҲЩҒЩӮ ШЁЩҲШҜ"}finally{b.disabled=false}if(authenticated)await load()};
el("logoutBtn").onclick=async function(){try{await fetch("/reseller-control-auth/"+encodeURIComponent(BOT_ID)+"/logout",{method:"POST",credentials:"same-origin"})}catch(_){}location.reload()};el("menuBtn").onclick=function(){el("sidebar").classList.toggle("open")};el("refreshTop").onclick=function(){load(true)};
document.querySelectorAll(".navBtn").forEach(function(b){b.onclick=function(){page(b.dataset.page)}});document.querySelectorAll(".catalogTab").forEach(function(b){b.onclick=function(){currentCatalog=b.dataset.catalog;document.querySelectorAll(".catalogTab").forEach(function(x){x.classList.toggle("active",x===b)});document.querySelectorAll(".catalogPanel").forEach(function(x){x.classList.toggle("active",x.id==="catalog-"+currentCatalog)})}});
["orderSearch","serviceSearch","walletSearch","customerSearch","ticketSearch","planSearch","promoSearch","paymentSearch"].forEach(function(id){el(id).oninput=function(){if(id==="orderSearch")renderOrders();else if(id==="serviceSearch")renderServices();else if(id==="walletSearch")renderWallets();else if(id==="customerSearch")renderCustomers();else if(id==="ticketSearch")renderTickets();else if(id==="planSearch")renderPlans();else if(id==="promoSearch")renderPromos();else renderPayments()}});["orderStatus","walletStatus","customerStatus","customerSort","ticketStatus","planTypeFilter","planStateFilter","promoStatus","paymentStatus"].forEach(function(id){el(id).onchange=function(){if(id==="orderStatus")renderOrders();else if(id==="walletStatus")renderWallets();else if(id==="customerStatus"||id==="customerSort")renderCustomers();else if(id==="ticketStatus")renderTickets();else if(id==="planTypeFilter"||id==="planStateFilter")renderPlans();else if(id==="promoStatus")renderPromos();else renderPayments()}});
el("downlineSettingsForm").onsubmit=function(e){e.preventDefault();run({action:"downline_settings_save",sales_enabled:el("downlineSalesEnabled").checked,default_price_per_gb:el("downlineDefaultPrice").value,setup_fee:el("downlineSetupFee").value,renewal_fee:el("downlineRenewalFee").value})};el("downlineCreateForm").onsubmit=function(e){e.preventDefault();run({action:"downline_create",telegram_id:el("downlineTelegram").value,brand_name:el("downlineBrand").value,price_per_gb:el("downlinePrice").value,initial_balance_toman:el("downlineInitialBalance").value,control_username:el("downlineUsername").value,control_password:el("downlinePassword").value,bot_token:el("downlineToken").value}).then(function(d){el("downlineToken").value="";el("downlinePassword").value="";if(d&&d.result)openModal("ШұШЁШ§ШӘ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ШіШ§Ш®ШӘЩҮ ШҙШҜ",'<div class="notice">ЩҫЩҶЩ„ PasarGuard ШЁШұШ§ЫҢ Ш§ЫҢЩҶ ЩҶЩ…Ш§ЫҢЩҶШҜЩҮ ШіШ§Ш®ШӘЩҮ ЩҶШҙШҜЩҮ Ш§ШіШӘ.<br>ШўШҜШұШі Щ…ШҜЫҢШұЫҢШӘ: <span class="ltr">'+esc(d.result.management_url)+'</span><br>ЩҶШ§Щ… Ъ©Ш§ШұШЁШұЫҢ: <b class="ltr">'+esc(d.result.control_username)+'</b><br>ШұЩ…ШІ ЫҢЪ©вҖҢШЁШ§Шұ ЩҶЩ…Ш§ЫҢШҙ: <b class="ltr">'+esc(d.result.control_password)+'</b></div>')})};el("textsForm").onsubmit=function(e){e.preventDefault();var texts={};document.querySelectorAll(".textValue").forEach(function(x){texts[x.dataset.key]=x.value});run({action:"save_texts",texts:texts})};el("channelsForm").onsubmit=function(e){e.preventDefault();var channels=Array.from(document.querySelectorAll(".channelRow")).map(function(r){return{chat_id:r.querySelector(".chId").value,title:r.querySelector(".chTitle").value,url:r.querySelector(".chUrl").value}}).filter(function(x){return x.chat_id.trim()});run({action:"save_channels",join_enabled:el("joinEnabled").checked,channels:channels})};el("settingsForm").onsubmit=function(e){e.preventDefault();run(collectSettings()).then(function(){el("setBlupalKey").value=""})};el("campaignForm").onsubmit=function(e){e.preventDefault();run({action:"campaign_create",message:el("campaignMessage").value,target_scope:el("campaignTarget").value,schedule_hours:el("campaignHours").value}).then(function(){el("campaignMessage").value=""})};el("staffForm").onsubmit=function(e){e.preventDefault();run({action:"staff_save",telegram_id:el("staffTelegram").value,display_name:el("staffName").value,role:el("staffRole").value}).then(function(){el("staffTelegram").value="";el("staffName").value=""})};el("panelForm").onsubmit=function(e){e.preventDefault();if(!state.bot.panel_access)return;run({action:"change_agency",agency_id:el("ownerAgency").value},"ЩҫЩҶЩ„ Щ…ШӘШөЩ„ ШұШЁШ§ШӘ ШӘШәЫҢЫҢШұ Ъ©ЩҶШҜШҹ")};
