  function bindBalanceButtons(){document.querySelectorAll('.adjustBalanceBtn').forEach(function(btn){btn.onclick=function(){var userId=btn.dataset.id,userName=btn.dataset.name,current=Number(btn.dataset.balance||0);openModal('Щ…ШҜЫҢШұЫҢШӘ Щ…ЩҲШ¬ЩҲШҜЫҢ '+userName,'<div class="credentials"><div class="credential-row"><span>Щ…ЩҲШ¬ЩҲШҜЫҢ ЩҒШ№Щ„ЫҢ</span><b>'+money(current)+' ШӘЩҲЩ…Ш§ЩҶ</b></div></div><div class="field"><label>Щ…ШЁЩ„Шә ШЁЩҮ ШӘЩҲЩ…Ш§ЩҶ</label><input id="balanceAdjustAmount" class="input ltr" type="number" min="1" step="1" placeholder="Щ…Ш«Щ„Ш§ЩӢ 100000"></div><div class="field"><label>ШӘЩҲШ¶ЫҢШӯ Ш§Ш®ШӘЫҢШ§ШұЫҢ</label><input id="balanceAdjustNote" class="input" maxlength="180" placeholder="Ш№Щ„ШӘ ШӘШәЫҢЫҢШұ Щ…ЩҲШ¬ЩҲШҜЫҢ"></div><div class="form-grid"><button type="button" id="increaseBalanceBtn" class="btn ok">Ш§ЩҒШІШ§ЫҢШҙ Щ…ЩҲШ¬ЩҲШҜЫҢ</button><button type="button" id="decreaseBalanceBtn" class="btn danger">Ъ©Ш§ЩҮШҙ Щ…ЩҲШ¬ЩҲШҜЫҢ</button></div>');function submit(op){var amount=Number(el('balanceAdjustAmount').value||0),note=el('balanceAdjustNote').value;if(!Number.isFinite(amount)||amount<=0)return toast('Щ…ШЁЩ„Шә Щ…Ш№ШӘШЁШұ ЩҲШ§ШұШҜ Ъ©ЩҶЫҢШҜ');if(op==='decrease'&&amount>current)return toast('Щ…ШЁЩ„Шә Ъ©Ш§ЩҮШҙ ЩҶЩ…ЫҢвҖҢШӘЩҲШ§ЩҶШҜ ШЁЫҢШҙШӘШұ Ш§ШІ Щ…ЩҲШ¬ЩҲШҜЫҢ ЩҒШ№Щ„ЫҢ ШЁШ§ШҙШҜ');api('/api/admin/users/'+encodeURIComponent(userId)+'/balance',{method:'POST',body:JSON.stringify({operation:op,amount:amount,note:note})}).then(function(d){closeModal();toast((op==='increase'?'Щ…ЩҲШ¬ЩҲШҜЫҢ Ш§ЩҒШІШ§ЫҢШҙ ЫҢШ§ЩҒШӘ':'Щ…ЩҲШ¬ЩҲШҜЫҢ Ъ©Ш§ЩҮШҙ ЫҢШ§ЩҒШӘ')+'Шӣ Щ…Ш§ЩҶШҜЩҮ '+money(d.user.wallet_balance)+' ШӘЩҲЩ…Ш§ЩҶ');load()}).catch(function(e){toast(e.message)})}el('increaseBalanceBtn').onclick=function(){submit('increase')};el('decreaseBalanceBtn').onclick=function(){submit('decrease')}}})}
